export interface ProcessedPhoto {
  id: string;
  originalName: string;
  originalUrl: string;
  processedUrl: string | null;
  status: 'idle' | 'processing' | 'ready' | 'error';
  error?: string;
  quantity: number;
}

export interface PrintSettings {
  photoWidthCm: number;
  photoHeightCm: number;
  spacingMm: number;
  maxHorizontal: number;
}

export const PASSPORT_SETTINGS: PrintSettings = {
  photoWidthCm: 3.1,
  photoHeightCm: 4.2,
  spacingMm: 4,
  maxHorizontal: 6
};

// A4 Dimensions in CM
export const A4_WIDTH_CM = 21.0;
export const A4_HEIGHT_CM = 29.7;

// Conversion factor for 300 DPI (standard for photos)
// 1 inch = 2.54 cm
// 300 / 2.54 = 118.11 pixels per cm
export const CM_TO_PX = 118.11;

import { GoogleGenAI } from "@google/genai";

export const removeBackgroundAndOptimize = async (base64Image: string, mimeType: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Using gemini-2.5-flash-image for image editing/background removal
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Image,
            mimeType: mimeType,
          },
        },
        {
          text: "Perform a professional background removal on this person. Replace the background with a pure, solid white color (#FFFFFF). Ensure the edges of the person are sharp and clean. Center the person's head and shoulders as if taking a formal passport photo. The result must be a high-quality image of only the person on white background.",
        },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data returned from Gemini API");
};

import { CM_TO_PX, A4_WIDTH_CM, A4_HEIGHT_CM, PrintSettings } from '../types';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const loadImage = (url: string): Promise<HTMLImageElement> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = url;
    img.onload = () => resolve(img);
    img.onerror = (err) => reject(err);
  });
};

export const generateA4Sheet = async (
  photos: { url: string; quantity: number }[],
  settings: PrintSettings
): Promise<string> => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Could not get canvas context");

  // Set high-res canvas for 300 DPI A4
  canvas.width = A4_WIDTH_CM * CM_TO_PX;
  canvas.height = A4_HEIGHT_CM * CM_TO_PX;

  // Background white
  ctx.fillStyle = '#FFFFFF';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  const photoWidthPx = settings.photoWidthCm * CM_TO_PX;
  const photoHeightPx = settings.photoHeightCm * CM_TO_PX;
  const spacingPx = (settings.spacingMm / 10) * CM_TO_PX;

  // Calculate margins to center the grid horizontally
  const totalGridWidth = (settings.maxHorizontal * photoWidthPx) + ((settings.maxHorizontal - 1) * spacingPx);
  const leftMargin = (canvas.width - totalGridWidth) / 2;
  const topMargin = CM_TO_PX; // 1cm top margin

  let currentX = leftMargin;
  let currentY = topMargin;
  let countInRow = 0;

  for (const photo of photos) {
    const img = await loadImage(photo.url);

    for (let i = 0; i < photo.quantity; i++) {
      // Check if we need to wrap to next line
      if (countInRow >= settings.maxHorizontal) {
        countInRow = 0;
        currentX = leftMargin;
        currentY += photoHeightPx + spacingPx;
      }

      // Draw the photo
      // We assume the image is already cropped/processed correctly
      ctx.drawImage(img, currentX, currentY, photoWidthPx, photoHeightPx);

      // Draw a very faint cutting guide border
      ctx.strokeStyle = '#E2E8F0';
      ctx.lineWidth = 1;
      ctx.strokeRect(currentX, currentY, photoWidthPx, photoHeightPx);

      currentX += photoWidthPx + spacingPx;
      countInRow++;

      // Prevent overflow vertically (A4 limit)
      if (currentY + photoHeightPx > canvas.height) {
        break; 
      }
    }
  }

  return canvas.toDataURL('image/jpeg', 0.95);
};

import React from 'react';
import { ProcessedPhoto } from '../types';
import { Check, Loader2, Plus, Minus, Trash2, Printer } from 'lucide-react';

interface PhotoCardProps {
  photo: ProcessedPhoto;
  onUpdateQuantity: (id: string, qty: number) => void;
  onRemove: (id: string) => void;
  onProcess: (id: string) => void;
}

const PhotoCard: React.FC<PhotoCardProps> = ({ photo, onUpdateQuantity, onRemove, onProcess }) => {
  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden transition-all hover:shadow-md group">
      <div className="relative aspect-[31/42] bg-slate-100 flex items-center justify-center overflow-hidden">
        {photo.status === 'processing' ? (
          <div className="flex flex-col items-center gap-3">
            <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
            <span className="text-xs font-medium text-slate-500">Processing...</span>
          </div>
        ) : photo.status === 'ready' && photo.processedUrl ? (
          <img 
            src={photo.processedUrl} 
            alt="Processed" 
            className="w-full h-full object-cover"
          />
        ) : (
          <img 
            src={photo.originalUrl} 
            alt="Original" 
            className="w-full h-full object-cover opacity-50 grayscale"
          />
        )}

        <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <button 
            onClick={() => onRemove(photo.id)}
            className="p-1.5 bg-white/90 hover:bg-red-50 text-red-500 rounded-full shadow-sm transition-colors"
          >
            <Trash2 size={16} />
          </button>
        </div>

        {photo.status === 'error' && (
          <div className="absolute inset-0 bg-red-50/90 flex flex-col items-center justify-center p-4 text-center">
            <span className="text-xs font-bold text-red-600 mb-1">Processing Failed</span>
            <button 
              onClick={() => onProcess(photo.id)}
              className="text-xs underline text-red-700 hover:text-red-900"
            >
              Retry
            </button>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-slate-100">
        <div className="flex items-center justify-between mb-3">
          <span className="text-xs font-semibold text-slate-400 truncate max-w-[100px]">
            {photo.originalName}
          </span>
          {photo.status === 'ready' && (
            <span className="flex items-center gap-1 text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-full">
              <Check size={10} /> READY
            </span>
          )}
        </div>

        {photo.status === 'ready' && (
          <div className="space-y-4">
            <div className="flex items-center justify-between bg-slate-50 rounded-lg p-2">
              <span className="text-xs font-medium text-slate-600">Print Quantity</span>
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => onUpdateQuantity(photo.id, Math.max(0, photo.quantity - 1))}
                  className="p-1 hover:bg-white rounded border border-slate-200 text-slate-600 disabled:opacity-30"
                  disabled={photo.quantity <= 0}
                >
                  <Minus size={14} />
                </button>
                <span className="text-sm font-bold text-slate-800 min-w-[20px] text-center">
                  {photo.quantity}
                </span>
                <button 
                  onClick={() => onUpdateQuantity(photo.id, photo.quantity + 1)}
                  className="p-1 hover:bg-white rounded border border-slate-200 text-slate-600"
                >
                  <Plus size={14} />
                </button>
              </div>
            </div>
          </div>
        )}

        {photo.status === 'idle' && (
          <button 
            onClick={() => onProcess(photo.id)}
            className="w-full py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-xs font-semibold shadow-sm transition-colors flex items-center justify-center gap-2"
          >
            Start AI Processing
          </button>
        )}
      </div>
    </div>
  );
};

export default PhotoCard;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Upload, Camera, Printer, Layout, Download, X, AlertCircle, RefreshCw } from 'lucide-react';
import { ProcessedPhoto, PASSPORT_SETTINGS } from './types';
import { fileToBase64, generateA4Sheet } from './utils/imageUtils';
import { removeBackgroundAndOptimize } from './services/geminiService';
import PhotoCard from './components/PhotoCard';

const App: React.FC = () => {
  const [photos, setPhotos] = useState<ProcessedPhoto[]>([]);
  const [isGeneratingSheet, setIsGeneratingSheet] = useState(false);
  const [finalSheetUrl, setFinalSheetUrl] = useState<string | null>(null);
  const [showPreviewModal, setShowPreviewModal] = useState(false);

  // Handle File Upload
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newPhotos: ProcessedPhoto[] = files.map(file => ({
      id: Math.random().toString(36).substring(7),
      originalName: file.name,
      originalUrl: URL.createObjectURL(file),
      processedUrl: null,
      status: 'idle',
      quantity: 8 // Default to 8 photos for passport
    }));

    setPhotos(prev => [...prev, ...newPhotos]);

    // Auto-process files after upload
    newPhotos.forEach(p => processPhoto(p.id, files.find(f => f.name === p.originalName)!));
  };

  const processPhoto = async (id: string, file: File) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', error: undefined } : p));

    try {
      const base64 = await fileToBase64(file);
      const processedUrl = await removeBackgroundAndOptimize(base64, file.type);

      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'ready', processedUrl } : p
      ));
    } catch (err) {
      console.error(err);
      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'error', error: 'AI processing failed' } : p
      ));
    }
  };

  const updateQuantity = (id: string, quantity: number) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity } : p));
  };

  const removePhoto = (id: string) => {
    setPhotos(prev => prev.filter(p => p.id !== id));
  };

  const generateSheet = async () => {
    const readyPhotos = photos.filter(p => p.status === 'ready' && p.processedUrl && p.quantity > 0);
    if (readyPhotos.length === 0) return;

    setIsGeneratingSheet(true);
    try {
      const sheetUrl = await generateA4Sheet(
        readyPhotos.map(p => ({ url: p.processedUrl!, quantity: p.quantity })),
        PASSPORT_SETTINGS
      );
      setFinalSheetUrl(sheetUrl);
      setShowPreviewModal(true);
    } catch (err) {
      console.error("Sheet generation failed:", err);
    } finally {
      setIsGeneratingSheet(false);
    }
  };

  const downloadSheet = () => {
    if (!finalSheetUrl) return;
    const link = document.createElement('a');
    link.href = finalSheetUrl;
    link.download = `StudioPro_PrintSheet_${new Date().getTime()}.jpg`;
    link.click();
  };

  const totalToPrint = useMemo(() => {
    return photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0);
  }, [photos]);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center text-white">
            <Layout size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight leading-none">StudioPro</h1>
            <p className="text-xs text-slate-500 font-medium mt-1">PASSPORT AUTOMATOR</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="hidden md:flex flex-col items-end">
            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Print Queue</span>
            <span className="text-sm font-semibold text-slate-700">{totalToPrint} Photos in Queue</span>
          </div>
          <button 
            onClick={generateSheet}
            disabled={totalToPrint === 0 || isGeneratingSheet}
            className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 text-white px-5 py-2.5 rounded-full text-sm font-bold transition-all transform hover:scale-[1.02] active:scale-95 shadow-lg shadow-slate-200"
          >
            {isGeneratingSheet ? (
              <RefreshCw className="animate-spin" size={18} />
            ) : (
              <Printer size={18} />
            )}
            {isGeneratingSheet ? 'Arranging...' : 'Generate A4 Sheet'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-6 md:p-8 space-y-8">
        {/* Upload Area */}
        {photos.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-24 border-2 border-dashed border-slate-300 rounded-3xl bg-white transition-all hover:border-blue-400 group">
            <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 mb-6 group-hover:scale-110 transition-transform">
              <Upload size={32} />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Upload Raw Photos</h2>
            <p className="text-slate-500 mb-8 max-w-md text-center">
              Upload multiple photos. Our AI will automatically remove backgrounds and optimize them for passport specifications (3.1cm x 4.2cm).
            </p>
            <label className="cursor-pointer bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-full font-bold shadow-lg shadow-blue-200 transition-all active:scale-95">
              Select Files from Computer
              <input 
                type="file" 
                multiple 
                accept="image/*" 
                onChange={handleFileUpload} 
                className="hidden" 
              />
            </label>
            <p className="mt-4 text-xs text-slate-400 font-medium">Supports JPG, PNG, WEBP (Max 10MB per image)</p>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                Processing Queue
                <span className="text-xs font-normal text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">{photos.length} files</span>
              </h2>
              <label className="cursor-pointer flex items-center gap-2 text-blue-600 hover:text-blue-700 font-bold text-sm">
                <Plus size={18} />
                Add More
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={handleFileUpload} 
                  className="hidden" 
                />
              </label>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {photos.map(photo => (
                <PhotoCard 
                  key={photo.id}
                  photo={photo}
                  onUpdateQuantity={updateQuantity}
                  onRemove={removePhoto}
                  onProcess={(id) => {
                    const originalFile = (document.querySelector('input[type="file"]') as HTMLInputElement)?.files?.length 
                      ? Array.from((document.querySelector('input[type="file"]') as HTMLInputElement).files!).find(f => f.name === photo.originalName)
                      : null;
                    if (originalFile) processPhoto(id, originalFile);
                  }}
                />
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Preview Modal */}
      {showPreviewModal && finalSheetUrl && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl scale-in-center">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Printer size={20} className="text-blue-600" />
                <h3 className="font-bold text-slate-800">Ready for Printing (A4 Sheet)</h3>
              </div>
              <button 
                onClick={() => setShowPreviewModal(false)}
                className="p-1.5 hover:bg-slate-100 rounded-full text-slate-400 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-auto bg-slate-200 p-8 flex justify-center">
              <div className="print-sheet bg-white shadow-xl relative" style={{ 
                width: `${A4_WIDTH_CM * 40}px`, // Scaled preview
                height: `${A4_HEIGHT_CM * 40}px`,
                minWidth: `${A4_WIDTH_CM * 40}px`
              }}>
                <img src={finalSheetUrl} alt="A4 Print Sheet" className="w-full h-full object-contain" />
              </div>
            </div>

            <div className="p-6 bg-slate-50 border-t border-slate-200 flex flex-col md:flex-row items-center justify-between gap-4">
              <div className="flex items-center gap-3 text-slate-500">
                <AlertCircle size={18} />
                <p className="text-sm">Final sheet is optimized for 300 DPI high-quality printing on A4 paper.</p>
              </div>
              <div className="flex items-center gap-3 w-full md:w-auto">
                <button 
                  onClick={() => setShowPreviewModal(false)}
                  className="flex-1 md:flex-none px-6 py-2.5 rounded-full text-slate-600 font-bold text-sm hover:bg-slate-100"
                >
                  Edit Further
                </button>
                <button 
                  onClick={downloadSheet}
                  className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-full font-bold shadow-lg shadow-blue-200 transition-all active:scale-95"
                >
                  <Download size={18} />
                  Download to Print
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer / Status Bar */}
      <footer className="bg-slate-900 text-slate-400 py-3 px-6 text-[10px] font-medium tracking-widest uppercase flex items-center justify-between">
        <div className="flex items-center gap-6">
          <span>Dimensions: {PASSPORT_SETTINGS.photoWidthCm} x {PASSPORT_SETTINGS.photoHeightCm} cm</span>
          <span>Target: A4 White Paper</span>
          <span>PPI: 300 Optimized</span>
        </div>
        <div className="hidden sm:block">
          &copy; {new Date().getFullYear()} StudioPro AI Visuals
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';

