import { CM_TO_PX, A4_WIDTH_CM, A4_HEIGHT_CM, PrintSettings } from '../types';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64String = result.split(',')[1];
      resolve(base64String);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const loadImage = (url: string): Promise<HTMLImageElement> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = url;
    img.onload = () => resolve(img);
    img.onerror = (err) => reject(err);
  });
};

/**
 * Crops an image based on provided pixel coordinates
 */
export const cropImageToDataUrl = async (
  imageUrl: string,
  crop: { x: number; y: number; width: number; height: number }
): Promise<string> => {
  const img = await loadImage(imageUrl);
  const canvas = document.createElement('canvas');
  canvas.width = crop.width;
  canvas.height = crop.height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Canvas context failed");

  ctx.drawImage(
    img,
    crop.x,
    crop.y,
    crop.width,
    crop.height,
    0,
    0,
    crop.width,
    crop.height
  );

  return canvas.toDataURL('image/jpeg', 0.95);
};

export const generateA4Sheet = async (
  photos: { url: string; quantity: number }[],
  settings: PrintSettings
): Promise<string> => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Could not get canvas context");

  // Set high-res canvas for 300 DPI A4
  canvas.width = A4_WIDTH_CM * CM_TO_PX;
  canvas.height = A4_HEIGHT_CM * CM_TO_PX;

  // Background white
  ctx.fillStyle = '#FFFFFF';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  const photoWidthPx = settings.photoWidthCm * CM_TO_PX;
  const photoHeightPx = settings.photoHeightCm * CM_TO_PX;
  const spacingPx = (settings.spacingMm / 10) * CM_TO_PX;

  // Calculate margins to center the grid horizontally
  const totalGridWidth = (settings.maxHorizontal * photoWidthPx) + ((settings.maxHorizontal - 1) * spacingPx);
  const leftMargin = (canvas.width - totalGridWidth) / 2;
  const topMargin = CM_TO_PX; // 1cm top margin

  let currentX = leftMargin;
  let currentY = topMargin;
  let countInRow = 0;

  for (const photo of photos) {
    const img = await loadImage(photo.url);

    for (let i = 0; i < photo.quantity; i++) {
      if (countInRow >= settings.maxHorizontal) {
        countInRow = 0;
        currentX = leftMargin;
        currentY += photoHeightPx + spacingPx;
      }

      // Draw the photo
      ctx.drawImage(img, currentX, currentY, photoWidthPx, photoHeightPx);

      // Draw a black border around the photo as requested
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 1.5; // Slightly thicker for clear cutting line
      ctx.strokeRect(currentX, currentY, photoWidthPx, photoHeightPx);

      currentX += photoWidthPx + spacingPx;
      countInRow++;

      if (currentY + photoHeightPx > canvas.height) {
        break; 
      }
    }
  }

  return canvas.toDataURL('image/jpeg', 0.95);
};

import React, { useState, useRef, useEffect } from 'react';
import { X, Check, ZoomIn, ZoomOut, Maximize } from 'lucide-react';
import { PASSPORT_SETTINGS } from '../types';

interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string) => void;
  onCancel: () => void;
}

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);

  const ASPECT_RATIO = PASSPORT_SETTINGS.photoWidthCm / PASSPORT_SETTINGS.photoHeightCm;

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStart({ x: e.clientX - offset.x, y: e.clientY - offset.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setOffset({
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    });
  };

  const handleMouseUp = () => setIsDragging(false);

  const handleConfirm = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx || !imgRef.current || !containerRef.current) return;

    // We want a high-quality output, so we use a large internal size
    const targetWidth = 600;
    const targetHeight = targetWidth / ASPECT_RATIO;
    canvas.width = targetWidth;
    canvas.height = targetHeight;

    const rect = containerRef.current.getBoundingClientRect();
    const cropBoxWidth = rect.width * 0.8;
    const cropBoxHeight = cropBoxWidth / ASPECT_RATIO;

    // Calculate the source coordinates
    // We need to map the visual representation in the modal to the actual image pixels
    const scale = imgRef.current.naturalWidth / (imgRef.current.width * zoom);

    // The center of the crop box is the center of the container
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;

    // Position of image top-left relative to crop box center
    const imgXInBox = offset.x + (imgRef.current.width * zoom) / 2 - centerX;
    const imgYInBox = offset.y + (imgRef.current.height * zoom) / 2 - centerY;

    // Source X/Y on natural image
    const sx = ( (imgRef.current.width * zoom) / 2 - imgXInBox - cropBoxWidth / 2 ) * scale;
    const sy = ( (imgRef.current.height * zoom) / 2 - imgYInBox - cropBoxHeight / 2 ) * scale;
    const sWidth = cropBoxWidth * scale;
    const sHeight = cropBoxHeight * scale;

    ctx.drawImage(imgRef.current, sx, sy, sWidth, sHeight, 0, 0, targetWidth, targetHeight);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95));
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div className="bg-slate-900 rounded-2xl w-full max-w-2xl overflow-hidden flex flex-col shadow-2xl border border-white/10">
        <div className="p-4 border-b border-white/5 flex items-center justify-between">
          <h3 className="text-white font-bold flex items-center gap-2">
            <Maximize size={18} className="text-blue-400" />
            Manual Passport Crop
          </h3>
          <button onClick={onCancel} className="p-1 hover:bg-white/10 rounded-full text-white/50 transition-colors">
            <X size={20} />
          </button>
        </div>

        <div 
          ref={containerRef}
          className="relative flex-1 h-[400px] overflow-hidden cursor-move bg-slate-950 flex items-center justify-center select-none"
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
        >
          {/* The Image */}
          <img
            ref={imgRef}
            src={imageUrl}
            alt="Crop target"
            draggable={false}
            style={{
              transform: `translate(${offset.x}px, ${offset.y}px) scale(${zoom})`,
              transition: isDragging ? 'none' : 'transform 0.1s ease-out'
            }}
            className="max-w-none pointer-events-none origin-center"
          />

          {/* Crop Overlay Mask */}
          <div className="absolute inset-0 pointer-events-none">
            <div className="w-full h-full flex flex-col">
               <div className="flex-1 bg-black/60"></div>
               <div className="flex">
                  <div className="flex-1 bg-black/60"></div>
                  <div className="border-2 border-blue-400 relative" style={{ 
                    width: '80%', 
                    aspectRatio: `${ASPECT_RATIO}`,
                    boxShadow: '0 0 0 9999px rgba(0,0,0,0.6)'
                  }}>
                    {/* Grid lines */}
                    <div className="absolute inset-0 flex">
                      <div className="flex-1 border-r border-white/20"></div>
                      <div className="flex-1 border-r border-white/20"></div>
                      <div className="flex-1"></div>
                    </div>
                    <div className="absolute inset-0 flex flex-col">
                      <div className="flex-1 border-b border-white/20"></div>
                      <div className="flex-1 border-b border-white/20"></div>
                      <div className="flex-1"></div>
                    </div>
                  </div>
                  <div className="flex-1 bg-black/60"></div>
               </div>
               <div className="flex-1 bg-black/60"></div>
            </div>
          </div>
        </div>

        <div className="p-6 bg-slate-900 border-t border-white/5 space-y-4">
          <div className="flex items-center gap-4">
            <ZoomOut size={18} className="text-white/40" />
            <input 
              type="range" 
              min="0.1" 
              max="3" 
              step="0.01" 
              value={zoom} 
              onChange={(e) => setZoom(parseFloat(e.target.value))}
              className="flex-1 accent-blue-500 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer"
            />
            <ZoomIn size={18} className="text-white/40" />
          </div>

          <div className="flex items-center justify-between">
            <p className="text-xs text-white/50">Drag image to position. Ensure head is centered.</p>
            <div className="flex items-center gap-3">
              <button 
                onClick={onCancel}
                className="px-5 py-2 rounded-full text-white/70 font-bold text-sm hover:bg-white/5 transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={handleConfirm}
                className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-full font-bold shadow-lg shadow-blue-900/20 transition-all active:scale-95"
              >
                <Check size={18} />
                Confirm Crop
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CropModal;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Upload, Camera, Printer, Layout, Download, X, AlertCircle, RefreshCw, Plus, Maximize } from 'lucide-react';
import { ProcessedPhoto, PASSPORT_SETTINGS, A4_WIDTH_CM, A4_HEIGHT_CM } from './types';
import { fileToBase64, generateA4Sheet } from './utils/imageUtils';
import { removeBackgroundAndOptimize } from './services/geminiService';
import PhotoCard from './components/PhotoCard';
import CropModal from './components/CropModal';

const App: React.FC = () => {
  const [photos, setPhotos] = useState<ProcessedPhoto[]>([]);
  const [isGeneratingSheet, setIsGeneratingSheet] = useState(false);
  const [finalSheetUrl, setFinalSheetUrl] = useState<string | null>(null);
  const [showPreviewModal, setShowPreviewModal] = useState(false);

  // Cropping State
  const [croppingPhotoId, setCroppingPhotoId] = useState<string | null>(null);

  // Handle File Upload
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newPhotos: ProcessedPhoto[] = files.map((file: File) => ({
      id: Math.random().toString(36).substring(7),
      originalName: file.name,
      originalUrl: URL.createObjectURL(file),
      processedUrl: null,
      status: 'idle',
      quantity: 8 // Default to 8 photos for passport
    }));

    setPhotos(prev => [...prev, ...newPhotos]);

    // We don't auto-process now; the user must crop first.
    // If it's the first upload, we could trigger crop for the first one automatically.
    if (newPhotos.length > 0) {
      setCroppingPhotoId(newPhotos[0].id);
    }

    // Reset the input so same file can be uploaded again if needed
    e.target.value = '';
  };

  const handleCropComplete = async (croppedDataUrl: string) => {
    if (!croppingPhotoId) return;

    const id = croppingPhotoId;
    setCroppingPhotoId(null);

    // Update photo status to processing and set the URL to cropped (temporarily)
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', originalUrl: croppedDataUrl } : p));

    try {
      // Background removal on the cropped image
      const base64 = croppedDataUrl.split(',')[1];
      const processedUrl = await removeBackgroundAndOptimize(base64, 'image/jpeg');

      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'ready', processedUrl } : p
      ));
    } catch (err) {
      console.error(err);
      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'error', error: 'AI processing failed' } : p
      ));
    }
  };

  const updateQuantity = (id: string, quantity: number) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity } : p));
  };

  const removePhoto = (id: string) => {
    setPhotos(prev => prev.filter(p => p.id !== id));
  };

  const generateSheet = async () => {
    const readyPhotos = photos.filter(p => p.status === 'ready' && p.processedUrl && p.quantity > 0);
    if (readyPhotos.length === 0) return;

    setIsGeneratingSheet(true);
    try {
      const sheetUrl = await generateA4Sheet(
        readyPhotos.map(p => ({ url: p.processedUrl!, quantity: p.quantity })),
        PASSPORT_SETTINGS
      );
      setFinalSheetUrl(sheetUrl);
      setShowPreviewModal(true);
    } catch (err) {
      console.error("Sheet generation failed:", err);
    } finally {
      setIsGeneratingSheet(false);
    }
  };

  const downloadSheet = () => {
    if (!finalSheetUrl) return;
    const link = document.createElement('a');
    link.href = finalSheetUrl;
    link.download = `StudioPro_PrintSheet_${new Date().getTime()}.jpg`;
    link.click();
  };

  const totalToPrint = useMemo(() => {
    return photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0);
  }, [photos]);

  const photoToCrop = useMemo(() => {
    return photos.find(p => p.id === croppingPhotoId);
  }, [photos, croppingPhotoId]);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
            <Layout size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight leading-none">StudioPro</h1>
            <p className="text-[10px] text-blue-600 font-bold mt-1 tracking-widest uppercase">Passport Automator</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="hidden md:flex flex-col items-end mr-2">
            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Queue Status</span>
            <span className="text-sm font-semibold text-slate-700">{totalToPrint} Photos ready</span>
          </div>
          <button 
            onClick={generateSheet}
            disabled={totalToPrint === 0 || isGeneratingSheet}
            className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 text-white px-6 py-3 rounded-full text-sm font-bold transition-all transform hover:scale-[1.02] active:scale-95 shadow-xl shadow-slate-200"
          >
            {isGeneratingSheet ? (
              <RefreshCw className="animate-spin" size={18} />
            ) : (
              <Printer size={18} />
            )}
            {isGeneratingSheet ? 'Arranging...' : 'Generate A4 Sheet'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-6 md:p-8 space-y-8">
        {/* Upload Area */}
        {photos.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-32 border-2 border-dashed border-slate-300 rounded-[2.5rem] bg-white transition-all hover:border-blue-400 group shadow-sm">
            <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 mb-8 group-hover:scale-110 transition-transform shadow-inner">
              <Upload size={40} />
            </div>
            <h2 className="text-3xl font-bold text-slate-800 mb-3">Professional Passport Tool</h2>
            <p className="text-slate-500 mb-10 max-w-md text-center text-lg leading-relaxed">
              Upload raw shots. You'll crop them manually for the perfect look, then we'll automate the background and layout.
