            <label className="cursor-pointer bg-blue-600 hover:bg-blue-700 text-white px-10 py-4 rounded-full font-bold text-lg shadow-2xl shadow-blue-300/50 transition-all active:scale-95 hover:translate-y-[-2px]">
              Upload Studio Photos
              <input 
                type="file" 
                multiple 
                accept="image/*" 
                onChange={handleFileUpload} 
                className="hidden" 
              />
            </label>
            <div className="mt-8 flex gap-8 items-center grayscale opacity-50">
              <span className="text-xs font-bold uppercase tracking-widest text-slate-400">3.1 x 4.2 CM</span>
              <span className="text-xs font-bold uppercase tracking-widest text-slate-400">AI Background</span>
              <span className="text-xs font-bold uppercase tracking-widest text-slate-400">A4 Layout</span>
            </div>
