import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, Check, Maximize, RotateCcw, Move } from 'lucide-react';
import { PASSPORT_SETTINGS } from '../types';

interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string) => void;
  onCancel: () => void;
}

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);

  // State for crop rectangle in pixels relative to the displayed image
  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'n' | 's' | 'e' | 'w' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const ASPECT_RATIO = PASSPORT_SETTINGS.photoWidthCm / PASSPORT_SETTINGS.photoHeightCm;

  // Initialize crop area when image loads
  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });

    // Initial crop: center 80% height with passport aspect ratio
    const initialHeight = height * 0.8;
    const initialWidth = initialHeight * ASPECT_RATIO;

    setCrop({
      x: (width - initialWidth) / 2,
      y: (height - initialHeight) / 2,
      width: initialWidth,
      height: initialHeight
    });
  };

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType || !imgRef.current) return;

    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;
    const { width: imgW, height: imgH } = imgDisplaySize;

    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'nw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'ne':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'se':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'n':
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 's':
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'w':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        break;
      case 'e':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        break;
    }

    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
    setDragType(null);
  }, []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const handleConfirm = () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Source coordinates scaled to natural image size
    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;

    const sX = crop.x * scaleX;
    const sY = crop.y * scaleY;
    const sW = crop.width * scaleX;
    const sH = crop.height * scaleY;

    // Use high resolution for output (keeping aspect of crop)
    canvas.width = sW;
    canvas.height = sH;
    ctx.drawImage(imgRef.current, sX, sY, sW, sH, 0, 0, sW, sH);

    onConfirm(canvas.toDataURL('image/jpeg', 0.95));
  };

  const resetCrop = () => {
    const { width, height } = imgDisplaySize;
    const h = height * 0.8;
    const w = h * ASPECT_RATIO;
    setCrop({
      x: (width - w) / 2,
      y: (height - h) / 2,
      width: w,
      height: h
    });
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 backdrop-blur-xl p-4 animate-in fade-in zoom-in duration-200">
      <div className="bg-slate-900 rounded-[2.5rem] w-full max-w-4xl overflow-hidden flex flex-col shadow-2xl border border-white/10">
        {/* Header */}
        <div className="px-8 py-5 border-b border-white/5 flex items-center justify-between bg-slate-900/50 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Maximize size={20} className="text-white" />
            </div>
            <div>
              <h3 className="text-white font-bold text-lg leading-none">Manual Studio Crop</h3>
              <p className="text-[10px] text-white/40 font-bold mt-1 uppercase tracking-widest">Adjust borders freely</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <button 
              onClick={resetCrop}
              className="flex items-center gap-2 px-4 py-2 rounded-xl text-white/50 font-bold text-xs hover:bg-white/5 transition-colors"
              title="Reset to Portrait Aspect"
            >
              <RotateCcw size={14} />
              Reset
            </button>
            <button onClick={onCancel} className="p-2 hover:bg-white/10 rounded-full text-white/50 transition-colors">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Cropping Workspace */}
        <div 
          ref={containerRef}
          className="relative flex-1 bg-slate-950 flex items-center justify-center p-8 min-h-[50vh] overflow-hidden select-none"
        >
          <div className="relative inline-block shadow-2xl">
            <img
              ref={imgRef}
              src={imageUrl}
              alt="Crop target"
              onLoad={handleImageLoad}
              className="max-h-[60vh] object-contain rounded-sm"
              draggable={false}
            />

            {/* Dark Mask Layer */}
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
               <div className="absolute inset-0 bg-black/60" style={{
                 clipPath: `polygon(
                   0% 0%, 0% 100%, 
                   ${crop.x}px 100%, 
                   ${crop.x}px ${crop.y}px, 
                   ${crop.x + crop.width}px ${crop.y}px, 
                   ${crop.x + crop.width}px ${crop.y + crop.height}px, 
                   ${crop.x}px ${crop.y + crop.height}px, 
                   ${crop.x}px 100%, 
                   100% 100%, 100% 0%
                 )`
               }}></div>
            </div>

            {/* Draggable Crop Rectangle */}
            <div 
              style={{
                left: crop.x,
                top: crop.y,
                width: crop.width,
                height: crop.height,
              }}
              className="absolute border-2 border-blue-500 shadow-[0_0_0_1px_rgba(255,255,255,0.3)] cursor-move group"
              onMouseDown={(e) => handleMouseDown(e, 'move')}
            >
              {/* Internal Grid lines */}
              <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-30 group-hover:opacity-60 transition-opacity">
                <div className="border-r border-b border-white/40"></div>
                <div className="border-r border-b border-white/40"></div>
                <div className="border-b border-white/40"></div>
                <div className="border-r border-b border-white/40"></div>
                <div className="border-r border-b border-white/40"></div>
                <div className="border-b border-white/40"></div>
                <div className="border-r border-white/40"></div>
                <div className="border-r border-white/40"></div>
                <div></div>
              </div>

              {/* Corner Handles */}
              <div onMouseDown={(e) => handleMouseDown(e, 'nw')} className="absolute -top-1.5 -left-1.5 w-4 h-4 bg-white border-2 border-blue-600 rounded-sm cursor-nw-resize z-10"></div>
              <div onMouseDown={(e) => handleMouseDown(e, 'ne')} className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-white border-2 border-blue-600 rounded-sm cursor-ne-resize z-10"></div>
              <div onMouseDown={(e) => handleMouseDown(e, 'sw')} className="absolute -bottom-1.5 -left-1.5 w-4 h-4 bg-white border-2 border-blue-600 rounded-sm cursor-sw-resize z-10"></div>
              <div onMouseDown={(e) => handleMouseDown(e, 'se')} className="absolute -bottom-1.5 -right-1.5 w-4 h-4 bg-white border-2 border-blue-600 rounded-sm cursor-se-resize z-10"></div>

              {/* Edge Handles */}
              <div onMouseDown={(e) => handleMouseDown(e, 'n')} className="absolute -top-1.5 left-1/2 -translate-x-1/2 w-8 h-1.5 bg-blue-400 rounded-full cursor-n-resize hover:bg-white transition-colors"></div>
              <div onMouseDown={(e) => handleMouseDown(e, 's')} className="absolute -bottom-1.5 left-1/2 -translate-x-1/2 w-8 h-1.5 bg-blue-400 rounded-full cursor-s-resize hover:bg-white transition-colors"></div>
              <div onMouseDown={(e) => handleMouseDown(e, 'w')} className="absolute -left-1.5 top-1/2 -translate-y-1/2 h-8 w-1.5 bg-blue-400 rounded-full cursor-w-resize hover:bg-white transition-colors"></div>
              <div onMouseDown={(e) => handleMouseDown(e, 'e')} className="absolute -right-1.5 top-1/2 -translate-y-1/2 h-8 w-1.5 bg-blue-400 rounded-full cursor-e-resize hover:bg-white transition-colors"></div>

              {/* Move indicator on hover */}
              <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                 <div className="bg-black/20 p-2 rounded-full backdrop-blur-sm">
                    <Move size={20} className="text-white/80" />
                 </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-900 border-t border-white/5">
          <div className="flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="flex items-center gap-4 bg-white/5 p-4 rounded-2xl border border-white/5">
              <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center">
                 <Maximize size={16} className="text-blue-400" />
              </div>
              <div>
                <p className="text-xs font-bold text-white/80 uppercase tracking-tight">Custom Selection</p>
                <p className="text-[10px] text-white/40 mt-0.5">Drag handles to set edges. Background removal will follow this crop.</p>
              </div>
            </div>

