        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-[1.25rem] flex items-center justify-center text-white shadow-xl shadow-blue-500/20 transform transition-transform hover:rotate-6">
            <Layout size={28} />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-none">StudioPro</h1>
            <p className="text-[10px] text-blue-600 font-black mt-1.5 tracking-[0.2em] uppercase">Visual Automation Hub</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden lg:flex flex-col items-end">
