        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between">
              <div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Image Workshop</h2>
                <p className="text-sm font-bold text-slate-400 mt-1 uppercase tracking-widest">Processing {photos.length} individual subjects</p>
              </div>
              <label className="cursor-pointer flex items-center gap-3 text-blue-600 hover:bg-blue-600 hover:text-white px-6 py-3 rounded-2xl font-black text-sm bg-blue-50 transition-all shadow-sm">
                <Plus size={20} />
                Add More
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={handleFileUpload} 
                  className="hidden" 
                />
              </label>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
              {photos.map(photo => (
                <div key={photo.id} className="relative group perspective-1000">
                  <PhotoCard 
                    photo={photo}
                    onUpdateQuantity={updateQuantity}
                    onRemove={removePhoto}
                    onProcess={() => setCroppingPhotoId(photo.id)}
                  />
                  {photo.status === 'idle' && (
                    <div className="absolute inset-x-0 bottom-[100px] flex justify-center pointer-events-none z-10">
                       <div className="bg-blue-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full shadow-2xl animate-bounce tracking-widest uppercase">
                          Action Required
                       </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Dynamic Crop Interface */}
      {photoToCrop && (
        <CropModal 
          imageUrl={photoToCrop.originalUrl}
          onCancel={() => setCroppingPhotoId(null)}
          onConfirm={handleCropComplete}
        />
      )}

      {/* A4 Sheet Print Preview */}
      {showPreviewModal && finalSheetUrl && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6 animate-in fade-in duration-500">
          <div className="bg-white rounded-[3rem] w-full max-w-6xl max-h-[95vh] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.4)] scale-in-center border border-white/20">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-white/50">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-green-100 text-green-600 rounded-[1.5rem] flex items-center justify-center shadow-inner">
