                <div>
                  <h3 className="font-black text-slate-900 text-2xl tracking-tight">Print Mastering</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-[0.2em] mt-1">3.1 x 4.2cm • 300 DPI • Black Borders</p>
