import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Check, Maximize, RotateCcw, Move, Sun, Contrast, Droplets, Thermometer, Activity } from 'lucide-react';
import { PASSPORT_SETTINGS } from '../types';

interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

interface Adjustments {
  brightness: number;
  contrast: number;
  saturation: number;
  temperature: number;
}

interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string) => void;
  onCancel: () => void;
}

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);

  // State for crop rectangle
  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });

  // Studio Adjustments
  const [adjustments, setAdjustments] = useState<Adjustments>({
    brightness: 100,
    contrast: 100,
    saturation: 100,
    temperature: 0,
  });

  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'n' | 's' | 'e' | 'w' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const ASPECT_RATIO = PASSPORT_SETTINGS.photoWidthCm / PASSPORT_SETTINGS.photoHeightCm;

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });

    const initialHeight = height * 0.8;
    const initialWidth = initialHeight * ASPECT_RATIO;

    setCrop({
      x: (width - initialWidth) / 2,
      y: (height - initialHeight) / 2,
      width: initialWidth,
      height: initialHeight
    });
  };

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType || !imgRef.current) return;

    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;
    const { width: imgW, height: imgH } = imgDisplaySize;

    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'nw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'ne':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'se':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'n':
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 's':
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'w':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        break;
      case 'e':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        break;
    }

    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
    setDragType(null);
  }, []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const filterString = useMemo(() => {
    return `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) sepia(${adjustments.temperature > 0 ? adjustments.temperature : 0}%) hue-rotate(${adjustments.temperature < 0 ? adjustments.temperature * 2 : 0}deg)`;
  }, [adjustments]);

  const handleConfirm = () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;

    const sX = crop.x * scaleX;
    const sY = crop.y * scaleY;
    const sW = crop.width * scaleX;
    const sH = crop.height * scaleY;

    canvas.width = sW;
    canvas.height = sH;

    // Apply filters to canvas
    ctx.filter = filterString;
    ctx.drawImage(imgRef.current, sX, sY, sW, sH, 0, 0, sW, sH);

    onConfirm(canvas.toDataURL('image/jpeg', 0.95));
  };

  const resetAll = () => {
    setAdjustments({
      brightness: 100,
      contrast: 100,
      saturation: 100,
      temperature: 0,
    });
    // Optional: reset crop area to default passport aspect
    if (imgDisplaySize.width > 0) {
      const h = imgDisplaySize.height * 0.8;
      const w = h * ASPECT_RATIO;
      setCrop({
        x: (imgDisplaySize.width - w) / 2,
        y: (imgDisplaySize.height - h) / 2,
        width: w,
        height: h
      });
    }
  };

  // Simplified Histogram visualization
  const Histogram = () => (
    <div className="w-full h-24 bg-black/40 rounded-xl overflow-hidden relative flex items-end gap-px px-2 group">
      <div className="absolute top-2 left-2 flex items-center gap-2 opacity-50 group-hover:opacity-100 transition-opacity">
        <Activity size={10} className="text-blue-400" />
        <span className="text-[8px] font-black uppercase tracking-tighter text-white/40">Studio Levels</span>
      </div>
      {[...Array(30)].map((_, i) => (
        <div 
          key={i} 
          className="flex-1 bg-gradient-to-t from-blue-500/40 to-blue-400/80 rounded-t-sm transition-all duration-300"
          style={{ height: `${Math.random() * 40 + (adjustments.brightness / 4) + (i % 5 * 10)}%` }}
        ></div>
      ))}
    </div>
  );

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-950/98 backdrop-blur-2xl p-4 animate-in fade-in zoom-in duration-300">
      <div className="bg-slate-900 rounded-[3rem] w-full max-w-6xl h-[90vh] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.6)] border border-white/10">
        {/* Header */}
        <div className="px-10 py-6 border-b border-white/5 flex items-center justify-between bg-slate-900/50">
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl shadow-blue-500/20">
              <Maximize size={24} className="text-white" />
            </div>
            <div>
              <h3 className="text-white font-black text-2xl tracking-tight leading-none">Studio Mastering</h3>
              <p className="text-[10px] text-blue-400 font-black mt-2 uppercase tracking-[0.2em]">Manual Crop & Color Grading</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button 
              onClick={resetAll}
              className="flex items-center gap-2 px-6 py-2.5 rounded-2xl text-white/50 font-black text-xs hover:bg-white/5 hover:text-white transition-all border border-transparent hover:border-white/10"
            >
              <RotateCcw size={16} />
              Reset All
            </button>
            <button onClick={onCancel} className="p-2 hover:bg-white/10 rounded-full text-white/50 transition-all hover:rotate-90">
              <X size={28} />
            </button>
          </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex overflow-hidden">
          {/* Cropping Area */}
          <div 
            ref={containerRef}
