          {/* Adjustment Sidebar */}
          <div className="w-80 bg-slate-900 border-l border-white/5 flex flex-col p-8 space-y-8 overflow-y-auto">
            <div>
              <h4 className="text-xs font-black text-white/30 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
