        {/* Footer Actions */}
        <div className="px-10 py-8 bg-slate-900 border-t border-white/5 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4 text-white/40">
             <div className="flex gap-2">
                <div className="w-4 h-4 rounded-full bg-blue-500/20 flex items-center justify-center text-[8px] font-black text-blue-400">1</div>
                <span className="text-[10px] font-black uppercase tracking-widest">Adjust</span>
             </div>
             <div className="w-8 h-px bg-white/10"></div>
             <div className="flex gap-2">
                <div className="w-4 h-4 rounded-full bg-blue-500/20 flex items-center justify-center text-[8px] font-black text-blue-400">2</div>
