                  {[...Array(9)].map((_, i) => <div key={i} className="border-[0.5px] border-white/30"></div>)}
                </div>

                {/* Handles */}
                <div onMouseDown={(e) => handleMouseDown(e, 'nw')} className="absolute -top-2 -left-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-nw-resize z-10 shadow-lg"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'ne')} className="absolute -top-2 -right-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-ne-resize z-10 shadow-lg"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'sw')} className="absolute -bottom-2 -left-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-sw-resize z-10 shadow-lg"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'se')} className="absolute -bottom-2 -right-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-se-resize z-10 shadow-lg"></div>
              </div>
            </div>
          </div>

          {/* Adjustment Sidebar */}
          <div className="w-96 bg-slate-900 border-l border-white/5 flex flex-col p-8 space-y-8 overflow-y-auto custom-scrollbar">
            {/* Curves Dialog Section */}
            <div>
              <h4 className="text-xs font-black text-white/30 uppercase tracking-[0.2em] mb-6 flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <BezierCurve size={14} className="text-blue-500" />
                   Curves
                </div>
                <span className="text-[9px] lowercase opacity-50">Click to add points</span>
              </h4>

              <div className="relative aspect-square w-full bg-slate-950 rounded-2xl border border-white/5 overflow-hidden group/curves">
                {/* Graph Grid */}
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none">
                  {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-white/5"></div>)}
                </div>

                {/* Diagonal Helper Line */}
                <div className="absolute inset-0 border-t border-white/5 rotate-45 origin-top-left translate-y-full pointer-events-none"></div>

                {/* The Interactive Surface */}
                <canvas 
                   ref={curvesCanvasRef}
                   className="absolute inset-0 w-full h-full cursor-crosshair"
                   onClick={addCurvePoint}
                />

                {/* SVG Curve Drawing */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <polyline
                    points={curvePoints.map(p => `${(p.x / 255) * 100}%, ${(1 - p.y / 255) * 100}%`).join(' ')}
                    fill="none"
                    stroke="#3b82f6"
                    strokeWidth="3"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    className="drop-shadow-[0_0_8px_rgba(59,130,246,0.6)]"
                  />
                  {curvePoints.map((p, i) => (
                    <circle
                      key={i}
                      cx={`${(p.x / 255) * 100}%`}
                      cy={`${(1 - p.y / 255) * 100}%`}
                      r="6"
                      fill={activePointIndex === i ? "#fff" : "#3b82f6"}
                      stroke="#1e293b"
                      strokeWidth="2"
                      className="cursor-pointer pointer-events-auto hover:r-8 transition-all"
                      onMouseDown={(e) => handleMouseDown(e, 'curve', i)}
                      onDoubleClick={() => removePoint(i)}
                      onContextMenu={(e) => { e.preventDefault(); removePoint(i); }}
                    />
                  ))}
                </svg>

                {/* Axis Labels */}
                <div className="absolute bottom-1 right-2 text-[8px] font-black text-white/20 uppercase tracking-tighter">Input</div>
                <div className="absolute top-2 left-1 text-[8px] font-black text-white/20 uppercase tracking-tighter -rotate-90">Output</div>
              </div>
            </div>

            {/* Sliders Section */}
            <div className="space-y-8">
              <div>
                <h4 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] mb-4">Basic Correction</h4>
                <div className="space-y-6">
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <label className="text-xs font-bold text-white/60 flex items-center gap-2">
                        <Sun size={14} /> Brightness
                      </label>
                      <span className="text-[10px] font-black text-blue-400">{adjustments.brightness}%</span>
                    </div>
                    <input 
                      type="range" min="50" max="150" value={adjustments.brightness} 
                      onChange={e => setAdjustments(a => ({...a, brightness: parseInt(e.target.value)}))}
                      className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
                    />
                  </div>

                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <label className="text-xs font-bold text-white/60 flex items-center gap-2">
                        <Contrast size={14} /> Contrast
                      </label>
                      <span className="text-[10px] font-black text-blue-400">{adjustments.contrast}%</span>
                    </div>
                    <input 
                      type="range" min="50" max="150" value={adjustments.contrast} 
                      onChange={e => setAdjustments(a => ({...a, contrast: parseInt(e.target.value)}))}
                      className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
                    />
                  </div>
                </div>
              </div>

              <div>
                <h4 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] mb-4">Color Grading</h4>
                <div className="space-y-6">
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <label className="text-xs font-bold text-white/60 flex items-center gap-2">
                        <Droplets size={14} /> Saturation
                      </label>
                      <span className="text-[10px] font-black text-blue-400">{adjustments.saturation}%</span>
                    </div>
                    <input 
                      type="range" min="0" max="200" value={adjustments.saturation} 
                      onChange={e => setAdjustments(a => ({...a, saturation: parseInt(e.target.value)}))}
                      className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
                    />
                  </div>

                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <label className="text-xs font-bold text-white/60 flex items-center gap-2">
                        <Thermometer size={14} /> Temperature
                      </label>
                      <span className="text-[10px] font-black text-blue-400">{adjustments.temperature > 0 ? `+${adjustments.temperature}` : adjustments.temperature}</span>
                    </div>
                    <input 
                      type="range" min="-50" max="50" value={adjustments.temperature} 
                      onChange={e => setAdjustments(a => ({...a, temperature: parseInt(e.target.value)}))}
                      className="w-full h-1.5 bg-gradient-to-r from-blue-500 via-slate-800 to-orange-500 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-auto pt-8 border-t border-white/5">
              <div className="bg-slate-950 p-5 rounded-[1.5rem] border border-white/5 shadow-inner">
                 <h5 className="text-[9px] font-black text-blue-500 uppercase tracking-widest mb-2">Tonal Mapping</h5>
                 <p className="text-[10px] text-white/30 leading-relaxed italic">
                    Curves allow precise control over shadows, midtones, and highlights. Drag the points to create a custom "Look".
                 </p>
              </div>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="px-10 py-8 bg-slate-900 border-t border-white/5 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4 text-white/40">
             <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-full border border-white/5">
                <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                <span className="text-[10px] font-black uppercase tracking-widest">Adjust</span>
             </div>
             <div className="w-6 h-px bg-white/10"></div>
             <div className="flex items-center gap-3">
                <span className="text-[10px] font-black uppercase tracking-widest opacity-30">Process</span>
             </div>
          </div>

          <div className="flex items-center gap-5 w-full md:w-auto">
            <button 
              onClick={onCancel}
              className="flex-1 md:flex-none px-10 py-4 rounded-full text-white/40 font-black text-sm hover:bg-white/5 hover:text-white transition-all"
            >
              Discard Changes
            </button>
            <button 
              onClick={handleConfirm}
              className="flex-1 md:flex-none flex items-center justify-center gap-4 bg-blue-600 hover:bg-blue-700 text-white px-12 py-5 rounded-full font-black text-lg shadow-2xl shadow-blue-500/40 transition-all active:scale-95 hover:translate-y-[-4px]"
            >
              <Check size={24} />
              Apply & AI Background
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

