import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Upload, Camera, Printer, Layout, Download, X, AlertCircle, RefreshCw, Plus, Maximize } from 'lucide-react';
import { ProcessedPhoto, PASSPORT_SETTINGS, A4_WIDTH_CM, A4_HEIGHT_CM } from './types';
import { fileToBase64, generateA4Sheet } from './utils/imageUtils';
import { removeBackgroundAndOptimize } from './services/geminiService';
import PhotoCard from './components/PhotoCard';
import CropModal from './components/CropModal';

const App: React.FC = () => {
  const [photos, setPhotos] = useState<ProcessedPhoto[]>([]);
  const [isGeneratingSheet, setIsGeneratingSheet] = useState(false);
  const [finalSheetUrl, setFinalSheetUrl] = useState<string | null>(null);
  const [showPreviewModal, setShowPreviewModal] = useState(false);

  // Cropping State
  const [croppingPhotoId, setCroppingPhotoId] = useState<string | null>(null);

  // Handle File Upload
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newPhotos: ProcessedPhoto[] = files.map((file: File) => ({
      id: Math.random().toString(36).substring(7),
      originalName: file.name,
      originalUrl: URL.createObjectURL(file),
      processedUrl: null,
      status: 'idle',
      quantity: 8 // Default to 8 photos for passport
    }));

    setPhotos(prev => [...prev, ...newPhotos]);

    // Auto-open crop for the first file if queue was empty
    if (photos.length === 0 && newPhotos.length > 0) {
      setCroppingPhotoId(newPhotos[0].id);
    }

    e.target.value = '';
  };

  const handleCropComplete = async (croppedDataUrl: string, customPrompt?: string) => {
    if (!croppingPhotoId) return;

    const id = croppingPhotoId;
    setCroppingPhotoId(null);

    // Update photo status to processing
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', originalUrl: croppedDataUrl } : p));

    try {
      // Background removal on the cropped image
      const base64 = croppedDataUrl.split(',')[1];
      const processedUrl = await removeBackgroundAndOptimize(base64, 'image/jpeg', customPrompt);

      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'ready', processedUrl } : p
      ));

      // Automatically open next idle photo for cropping if any
      setPhotos(currentPhotos => {
        const nextIdle = currentPhotos.find(p => p.status === 'idle');
        if (nextIdle) {
          setCroppingPhotoId(nextIdle.id);
        }
        return currentPhotos;
      });

    } catch (err) {
      console.error(err);
      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'error', error: 'AI processing failed' } : p
      ));
    }
  };

  const updateQuantity = (id: string, quantity: number) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity } : p));
  };

  const removePhoto = (id: string) => {
    setPhotos(prev => prev.filter(p => p.id !== id));
  };

  const generateSheet = async () => {
    const readyPhotos = photos.filter(p => p.status === 'ready' && p.processedUrl && p.quantity > 0);
    if (readyPhotos.length === 0) return;

    setIsGeneratingSheet(true);
    try {
      const sheetUrl = await generateA4Sheet(
        readyPhotos.map(p => ({ url: p.processedUrl!, quantity: p.quantity })),
        PASSPORT_SETTINGS
      );
      setFinalSheetUrl(sheetUrl);
      setShowPreviewModal(true);
    } catch (err) {
      console.error("Sheet generation failed:", err);
    } finally {
      setIsGeneratingSheet(false);
    }
  };

  const downloadSheet = () => {
    if (!finalSheetUrl) return;
    const link = document.createElement('a');
    link.href = finalSheetUrl;
    link.download = `VIPUL_PrintSheet_${new Date().getTime()}.jpg`;
    link.click();
  };

  const totalToPrint = useMemo(() => {
    return photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0);
  }, [photos]);

  const photoToCrop = useMemo(() => {
    return photos.find(p => p.id === croppingPhotoId);
  }, [photos, croppingPhotoId]);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 selection:bg-blue-100">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex items-center justify-between sticky top-0 z-40 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-[1.25rem] flex items-center justify-center text-white shadow-xl shadow-blue-500/20 transform transition-transform hover:rotate-6">
            <Layout size={28} />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-none uppercase">VIPUL EDITOR</h1>
            <p className="text-[10px] text-blue-600 font-black mt-1.5 tracking-[0.2em] uppercase">Visual Studio Automator</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden lg:flex flex-col items-end">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">A4 Print Queue</span>
            <span className="text-base font-black text-slate-800 mt-1">{totalToPrint} Copies Total</span>
          </div>
          <button 
            onClick={generateSheet}
            disabled={totalToPrint === 0 || isGeneratingSheet}
            className="group flex items-center gap-3 bg-slate-900 hover:bg-blue-600 disabled:bg-slate-200 text-white px-8 py-4 rounded-full text-sm font-black transition-all transform hover:scale-[1.03] active:scale-95 shadow-2xl shadow-slate-200 disabled:shadow-none"
          >
            {isGeneratingSheet ? (
              <RefreshCw className="animate-spin" size={20} />
            ) : (
              <Printer className="group-hover:animate-bounce" size={20} />
            )}
            {isGeneratingSheet ? 'Building Sheet...' : 'Export A4 Sheet'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-8 space-y-12">
        {/* Upload Area */}
        {photos.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-40 border-4 border-dashed border-slate-200 rounded-[4rem] bg-white transition-all hover:border-blue-400 hover:bg-blue-50/30 group shadow-sm">
            <div className="w-28 h-28 bg-blue-600 rounded-full flex items-center justify-center text-white mb-10 group-hover:scale-110 transition-all shadow-2xl shadow-blue-500/30">
              <Upload size={48} />
            </div>
            <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tight uppercase tracking-widest">VIPUL EDITOR</h2>
            <p className="text-slate-500 mb-12 max-w-lg text-center text-xl font-medium leading-relaxed">
              Upload raw photos. Edit, crop, and apply AI magic. Automate your studio passport workflow with 3.1 x 4.2cm precision.
            </p>
            <label className="cursor-pointer bg-slate-900 hover:bg-blue-600 text-white px-12 py-5 rounded-full font-black text-xl shadow-2xl shadow-slate-300 transition-all active:scale-95 hover:translate-y-[-4px]">
              Browse Raw Files
              <input 
                type="file" 
                multiple 
                accept="image/*" 
                onChange={handleFileUpload} 
                className="hidden" 
              />
            </label>
            <div className="mt-12 flex gap-12 items-center opacity-40">
              <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">Fixed Borders</span>
              <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">AI Dress Change</span>
              <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">A4 Spacing</span>
            </div>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between">
              <div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Workshop Desk</h2>
                <p className="text-sm font-bold text-slate-400 mt-1 uppercase tracking-widest">Managing {photos.length} individual subjects</p>
              </div>
              <label className="cursor-pointer flex items-center gap-3 text-blue-600 hover:bg-blue-600 hover:text-white px-6 py-3 rounded-2xl font-black text-sm bg-blue-50 transition-all shadow-sm">
                <Plus size={20} />
                Add More
                <input 
                  type="file" 
                  multiple 
                  accept="image/*" 
                  onChange={handleFileUpload} 
                  className="hidden" 
                />
              </label>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
              {photos.map(photo => (
                <div key={photo.id} className="relative group perspective-1000">
                  <PhotoCard 
                    photo={photo}
                    onUpdateQuantity={updateQuantity}
                    onRemove={removePhoto}
                    onProcess={() => setCroppingPhotoId(photo.id)}
                  />
                  {photo.status === 'idle' && (
                    <div className="absolute inset-x-0 bottom-[100px] flex justify-center pointer-events-none z-10">
                       <div className="bg-blue-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full shadow-2xl animate-bounce tracking-widest uppercase">
                          Review Required
                       </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Dynamic Crop Interface */}
      {photoToCrop && (
        <CropModal 
          imageUrl={photoToCrop.originalUrl}
          onCancel={() => setCroppingPhotoId(null)}
          onConfirm={handleCropComplete}
        />
      )}

      {/* A4 Sheet Print Preview */}
      {showPreviewModal && finalSheetUrl && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6 animate-in fade-in duration-500">
          <div className="bg-white rounded-[3rem] w-full max-w-6xl max-h-[95vh] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.4)] scale-in-center border border-white/20">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-white/50">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-green-100 text-green-600 rounded-[1.5rem] flex items-center justify-center shadow-inner">
                  <Printer size={32} />
                </div>
                <div>
                  <h3 className="font-black text-slate-900 text-2xl tracking-tight">Print Ready Sheet</h3>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-[0.2em] mt-1">3.1 x 4.2cm • 300 DPI • Cutting Borders</p>
                </div>
              </div>
              <button 
                onClick={() => setShowPreviewModal(false)}
                className="p-3 hover:bg-slate-100 rounded-full text-slate-400 transition-all hover:rotate-90"
              >
                <X size={32} />
              </button>
            </div>

            <div className="flex-1 overflow-auto bg-slate-100/50 p-16 flex justify-center">
              <div className="print-sheet bg-white shadow-[0_40px_80px_rgba(0,0,0,0.1)] relative" style={{ 
                width: `${A4_WIDTH_CM * 32}px`, 
                height: `${A4_HEIGHT_CM * 32}px`,
                minWidth: `${A4_WIDTH_CM * 32}px`
              }}>
                <img src={finalSheetUrl} alt="A4 Print Sheet" className="w-full h-full object-contain" />
              </div>
            </div>

            <div className="p-10 bg-slate-50 border-t border-slate-200 flex flex-col md:flex-row items-center justify-between gap-8">
              <div className="flex items-center gap-6 text-slate-600 bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200/50 max-w-lg">
                <AlertCircle size={32} className="text-blue-500 shrink-0" />
