import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
// Fix: Replace non-existent BezierCurve with Spline
import { X, Check, Maximize, RotateCcw, Move, Sun, Contrast, Droplets, Thermometer, Activity, Spline, Wand2, MessageSquare } from 'lucide-react';
import { PASSPORT_SETTINGS } from '../types';

interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

interface Point {
  x: number;
  y: number;
}

interface Adjustments {
  brightness: number;
  contrast: number;
  saturation: number;
  temperature: number;
}

interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);
  const curvesCanvasRef = useRef<HTMLCanvasElement>(null);

  // State for crop rectangle
  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });

  // Custom AI Prompt State
  const [aiPrompt, setAiPrompt] = useState('');

  // Studio Adjustments
  const [adjustments, setAdjustments] = useState<Adjustments>({
    brightness: 100,
    contrast: 100,
    saturation: 100,
    temperature: 0,
  });

  // Curves State: Values from 0 to 255
  const [curvePoints, setCurvePoints] = useState<Point[]>([
    { x: 0, y: 0 },
    { x: 255, y: 255 },
  ]);
  const [activePointIndex, setActivePointIndex] = useState<number | null>(null);

  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'n' | 's' | 'e' | 'w' | 'curve' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const ASPECT_RATIO = PASSPORT_SETTINGS.photoWidthCm / PASSPORT_SETTINGS.photoHeightCm;

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });

    const initialHeight = height * 0.8;
    const initialWidth = initialHeight * ASPECT_RATIO;

    setCrop({
      x: (width - initialWidth) / 2,
      y: (height - initialHeight) / 2,
      width: initialWidth,
      height: initialHeight
    });
  };

  const getCurveValue = (inputX: number) => {
    const sorted = [...curvePoints].sort((a, b) => a.x - b.x);
    const p0 = sorted[0];
    const pN = sorted[sorted.length - 1];

    if (p0 && inputX <= p0.x) return p0.y;
    if (pN && inputX >= pN.x) return pN.y;

    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i];
      const p2 = sorted[i + 1];
      if (p1 && p2 && inputX >= p1.x && inputX <= p2.x) {
        const dx = p2.x - p1.x;
        if (dx === 0) return p1.y;
        const t = (inputX - p1.x) / dx;
        return p1.y + t * (p2.y - p1.y);
      }
    }
    return inputX;
  };

  const lookupTable = useMemo(() => {
    const lut = new Uint8Array(256);
    for (let i = 0; i < 256; i++) {
      lut[i] = Math.max(0, Math.min(255, getCurveValue(i)));
    }
    return lut;
  }, [curvePoints]);

  const tableValuesString = useMemo(() => {
    return Array.from(lookupTable).map((v: number) => (v / 255).toFixed(3)).join(' ');
  }, [lookupTable]);

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType, pointIndex?: number) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
    if (pointIndex !== undefined) setActivePointIndex(pointIndex);
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType || !imgRef.current) return;

    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;

    if (dragType === 'curve' && activePointIndex !== null && curvesCanvasRef.current) {
      const rect = curvesCanvasRef.current.getBoundingClientRect();
      const newX = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const newY = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));

      const newPoints = [...curvePoints];
      if (activePointIndex === 0) {
        newPoints[0] = { x: 0, y: newY };
      } else if (activePointIndex === curvePoints.length - 1) {
        newPoints[newPoints.length - 1] = { x: 255, y: newY };
      } else {
        newPoints[activePointIndex] = { x: newX, y: newY };
      }
      setCurvePoints(newPoints);
      return;
    }

    const { width: imgW, height: imgH } = imgDisplaySize;
    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'nw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'ne':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'se':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'n':
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 's':
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'w':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        break;
      case 'e':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        break;
    }

    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize, activePointIndex, curvePoints]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
    setDragType(null);
    setActivePointIndex(null);
  }, []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const filterString = useMemo(() => {
    return `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#studio-curves-filter) sepia(${adjustments.temperature > 0 ? adjustments.temperature : 0}%) hue-rotate(${adjustments.temperature < 0 ? adjustments.temperature * 2 : 0}deg)`;
  }, [adjustments, tableValuesString]);

  const handleConfirm = async () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;

    const sX = crop.x * scaleX;
    const sY = crop.y * scaleY;
    const sW = crop.width * scaleX;
    const sH = crop.height * scaleY;

    canvas.width = sW;
    canvas.height = sH;

    ctx.filter = filterString;
    ctx.drawImage(imgRef.current, sX, sY, sW, sH, 0, 0, sW, sH);

    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  const addCurvePoint = (e: React.MouseEvent) => {
    if (!curvesCanvasRef.current) return;
    const rect = curvesCanvasRef.current.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);

    const threshold = 15;
    const exists = curvePoints.some(p => Math.abs(p.x - x) < threshold && Math.abs(p.y - y) < threshold);
    if (exists) return;

    setCurvePoints(prev => [...prev, { x, y }].sort((a, b) => a.x - b.x));
  };

  const removePoint = (index: number) => {
    if (index === 0 || index === curvePoints.length - 1) return;
    setCurvePoints(prev => prev.filter((_, i) => i !== index));
  };

  const resetAll = () => {
    setAdjustments({
      brightness: 100,
      contrast: 100,
      saturation: 100,
      temperature: 0,
    });
    setCurvePoints([{ x: 0, y: 0 }, { x: 255, y: 255 }]);
    setAiPrompt('');
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-950/98 backdrop-blur-2xl p-4 animate-in fade-in zoom-in duration-300">
      <div id="studio-curves-container" style={{ position: 'absolute', width: 0, height: 0, overflow: 'hidden' }}>
        <svg xmlns="http://www.w3.org/2000/svg">
          <filter id="studio-curves-filter">
            <feComponentTransfer>
              <feFuncR type="table" tableValues={tableValuesString} />
              <feFuncG type="table" tableValues={tableValuesString} />
              <feFuncB type="table" tableValues={tableValuesString} />
            </feComponentTransfer>
          </filter>
        </svg>
      </div>

      <div className="bg-slate-900 rounded-[3rem] w-full max-w-6xl h-[90vh] overflow-hidden flex flex-col shadow-[0_0_120px_rgba(0,0,0,0.8)] border border-white/10">
        {/* Header */}
        <div className="px-10 py-6 border-b border-white/5 flex items-center justify-between bg-slate-900/50">
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl shadow-blue-500/20">
              <Maximize size={24} className="text-white" />
            </div>
            <div>
              <h3 className="text-white font-black text-2xl tracking-tight leading-none uppercase">VIPUL EDITOR</h3>
              <p className="text-[10px] text-blue-400 font-black mt-2 uppercase tracking-[0.2em]">Studio Pro Mastering</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button 
              onClick={resetAll}
              className="flex items-center gap-2 px-6 py-2.5 rounded-2xl text-white/50 font-black text-xs hover:bg-white/5 hover:text-white transition-all border border-transparent hover:border-white/10"
            >
              <RotateCcw size={16} />
              Reset All
            </button>
            <button onClick={onCancel} className="p-2 hover:bg-white/10 rounded-full text-white/50 transition-all hover:rotate-90">
              <X size={28} />
            </button>
          </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex overflow-hidden">
          {/* Cropping Area */}
          <div 
            ref={containerRef}
            className="flex-1 relative bg-black/40 flex items-center justify-center p-12 overflow-hidden select-none"
          >
            <div className="relative inline-block">
              <img
                ref={imgRef}
                src={imageUrl}
                alt="Crop target"
                onLoad={handleImageLoad}
                style={{ filter: filterString }}
                className="max-h-[65vh] object-contain rounded-lg transition-all duration-100"
                draggable={false}
              />

              <div className="absolute inset-0 pointer-events-none overflow-hidden">
                 <div className="absolute inset-0 bg-black/70" style={{
                   clipPath: `polygon(
                     0% 0%, 0% 100%, 
                     ${crop.x}px 100%, 
                     ${crop.x}px ${crop.y}px, 
                     ${crop.x + crop.width}px ${crop.y}px, 
                     ${crop.x + crop.width}px ${crop.y + crop.height}px, 
                     ${crop.x}px ${crop.y + crop.height}px, 
                     ${crop.x}px 100%, 
                     100% 100%, 100% 0%
                   )`
                 }}></div>
              </div>

              <div 
                style={{ left: crop.x, top: crop.y, width: crop.width, height: crop.height }}
                className="absolute border-2 border-blue-500 shadow-[0_0_0_1px_rgba(255,255,255,0.4)] cursor-move group"
                onMouseDown={(e) => handleMouseDown(e, 'move')}
              >
                <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-40 group-hover:opacity-60 transition-opacity">
                  {[...Array(9)].map((_, i) => <div key={i} className="border-[0.5px] border-white/30"></div>)}
                </div>

                <div onMouseDown={(e) => handleMouseDown(e, 'nw')} className="absolute -top-2 -left-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-nw-resize z-10 shadow-lg"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'ne')} className="absolute -top-2 -right-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-ne-resize z-10 shadow-lg"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'sw')} className="absolute -bottom-2 -left-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-sw-resize z-10 shadow-lg"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'se')} className="absolute -bottom-2 -right-2 w-5 h-5 bg-white border-2 border-blue-600 rounded-full cursor-se-resize z-10 shadow-lg"></div>
              </div>
            </div>
          </div>

          {/* Adjustment Sidebar */}
          <div className="w-96 bg-slate-900 border-l border-white/5 flex flex-col p-8 space-y-6 overflow-y-auto custom-scrollbar">
            {/* AI Prompt Input Bar */}
            <div className="space-y-3">
              <h4 className="text-xs font-black text-blue-400 uppercase tracking-[0.2em] flex items-center gap-2">
                <Wand2 size={14} /> AI Magic Prompt
              </h4>
              <div className="relative group">
                <textarea
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  placeholder="e.g., Change clothes to a black business suit, adjust hair style..."
                  className="w-full h-24 bg-slate-950 border border-white/10 rounded-2xl p-4 text-xs text-white placeholder:text-white/20 focus:outline-none focus:border-blue-500 transition-all resize-none custom-scrollbar"
                />
                <div className="absolute bottom-3 right-3 opacity-20 group-hover:opacity-50 transition-opacity">
                  <MessageSquare size={14} className="text-white" />
                </div>
              </div>
              <p className="text-[9px] text-white/30 italic">
                Optional: Tell the AI to change clothing or refine details during background removal.
              </p>
            </div>

            <div className="h-px bg-white/5"></div>

            {/* Curves Dialog Section */}
            <div>
              <h4 className="text-xs font-black text-white/30 uppercase tracking-[0.2em] mb-4 flex items-center justify-between">
                <div className="flex items-center gap-2">
                   {/* Fix: Replace non-existent BezierCurve with Spline */}
                   <Spline size={14} className="text-blue-500" />
                   Curves
                </div>
              </h4>

              <div className="relative aspect-square w-full bg-slate-950 rounded-2xl border border-white/5 overflow-hidden">
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none">
                  {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-white/5"></div>)}
                </div>
                <canvas 
                   ref={curvesCanvasRef}
                   className="absolute inset-0 w-full h-full cursor-crosshair"
                   onClick={addCurvePoint}
                />
                <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <polyline
                    points={curvePoints.map(p => `${(p.x / 255) * 100}%, ${(1 - p.y / 255) * 100}%`).join(' ')}
                    fill="none"
                    stroke="#3b82f6"
                    strokeWidth="3"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                  {curvePoints.map((p, i) => (
                    <circle
                      key={i}
                      cx={`${(p.x / 255) * 100}%`}
                      cy={`${(1 - p.y / 255) * 100}%`}
                      r="6"
                      fill={activePointIndex === i ? "#fff" : "#3b82f6"}
                      stroke="#1e293b"
                      strokeWidth="2"
                      className="cursor-pointer pointer-events-auto transition-all"
                      onMouseDown={(e) => handleMouseDown(e, 'curve', i)}
                      onDoubleClick={() => removePoint(i)}
                    />
                  ))}
                </svg>
              </div>
            </div>

            {/* Sliders Section */}
            <div className="space-y-6">
              <div className="space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between items-center">
                    <label className="text-[10px] font-bold text-white/40 flex items-center gap-2 uppercase tracking-widest">
                      <Sun size={12} /> Brightness
                    </label>
                    <span className="text-[10px] font-black text-blue-400">{adjustments.brightness}%</span>
                  </div>
                  <input 
                    type="range" min="50" max="150" value={adjustments.brightness} 
                    onChange={e => setAdjustments(a => ({...a, brightness: parseInt(e.target.value)}))}
                    className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between items-center">
                    <label className="text-[10px] font-bold text-white/40 flex items-center gap-2 uppercase tracking-widest">
                      <Contrast size={12} /> Contrast
                    </label>
                    <span className="text-[10px] font-black text-blue-400">{adjustments.contrast}%</span>
                  </div>
                  <input 
                    type="range" min="50" max="150" value={adjustments.contrast} 
                    onChange={e => setAdjustments(a => ({...a, contrast: parseInt(e.target.value)}))}
                    className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between items-center">
                    <label className="text-[10px] font-bold text-white/40 flex items-center gap-2 uppercase tracking-widest">
                      <Droplets size={12} /> Saturation
                    </label>
                    <span className="text-[10px] font-black text-blue-400">{adjustments.saturation}%</span>
                  </div>
                  <input 
                    type="range" min="0" max="200" value={adjustments.saturation} 
                    onChange={e => setAdjustments(a => ({...a, saturation: parseInt(e.target.value)}))}
                    className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
                  />
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="px-10 py-8 bg-slate-900 border-t border-white/5 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4 text-white/40">
             <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-full border border-white/5">
                <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                <span className="text-[10px] font-black uppercase tracking-widest">Adjust</span>
             </div>
             <div className="w-6 h-px bg-white/10"></div>
             <div className="flex items-center gap-3">
                <span className="text-[10px] font-black uppercase tracking-widest opacity-30">AI Finalization</span>
             </div>
          </div>

          <div className="flex items-center gap-5 w-full md:w-auto">
            <button 
              onClick={onCancel}
              className="flex-1 md:flex-none px-10 py-4 rounded-full text-white/40 font-black text-sm hover:bg-white/5 hover:text-white transition-all"
            >
              Discard
            </button>
            <button 
              onClick={handleConfirm}
              className="flex-1 md:flex-none flex items-center justify-center gap-4 bg-blue-600 hover:bg-blue-700 text-white px-12 py-5 rounded-full font-black text-lg shadow-2xl shadow-blue-500/40 transition-all active:scale-95 hover:translate-y-[-4px]"
            >
              <Check size={24} />
              Process & Finish
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CropModal;

export interface ProcessedPhoto {
  id: string;
  originalName: string;
  originalUrl: string;
  processedUrl: string | null;
  status: 'idle' | 'processing' | 'ready' | 'error';
  error?: string;
  quantity: number;
}

export interface SheetPhoto {
  id: string;
  photoId: string;
  url: string;
  x: number;
  y: number;
  width: number;
  height: number;
}

export interface PrintSettings {
  photoWidthCm: number;
  photoHeightCm: number;
  spacingMm: number;
  maxHorizontal: number;
}

export const PASSPORT_SETTINGS: PrintSettings = {
  photoWidthCm: 3.1,
  photoHeightCm: 4.2,
  spacingMm: 4,
  maxHorizontal: 6
};

// A4 Dimensions in CM
export const A4_WIDTH_CM = 21.0;
export const A4_HEIGHT_CM = 29.7;

// Conversion factor for 300 DPI
export const CM_TO_PX = 118.11;
export const CM_TO_VIEWPORT = 35; // Visual scaling for the editor

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, Download, Printer, Move, RotateCcw, LayoutGrid, Check, Layers } from 'lucide-react';
import { SheetPhoto, A4_WIDTH_CM, A4_HEIGHT_CM, CM_TO_VIEWPORT } from '../types';

interface LayoutStudioProps {
  initialPhotos: { url: string; quantity: number; photoId: string }[];
  onClose: () => void;
  onExport: (dataUrl: string) => void;
}

const LayoutStudio: React.FC<LayoutStudioProps> = ({ initialPhotos, onClose, onExport }) => {
  const [sheetPhotos, setSheetPhotos] = useState<SheetPhoto[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const sheetRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  // Initialize photo positions in a standard grid
  useEffect(() => {
    const photos: SheetPhoto[] = [];
    let currentX = 1;
    let currentY = 1;
    const itemWidth = 3.1;
    const itemHeight = 4.2;
    const spacing = 0.5;

    initialPhotos.forEach((group) => {
      for (let i = 0; i < group.quantity; i++) {
        if (currentX + itemWidth > A4_WIDTH_CM - 1) {
          currentX = 1;
          currentY += itemHeight + spacing;
        }

        photos.push({
          id: `${group.photoId}-${i}`,
          photoId: group.photoId,
          url: group.url,
          x: currentX,
          y: currentY,
          width: itemWidth,
          height: itemHeight
        });

        currentX += itemWidth + spacing;
      }
    });
    setSheetPhotos(photos);
  }, [initialPhotos]);

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    const startX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const startY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const photo = sheetPhotos.find(p => p.id === id);
    if (!photo) return;

    const initialX = photo.x;
    const initialY = photo.y;
    setActiveId(id);

    const onMove = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const currentY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;

      const dx = (currentX - startX) / CM_TO_VIEWPORT;
      const dy = (currentY - startY) / CM_TO_VIEWPORT;

      setSheetPhotos(prev => prev.map(p => 
        p.id === id ? { 
          ...p, 
          x: Math.max(0, Math.min(A4_WIDTH_CM - p.width, initialX + dx)),
          y: Math.max(0, Math.min(A4_HEIGHT_CM - p.height, initialY + dy))
        } : p
      ));
    };

    const onEnd = () => {
      setActiveId(null);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchmove', onMove);
      window.removeEventListener('touchend', onEnd);
    };

    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onEnd);
    window.addEventListener('touchmove', onMove);
    window.addEventListener('touchend', onEnd);
  };

  const captureSheet = async () => {
    setIsExporting(true);
    // Simple way to export: we build a canvas version of current state
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpiScale = 118.11; // 300 DPI
    canvas.width = A4_WIDTH_CM * dpiScale;
    canvas.height = A4_HEIGHT_CM * dpiScale;

    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (const p of sheetPhotos) {
      const img = new Image();
      img.src = p.url;
      await new Promise(resolve => img.onload = resolve);
      ctx.drawImage(img, p.x * dpiScale, p.y * dpiScale, p.width * dpiScale, p.height * dpiScale);

      // Black cut line
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 1;
      ctx.strokeRect(p.x * dpiScale, p.y * dpiScale, p.width * dpiScale, p.height * dpiScale);
    }

    const dataUrl = canvas.toDataURL('image/jpeg', 0.95);
    onExport(dataUrl);
    setIsExporting(false);
  };

  return (
