import React, { useState, useCallback, useMemo } from 'react';
import { Upload, Printer, Layout, Download, X, AlertCircle, RefreshCw, Plus, Maximize, Sparkles } from 'lucide-react';
import { ProcessedPhoto, PASSPORT_SETTINGS } from './types';
import { removeBackgroundAndOptimize } from './services/geminiService';
import PhotoCard from './components/PhotoCard';
import CropModal from './components/CropModal';
import LayoutStudio from './components/LayoutStudio';

const App: React.FC = () => {
  const [photos, setPhotos] = useState<ProcessedPhoto[]>([]);
  const [showLayoutStudio, setShowLayoutStudio] = useState(false);
  const [croppingPhotoId, setCroppingPhotoId] = useState<string | null>(null);

  // Handle File Upload
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newPhotos: ProcessedPhoto[] = files.map((file: File) => ({
      id: Math.random().toString(36).substring(7),
      originalName: file.name,
      originalUrl: URL.createObjectURL(file),
      processedUrl: null,
      status: 'idle',
      quantity: 8 
    }));

    setPhotos(prev => [...prev, ...newPhotos]);
    if (photos.length === 0 && newPhotos.length > 0) {
      setCroppingPhotoId(newPhotos[0].id);
    }
    e.target.value = '';
  };

  const handleCropComplete = async (croppedDataUrl: string, customPrompt?: string) => {
    if (!croppingPhotoId) return;
    const id = croppingPhotoId;
    setCroppingPhotoId(null);

    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', originalUrl: croppedDataUrl } : p));

    try {
      const base64 = croppedDataUrl.split(',')[1];
      const processedUrl = await removeBackgroundAndOptimize(base64, 'image/jpeg', customPrompt);

      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'ready', processedUrl } : p
      ));

      setPhotos(currentPhotos => {
        const nextIdle = currentPhotos.find(p => p.status === 'idle');
        if (nextIdle) setCroppingPhotoId(nextIdle.id);
        return currentPhotos;
      });
    } catch (err) {
      console.error(err);
      setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'error', error: 'AI processing failed' } : p));
    }
  };

  const updateQuantity = (id: string, quantity: number) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity } : p));
  };

  const removePhoto = (id: string) => {
    setPhotos(prev => prev.filter(p => p.id !== id));
  };

  const totalToPrint = useMemo(() => {
    return photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0);
  }, [photos]);

  const readyPhotosData = useMemo(() => {
    return photos
      .filter(p => p.status === 'ready' && p.processedUrl && p.quantity > 0)
      .map(p => ({ url: p.processedUrl!, quantity: p.quantity, photoId: p.id }));
  }, [photos]);

  const photoToCrop = useMemo(() => {
    return photos.find(p => p.id === croppingPhotoId);
  }, [photos, croppingPhotoId]);

  return (
    <div className="min-h-screen flex flex-col bg-[#05070a] text-slate-300 selection:bg-blue-500/30 overflow-x-hidden">
      {/* Premium UI Overlay */}
      <div className="fixed top-0 left-0 w-full h-[60vh] bg-gradient-to-b from-blue-600/5 to-transparent pointer-events-none z-0"></div>

      {/* Modern Studio Header */}
      <header className="relative z-40 bg-slate-900/60 backdrop-blur-2xl border-b border-white/5 px-10 py-6 flex items-center justify-between sticky top-0">
        <div className="flex items-center gap-6 group">
          <div className="w-14 h-14 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-2xl shadow-blue-500/20 transform transition-all group-hover:scale-110 group-hover:rotate-3">
            <Sparkles size={32} fill="currentColor" />
          </div>
          <div>
            <h1 className="text-3xl font-black text-white tracking-tighter leading-none uppercase italic">VIPUL EDITOR</h1>
            <p className="text-[9px] text-blue-500 font-black mt-2 tracking-[0.3em] uppercase opacity-70">Vision Studio Professional v4.0</p>
          </div>
        </div>

        <div className="flex items-center gap-8">
          <div className="hidden lg:flex flex-col items-end">
            <span className="text-[9px] font-black text-white/30 uppercase tracking-[0.2em] leading-none">Global Queue</span>
            <span className="text-xl font-black text-white mt-2">{totalToPrint} TOTAL COPIES</span>
          </div>
          <button 
            onClick={() => setShowLayoutStudio(true)}
            disabled={totalToPrint === 0}
            className="group flex items-center gap-4 bg-white hover:bg-blue-50 disabled:bg-white/5 text-slate-950 disabled:text-white/20 px-10 py-4 rounded-full text-sm font-black transition-all transform hover:scale-[1.05] active:scale-95 shadow-[0_10px_40px_rgba(255,255,255,0.1)]"
          >
            <Printer className="group-hover:rotate-12 transition-transform" size={20} />
            ENTER LAYOUT STUDIO
          </button>
        </div>
      </header>

      {/* Main Studio Floor */}
      <main className="relative z-10 flex-1 max-w-7xl mx-auto w-full p-10 space-y-16">
        {photos.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-48 border-2 border-dashed border-white/5 rounded-[4rem] bg-slate-900/20 backdrop-blur-sm transition-all hover:border-blue-500/30 group">
            <div className="relative">
              <div className="absolute inset-0 bg-blue-500 blur-[60px] opacity-20 group-hover:opacity-40 transition-opacity"></div>
              <div className="relative w-32 h-32 bg-gradient-to-b from-blue-500 to-blue-700 rounded-[2.5rem] flex items-center justify-center text-white mb-12 shadow-2xl group-hover:scale-110 transition-all">
                <Upload size={56} />
              </div>
            </div>
            <h2 className="text-5xl font-black text-white mb-6 tracking-tighter uppercase text-center">UNLEASH THE STUDIO</h2>
            <p className="text-slate-500 mb-14 max-w-xl text-center text-lg font-medium leading-relaxed uppercase tracking-tighter opacity-60">
              Drag and drop your raw captures. Our AI engine and interactive Layout Studio handle the rest with pixel precision.
            </p>
            <label className="cursor-pointer bg-white hover:bg-blue-50 text-slate-950 px-14 py-6 rounded-full font-black text-xl shadow-2xl transition-all active:scale-95 hover:-translate-y-1">
              INITIALIZE UPLOAD
              <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
            </label>
          </div>
        ) : (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="flex items-end justify-between px-2">
              <div>
                <div className="flex items-center gap-3 mb-2">
                   <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
                   <span className="text-[10px] font-black text-blue-500 uppercase tracking-[0.3em]">Active Workshop</span>
                </div>
                <h2 className="text-5xl font-black text-white tracking-tighter uppercase italic">Desk View</h2>
              </div>
              <label className="cursor-pointer flex items-center gap-4 text-white hover:text-blue-400 px-8 py-4 rounded-3xl font-black text-sm bg-white/5 border border-white/5 hover:bg-white/10 transition-all">
                <Plus size={24} />
                ADD RAW ASSET
                <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
              </label>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
              {photos.map(photo => (
                <PhotoCard 
                  key={photo.id}
                  photo={photo}
                  onUpdateQuantity={updateQuantity}
                  onRemove={removePhoto}
                  onProcess={() => setCroppingPhotoId(photo.id)}
                />
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Interactive Modals */}
      {photoToCrop && (
        <CropModal 
          imageUrl={photoToCrop.originalUrl}
          onCancel={() => setCroppingPhotoId(null)}
          onConfirm={handleCropComplete}
        />
      )}

      {showLayoutStudio && (
        <LayoutStudio 
          initialPhotos={readyPhotosData}
          onClose={() => setShowLayoutStudio(false)}
          onExport={(dataUrl) => {
            const link = document.createElement('a');
            link.href = dataUrl;
            link.download = `VIPUL_STUDIO_EXPORT_${Date.now()}.jpg`;
            link.click();
          }}
        />
      )}

      {/* Catchy Status Footer */}
      <footer className="relative z-40 bg-slate-950 border-t border-white/5 py-8 px-12 flex items-center justify-between overflow-hidden">
        <div className="absolute inset-0 bg-blue-600/5 pointer-events-none"></div>
        <div className="flex items-center gap-16 relative z-10">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-blue-500 uppercase tracking-widest mb-1">Engine Status</span>
            <span className="text-xs font-bold text-white uppercase tracking-tighter">VIPUL CORE v4.0 ACTIVE</span>
          </div>
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-blue-500 uppercase tracking-widest mb-1">Precision Range</span>
            <span className="text-xs font-bold text-white uppercase tracking-tighter">3.1x4.2CM ISO Standard</span>
          </div>
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-blue-500 uppercase tracking-widest mb-1">AI Latency</span>
            <span className="text-xs font-bold text-white uppercase tracking-tighter">Sub-300ms Background Removal</span>
          </div>
        </div>
        <div className="text-[10px] font-black text-white/20 uppercase tracking-[0.4em] italic">
          Professional Studio Automator
        </div>
      </footer>
    </div>
  );
};

export default App;

