              <span className="text-lg font-black text-white min-w-[32px] text-center font-mono tracking-tighter">
                {photo.quantity.toString().padStart(2, '0')}
              </span>
              <button 
                onClick={() => onUpdateQuantity(photo.id, photo.quantity + 1)}
                className="w-10 h-10 flex items-center justify-center bg-white/5 hover:bg-white/10 rounded-xl border border-white/5 text-white transition-all active:scale-90"
              >
                <Plus size={16} />
              </button>
            </div>
          </div>
        ) : (
          photo.status !== 'processing' && (
            <button 
              onClick={() => onProcess(photo.id)}
              className="w-full py-5 bg-white hover:bg-blue-600 text-slate-950 hover:text-white rounded-[1.5rem] text-[10px] font-black uppercase tracking-[0.2em] shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3"
            >
              <Sparkles size={16} />
              Begin Processing
            </button>
          )
        )}
      </div>
    </div>
  );
};

