    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', originalUrl: croppedDataUrl } : p));

    try {
      const base64 = croppedDataUrl.split(',')[1];
      const processedUrl = await removeBackgroundAndOptimize(base64, 'image/jpeg', customPrompt);

      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'ready', processedUrl } : p
      ));

      setPhotos(currentPhotos => {
        const nextIdle = currentPhotos.find(p => p.status === 'idle');
        if (nextIdle) setCroppingPhotoId(nextIdle.id);
        return currentPhotos;
      });
    } catch (err) {
      console.error(err);
      setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'error', error: 'AI processing failed' } : p));
    }
  };

  const updateQuantity = (id: string, quantity: number) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity } : p));
  };

  const removePhoto = (id: string) => {
    setPhotos(prev => prev.filter(p => p.id !== id));
  };

  const totalToPrint = useMemo(() => {
    return photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0);
  }, [photos]);

  const readyPhotosData = useMemo(() => {
    return photos
      .filter(p => p.status === 'ready' && p.processedUrl && p.quantity > 0)
      .map(p => ({ url: p.processedUrl!, quantity: p.quantity, photoId: p.id }));
  }, [photos]);

  const photoToCrop = useMemo(() => {
    return photos.find(p => p.id === croppingPhotoId);
  }, [photos, croppingPhotoId]);

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc] text-slate-900 selection:bg-blue-100 overflow-x-hidden">
      {/* Modern Studio Header */}
      <header className="relative z-40 bg-white/80 backdrop-blur-2xl border-b border-slate-200/60 px-10 py-5 flex items-center justify-between sticky top-0 shadow-sm">
        <div className="flex items-center gap-6 group">
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20 transition-all group-hover:rotate-3">
            <Sparkles size={28} fill="currentColor" />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tighter leading-none uppercase italic">VIPUL EDITOR</h1>
            <p className="text-[9px] text-blue-600 font-black mt-1.5 tracking-[0.3em] uppercase opacity-80">Visual Automation Suite</p>
          </div>
        </div>

        <div className="flex items-center gap-8">
          <div className="hidden lg:flex flex-col items-end">
            <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] leading-none">Global Print Queue</span>
            <span className="text-lg font-black text-slate-900 mt-1">{totalToPrint} TOTAL COPIES</span>
          </div>
          <button 
            onClick={() => setShowLayoutStudio(true)}
            disabled={totalToPrint === 0}
            className="group flex items-center gap-4 bg-slate-900 hover:bg-blue-600 disabled:bg-slate-200 text-white px-10 py-4 rounded-full text-sm font-black transition-all transform hover:scale-[1.05] active:scale-95 shadow-xl shadow-slate-200 disabled:shadow-none"
          >
            <Printer className="group-hover:rotate-12 transition-transform" size={18} />
            LAYOUT STUDIO
          </button>
        </div>
      </header>

      {/* Main Studio Floor */}
      <main className="relative z-10 flex-1 max-w-7xl mx-auto w-full p-10 space-y-12">
        {photos.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-40 border-4 border-dashed border-slate-200 rounded-[4rem] bg-white transition-all hover:border-blue-500/30 group shadow-sm">
            <div className="relative w-28 h-28 bg-blue-600 rounded-[2rem] flex items-center justify-center text-white mb-10 shadow-2xl transition-all group-hover:scale-105">
              <Upload size={48} />
            </div>
            <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tighter uppercase text-center">STUDIO WORKSPACE</h2>
            <p className="text-slate-500 mb-12 max-w-lg text-center text-lg font-medium leading-relaxed opacity-70">
              Drag and drop your raw captures. Automate background removal and A4 layouts with professional-grade precision.
            </p>
            <label className="cursor-pointer bg-slate-900 hover:bg-blue-600 text-white px-14 py-5 rounded-full font-black text-xl shadow-2xl transition-all active:scale-95 hover:-translate-y-1">
              OPEN RAW FILES
              <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
            </label>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="flex items-end justify-between px-2">
              <div>
                <div className="flex items-center gap-2 mb-2">
                   <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse"></div>
                   <span className="text-[10px] font-black text-blue-500 uppercase tracking-[0.3em]">Active Workshop</span>
                </div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase italic">Desk View</h2>
              </div>
              <label className="cursor-pointer flex items-center gap-3 text-slate-600 hover:text-blue-600 px-8 py-4 rounded-3xl font-black text-sm bg-white border border-slate-200 hover:border-blue-200 transition-all shadow-sm">
                <Plus size={20} />
                ADD ASSET
                <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
