        <div className="flex items-center gap-12">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Engine Status</span>
            <span className="text-xs font-bold text-slate-900 uppercase">VIPUL CORE ACTIVE</span>
