import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, Download, Move, RotateCcw, LayoutGrid, Check, Layers, Printer } from 'lucide-react';
import { SheetPhoto, A4_WIDTH_CM, A4_HEIGHT_CM, CM_TO_VIEWPORT } from '../types';

interface LayoutStudioProps {
  initialPhotos: { url: string; quantity: number; photoId: string }[];
  onClose: () => void;
  onExport: (dataUrl: string) => void;
}

const LayoutStudio: React.FC<LayoutStudioProps> = ({ initialPhotos, onClose, onExport }) => {
  const [sheetPhotos, setSheetPhotos] = useState<SheetPhoto[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const sheetRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const photos: SheetPhoto[] = [];
    let currentX = 1;
    let currentY = 1;
    const itemWidth = 3.1;
    const itemHeight = 4.2;
    const spacing = 0.5;

    initialPhotos.forEach((group) => {
      for (let i = 0; i < group.quantity; i++) {
        if (currentX + itemWidth > A4_WIDTH_CM - 1) {
          currentX = 1;
          currentY += itemHeight + spacing;
        }
        photos.push({
          id: `${group.photoId}-${i}`,
          photoId: group.photoId,
          url: group.url,
          x: currentX,
          y: currentY,
          width: itemWidth,
          height: itemHeight
        });
        currentX += itemWidth + spacing;
      }
    });
    setSheetPhotos(photos);
  }, [initialPhotos]);

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    const startX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const startY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const photo = sheetPhotos.find(p => p.id === id);
    if (!photo) return;

    const initialX = photo.x;
    const initialY = photo.y;
    setActiveId(id);

    const onMove = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const currentY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;
      const dx = (currentX - startX) / CM_TO_VIEWPORT;
      const dy = (currentY - startY) / CM_TO_VIEWPORT;

      setSheetPhotos(prev => prev.map(p => 
        p.id === id ? { 
          ...p, 
          x: Math.max(0, Math.min(A4_WIDTH_CM - p.width, initialX + dx)),
          y: Math.max(0, Math.min(A4_HEIGHT_CM - p.height, initialY + dy))
        } : p
      ));
    };

    const onEnd = () => {
      setActiveId(null);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onEnd);
    };

    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onEnd);
  };

  const captureSheet = async () => {
    setIsExporting(true);
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const dpiScale = 118.11;
    canvas.width = A4_WIDTH_CM * dpiScale;
    canvas.height = A4_HEIGHT_CM * dpiScale;
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (const p of sheetPhotos) {
      const img = new Image();
      img.src = p.url;
      await new Promise(resolve => img.onload = resolve);
      ctx.drawImage(img, p.x * dpiScale, p.y * dpiScale, p.width * dpiScale, p.height * dpiScale);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 1;
      ctx.strokeRect(p.x * dpiScale, p.y * dpiScale, p.width * dpiScale, p.height * dpiScale);
    }
    onExport(canvas.toDataURL('image/jpeg', 0.95));
    setIsExporting(false);
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col bg-slate-100 animate-in fade-in duration-500 overflow-hidden">
      {/* Header */}
      <header className="relative z-10 px-10 py-5 border-b border-slate-200 bg-white flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-6">
          <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white">
            <LayoutGrid size={20} />
          </div>
          <div>
            <h2 className="text-slate-900 text-xl font-black tracking-tight uppercase">LAYOUT STUDIO</h2>
            <p className="text-[9px] text-blue-600 font-black tracking-[0.2em] uppercase mt-0.5">Interactive Print Engine</p>
          </div>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
          <X size={24} />
        </button>
      </header>

      {/* Workspace */}
      <main className="flex-1 overflow-auto bg-slate-50 flex justify-center p-20 custom-scrollbar">
        <div 
          ref={sheetRef}
          className="relative bg-white shadow-[0_30px_60px_rgba(0,0,0,0.12)] border border-slate-200"
          style={{ 
            width: `${A4_WIDTH_CM * CM_TO_VIEWPORT}px`, 
            height: `${A4_HEIGHT_CM * CM_TO_VIEWPORT}px`,
            minWidth: `${A4_WIDTH_CM * CM_TO_VIEWPORT}px`
          }}
        >
          {/* Grid Helper */}
          <div className="absolute inset-0 pointer-events-none opacity-[0.03]" style={{ 
            backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)',
            backgroundSize: `${CM_TO_VIEWPORT}px ${CM_TO_VIEWPORT}px`
          }}></div>

          {sheetPhotos.map((p) => (
            <div
              key={p.id}
              onMouseDown={(e) => handleDrag(p.id, e)}
              className={`absolute cursor-move transition-shadow duration-200 select-none group ${activeId === p.id ? 'z-50 shadow-2xl scale-105' : 'z-10 shadow-sm'}`}
              style={{
                left: `${p.x * CM_TO_VIEWPORT}px`,
                top: `${p.y * CM_TO_VIEWPORT}px`,
                width: `${p.width * CM_TO_VIEWPORT}px`,
                height: `${p.height * CM_TO_VIEWPORT}px`,
              }}
            >
              <img src={p.url} alt="Passport" className="w-full h-full object-cover border border-black pointer-events-none" />
              {activeId === p.id && (
                <div className="absolute -top-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white text-[8px] font-black px-3 py-1 rounded shadow-lg whitespace-nowrap">
                  {p.x.toFixed(1)}cm, {p.y.toFixed(1)}cm
                </div>
              )}
            </div>
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="relative z-10 px-10 py-8 border-t border-slate-200 bg-white flex items-center justify-between">
        <div className="flex items-center gap-6">
           <div className="flex flex-col">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Interactive Mode</span>
              <div className="flex items-center gap-2 mt-1 text-slate-900">
                 <Move size={14} className="text-blue-600" />
                 <span className="text-sm font-bold">Free Placement</span>
              </div>
           </div>
        </div>

        <div className="flex items-center gap-4">
          <button onClick={onClose} className="px-8 py-3 rounded-full text-slate-600 font-black text-sm">Discard</button>
          <button 
            onClick={captureSheet}
            disabled={isExporting}
            className="flex items-center justify-center gap-3 bg-slate-900 text-white px-12 py-4 rounded-full font-black text-sm shadow-xl transition-all hover:bg-blue-600 active:scale-95"
          >
            {isExporting ? <RotateCcw className="animate-spin" /> : <Download size={20} />}
            {isExporting ? 'CAPTURING...' : 'DOWNLOAD PRINT SHEET'}
          </button>
        </div>
      </footer>
    </div>
  );
};

export default LayoutStudio;

import React, { useState, useCallback, useMemo } from 'react';
import { Upload, Printer, Layout, Download, X, AlertCircle, RefreshCw, Plus, Maximize, Sparkles, Layers } from 'lucide-react';
import { ProcessedPhoto, PASSPORT_SETTINGS } from './types';
import { removeBackgroundAndOptimize } from './services/geminiService';
import PhotoCard from './components/PhotoCard';
import CropModal from './components/CropModal';
import LayoutStudio from './components/LayoutStudio';

const App: React.FC = () => {
  const [photos, setPhotos] = useState<ProcessedPhoto[]>([]);
  const [showLayoutStudio, setShowLayoutStudio] = useState(false);
  const [croppingPhotoId, setCroppingPhotoId] = useState<string | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files: File[] = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newPhotos: ProcessedPhoto[] = files.map((file: File) => ({
      id: Math.random().toString(36).substring(7),
      originalName: file.name,
      originalUrl: URL.createObjectURL(file),
      processedUrl: null,
      status: 'idle',
      quantity: 8 
    }));

    setPhotos(prev => [...prev, ...newPhotos]);
    if (photos.length === 0 && newPhotos.length > 0) {
      setCroppingPhotoId(newPhotos[0].id);
    }
    e.target.value = '';
  };

  const handleCropComplete = async (croppedDataUrl: string, customPrompt?: string) => {
    if (!croppingPhotoId) return;
    const id = croppingPhotoId;
    setCroppingPhotoId(null);

    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', originalUrl: croppedDataUrl } : p));

    try {
      const base64 = croppedDataUrl.split(',')[1];
      const processedUrl = await removeBackgroundAndOptimize(base64, 'image/jpeg', customPrompt);

      setPhotos(prev => prev.map(p => 
        p.id === id ? { ...p, status: 'ready', processedUrl } : p
      ));

      setPhotos(currentPhotos => {
        const nextIdle = currentPhotos.find(p => p.status === 'idle');
        if (nextIdle) setCroppingPhotoId(nextIdle.id);
        return currentPhotos;
      });
    } catch (err) {
      console.error(err);
      setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'error', error: 'AI processing failed' } : p));
    }
  };

  const updateQuantity = (id: string, quantity: number) => {
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity } : p));
  };

  const removePhoto = (id: string) => {
    setPhotos(prev => prev.filter(p => p.id !== id));
  };

  const totalToPrint = useMemo(() => {
    return photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0);
  }, [photos]);

  const readyPhotosData = useMemo(() => {
    return photos
      .filter(p => p.status === 'ready' && p.processedUrl && p.quantity > 0)
      .map(p => ({ url: p.processedUrl!, quantity: p.quantity, photoId: p.id }));
  }, [photos]);

  const photoToCrop = useMemo(() => {
    return photos.find(p => p.id === croppingPhotoId);
  }, [photos, croppingPhotoId]);

  return (
    <div className="min-h-screen flex flex-col text-slate-800 selection:bg-blue-100">
      {/* Immersive Minimalism Header */}
      <header className="z-40 px-12 py-8 flex items-center justify-between sticky top-0 transition-all">
        <div className="flex items-center gap-4 group">
          <div className="w-10 h-10 bg-slate-900 rounded-full flex items-center justify-center text-white transition-transform group-hover:scale-105">
            <Sparkles size={20} fill="currentColor" />
          </div>
          <div>
            <h1 className="text-xl font-extrabold tracking-tighter uppercase leading-none">VIPUL</h1>
            <p className="text-[8px] font-black tracking-[0.4em] uppercase text-slate-400 mt-1">Immersive Studio</p>
          </div>
        </div>

        <div className="flex items-center gap-12">
          {totalToPrint > 0 && (
            <div className="flex flex-col items-end">
              <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Queue</span>
              <span className="text-sm font-black text-slate-900">{totalToPrint} Copies</span>
            </div>
          )}
          <button 
            onClick={() => setShowLayoutStudio(true)}
            disabled={totalToPrint === 0}
            className="flex items-center gap-3 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-200 text-white px-8 py-3 rounded-full text-[10px] font-black tracking-widest transition-all disabled:shadow-none shadow-xl shadow-slate-200 uppercase"
          >
            <Printer size={14} />
            Layout Studio
          </button>
        </div>
      </header>

      {/* Main Studio Floor */}
      <main className="flex-1 max-w-7xl mx-auto w-full p-12 space-y-12">
        {photos.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-40 animate-in fade-in zoom-in duration-700">
            <div className="w-24 h-24 bg-slate-50 border border-slate-100 rounded-full flex items-center justify-center mb-8 shadow-sm">
              <Upload size={32} className="text-slate-400" />
            </div>
            <h2 className="text-3xl font-light text-slate-900 mb-2 tracking-tighter">Start your creative process.</h2>
            <p className="text-slate-400 mb-10 max-w-sm text-center text-sm font-medium leading-relaxed">
              Upload raw assets to begin professional grade background removal and grading.
            </p>
            <label className="cursor-pointer bg-slate-900 text-white px-12 py-4 rounded-full font-black text-xs tracking-widest shadow-2xl transition-all hover:scale-105 active:scale-95 uppercase">
              Upload Assets
              <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
            </label>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between">
              <h2 className="text-2xl font-extrabold tracking-tighter uppercase">Workshop</h2>
              <label className="cursor-pointer flex items-center gap-2 text-slate-500 hover:text-slate-900 px-6 py-2 rounded-full font-bold text-[10px] bg-white/50 border border-slate-200 transition-all uppercase tracking-widest">
                <Plus size={14} />
                Add Image
                <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
              </label>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {photos.map(photo => (
                <PhotoCard 
                  key={photo.id}
                  photo={photo}
                  onUpdateQuantity={updateQuantity}
                  onRemove={removePhoto}
                  onProcess={() => setCroppingPhotoId(photo.id)}
                />
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Interactive Modals */}
      {photoToCrop && (
        <CropModal 
          imageUrl={photoToCrop.originalUrl}
          onCancel={() => setCroppingPhotoId(null)}
          onConfirm={handleCropComplete}
        />
      )}

      {showLayoutStudio && (
        <LayoutStudio 
          initialPhotos={readyPhotosData}
          onClose={() => setShowLayoutStudio(false)}
          onExport={(dataUrl) => {
            const link = document.createElement('a');
            link.href = dataUrl;
            link.download = `VIPUL_STUDIO_EXPORT_${Date.now()}.jpg`;
            link.click();
          }}
        />
      )}
    </div>
  );
};

export default App;

