}

interface Point {
  x: number;
  y: number;
}

interface Adjustments {
  brightness: number;
  contrast: number;
  saturation: number;
}

interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });
  const [aiPrompt, setAiPrompt] = useState('');
  const [adjustments, setAdjustments] = useState<Adjustments>({ brightness: 100, contrast: 100, saturation: 100 });

  // 4 Channels of Curves
  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });
  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [activePointIndex, setActivePointIndex] = useState<number | null>(null);

  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'curve' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });
    setCrop({ x: width * 0.1, y: height * 0.1, width: width * 0.8, height: height * 0.8 });
  };

  const getCurveValue = (points: Point[], inputX: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    const p0 = sorted[0];
    const pN = sorted[sorted.length - 1];
    if (inputX <= p0.x) return p0.y;
    if (inputX >= pN.x) return pN.y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i];
      const p2 = sorted[i+1];
      if (inputX >= p1.x && inputX <= p2.x) {
        const t = (inputX - p1.x) / (p2.x - p1.x);
        return p1.y + t * (p2.y - p1.y);
      }
    }
    return inputX;
  };

  const generateTable = (masterPoints: Point[], channelPoints: Point[]) => {
    const table = new Array(256);
    for (let i = 0; i < 256; i++) {
      const valAfterMaster = getCurveValue(masterPoints, i);
      const finalVal = getCurveValue(channelPoints, valAfterMaster);
      table[i] = (Math.max(0, Math.min(255, finalVal)) / 255).toFixed(3);
    }
    return table.join(' ');
  };

  const tableR = useMemo(() => generateTable(curves.rgb, curves.r), [curves]);
  const tableG = useMemo(() => generateTable(curves.rgb, curves.g), [curves]);
  const tableB = useMemo(() => generateTable(curves.rgb, curves.b), [curves]);

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType, pIdx?: number) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
    if (pIdx !== undefined) setActivePointIndex(pIdx);
  };

  const handleCurveClick = (e: React.MouseEvent, channel: Channel) => {
    if (dragType === 'curve') return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);

    // Check if clicking near existing point to remove (double click simulated)
    const existingIdx = curves[channel].findIndex(p => Math.abs(p.x - x) < 10 && Math.abs(p.y - y) < 10);
    if (existingIdx !== -1 && existingIdx !== 0 && existingIdx !== curves[channel].length - 1) {
      setCurves(prev => ({ ...prev, [channel]: prev[channel].filter((_, i) => i !== existingIdx) }));
      return;
    }

    // Add new point
    setCurves(prev => ({
      ...prev,
      [channel]: [...prev[channel], { x, y }].sort((a, b) => a.x - b.x)
    }));
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType || !imgRef.current) return;
    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;

    if (dragType === 'curve' && activePointIndex !== null) {
      const channelEl = document.getElementById(`curve-${activeChannel}`);
      if (!channelEl) return;
      const rect = channelEl.getBoundingClientRect();
      const newX = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const newY = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));

      setCurves(prev => {
        const newPoints = [...prev[activeChannel]];
        if (activePointIndex === 0) newPoints[0] = { x: 0, y: newY };
        else if (activePointIndex === newPoints.length - 1) newPoints[newPoints.length - 1] = { x: 255, y: newY };
        else newPoints[activePointIndex] = { x: newX, y: newY };
        return { ...prev, [activeChannel]: newPoints };
      });
      return;
    }

    const { width: imgW, height: imgH } = imgDisplaySize;
    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'se':
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'nw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      // Other corners for freestyle
      case 'ne':
        newCrop.y = Math.max(0, Math.min(startCrop.y + startCrop.height - 20, startCrop.y + dy));
        newCrop.width = Math.max(20, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        newCrop.x = Math.max(0, Math.min(startCrop.x + startCrop.width - 20, startCrop.x + dx));
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(20, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
    }
    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize, activePointIndex, activeChannel]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
    setDragType(null);
    setActivePointIndex(null);
  }, []);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, handleMouseMove, handleMouseUp]);

  const filterString = useMemo(() => {
    return `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#immersive-grading-filter)`;
  }, [adjustments, tableR, tableG, tableB]);

  const handleConfirm = async () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;
    canvas.width = crop.width * scaleX;
    canvas.height = crop.height * scaleY;
    ctx.filter = filterString;
    ctx.drawImage(imgRef.current, crop.x * scaleX, crop.y * scaleY, crop.width * scaleX, crop.height * scaleY, 0, 0, canvas.width, canvas.height);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  const scrollChannel = (dir: 1 | -1) => {
    const idx = CHANNELS.indexOf(activeChannel);
    const nextIdx = (idx + dir + CHANNELS.length) % CHANNELS.length;
    setActiveChannel(CHANNELS[nextIdx]);
    scrollRef.current?.children[nextIdx].scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 animate-in fade-in duration-500">
      <svg width="0" height="0" className="absolute">
        <filter id="immersive-grading-filter">
          <feComponentTransfer>
            <feFuncR type="table" tableValues={tableR} />
            <feFuncG type="table" tableValues={tableG} />
            <feFuncB type="table" tableValues={tableB} />
          </feComponentTransfer>
        </filter>
      </svg>

      <div className="glass rounded-[2rem] w-full max-w-6xl h-[85vh] overflow-hidden flex flex-col shadow-2xl relative">
        {/* Header */}
        <div className="px-10 py-6 border-b border-slate-100/50 flex items-center justify-between">
          <div className="flex flex-col">
            <h3 className="text-sm font-black tracking-widest uppercase text-slate-900">Visual Grading</h3>
            <p className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.4em] mt-1">Freestyle Master Suite</p>
          </div>
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-all text-slate-300 hover:text-slate-900">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Main Visualizer */}
          <div className="flex-1 relative bg-slate-50/30 flex items-center justify-center p-12 overflow-hidden select-none">
            <div className="relative inline-block">
              <img
                ref={imgRef}
                src={imageUrl}
                alt="Target"
                onLoad={handleImageLoad}
                style={{ filter: filterString }}
                className="max-h-[55vh] object-contain rounded-sm shadow-2xl"
                draggable={false}
              />
              <div 
                style={{ left: crop.x, top: crop.y, width: crop.width, height: crop.height }}
                className="absolute border border-white/80 shadow-[0_0_0_9999px_rgba(255,255,255,0.4)] cursor-move"
                onMouseDown={(e) => handleMouseDown(e, 'move')}
              >
                {/* Freestyle Handles */}
                <div onMouseDown={(e) => handleMouseDown(e, 'nw')} className="absolute -top-1 -left-1 w-3 h-3 bg-white border border-slate-900 rounded-full cursor-nw-resize"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'ne')} className="absolute -top-1 -right-1 w-3 h-3 bg-white border border-slate-900 rounded-full cursor-ne-resize"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'sw')} className="absolute -bottom-1 -left-1 w-3 h-3 bg-white border border-slate-900 rounded-full cursor-sw-resize"></div>
                <div onMouseDown={(e) => handleMouseDown(e, 'se')} className="absolute -bottom-1 -right-1 w-3 h-3 bg-white border border-slate-900 rounded-full cursor-se-resize"></div>
              </div>
            </div>
          </div>

          {/* Grading Sidebar */}
          <div className="w-80 border-l border-slate-100/50 bg-white/20 backdrop-blur-md flex flex-col p-8 space-y-10 overflow-y-auto custom-scrollbar">

            {/* AI Prompt */}
            <div className="space-y-3">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <Wand2 size={12} className="text-slate-900"/> Edit Request
              </label>
              <textarea
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                placeholder="e.g. Formal black attire..."
                className="w-full h-20 bg-white/50 border border-slate-200 rounded-xl p-3 text-[10px] text-slate-900 placeholder:text-slate-300 focus:outline-none focus:border-slate-900 transition-all resize-none font-medium"
              />
            </div>

            {/* Horizontal Curves Navigator */}
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                 <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   <Spline size={12} className="text-slate-900"/> Channel: <span className="text-slate-900">{activeChannel.toUpperCase()}</span>
                 </label>
                 <div className="flex gap-2">
                   <button onClick={() => scrollChannel(-1)} className="p-1 hover:bg-slate-100 rounded-full text-slate-400"><ArrowLeft size={14}/></button>
                   <button onClick={() => scrollChannel(1)} className="p-1 hover:bg-slate-100 rounded-full text-slate-400"><ArrowRight size={14}/></button>
                 </div>
              </div>

              <div ref={scrollRef} className="flex overflow-x-auto snap-x custom-scrollbar pb-2 -mx-2 px-2 gap-4">
                {CHANNELS.map(ch => (
                  <div key={ch} className={`flex-shrink-0 w-64 snap-center space-y-2`}>
                    <div 
                      id={`curve-${ch}`}
                      className={`relative aspect-square w-full rounded-lg border overflow-hidden transition-all duration-300 ${activeChannel === ch ? 'border-slate-900 ring-2 ring-slate-900/5 bg-white' : 'border-slate-100 bg-slate-50/50 grayscale'}`}
                      onClick={(e) => handleCurveClick(e, ch)}
                    >
                      <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-5">
                        {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-black"></div>)}
                      </div>
                      <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                        <polyline
                          points={curves[ch].map(p => `${(p.x / 255) * 100}%, ${(1 - p.y / 255) * 100}%`).join(' ')}
                          fill="none"
                          stroke={ch === 'rgb' ? '#000' : ch === 'r' ? '#ef4444' : ch === 'g' ? '#22c55e' : '#3b82f6'}
                          strokeWidth="2"
                        />
                        {curves[ch].map((p, i) => (
                          <circle
                            key={i}
                            cx={`${(p.x / 255) * 100}%`}
                            cy={`${(1 - p.y / 255) * 100}%`}
                            r="5"
                            fill="white"
                            stroke="#000"
                            strokeWidth="1.5"
                            className="cursor-pointer pointer-events-auto hover:scale-125 transition-transform"
                            onMouseDown={(e) => {
                              setActiveChannel(ch);
                              handleMouseDown(e, 'curve', i);
                            }}
                          />
                        ))}
                      </svg>
                    </div>
                    <p className="text-[8px] font-bold text-center text-slate-400 uppercase tracking-widest">
                      {ch === 'rgb' ? 'Luminance' : ch === 'r' ? 'Red' : ch === 'g' ? 'Green' : 'Blue'}
                    </p>
                  </div>
                ))}
              </div>
            </div>

            {/* Basic Adjustments */}
            <div className="space-y-6">
              <div className="space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between items-center text-[9px] font-bold text-slate-400 uppercase tracking-widest">
                    <span>Brightness</span>
                    <span className="text-slate-900">{adjustments.brightness}%</span>
                  </div>
                  <input type="range" min="50" max="150" value={adjustments.brightness} 
                    onChange={e => setAdjustments(a => ({...a, brightness: parseInt(e.target.value)}))}
                    className="w-full"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between items-center text-[9px] font-bold text-slate-400 uppercase tracking-widest">
                    <span>Contrast</span>
                    <span className="text-slate-900">{adjustments.contrast}%</span>
                  </div>
                  <input type="range" min="50" max="150" value={adjustments.contrast} 
                    onChange={e => setAdjustments(a => ({...a, contrast: parseInt(e.target.value)}))}
                    className="w-full"
                  />
                </div>
              </div>
            </div>

          </div>
        </div>

        {/* Footer */}
        <div className="px-10 py-8 border-t border-slate-100/50 flex items-center justify-between">
          <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest italic leading-relaxed max-w-xs">
            Refine curves and framing for professional studio excellence.
          </p>
          <div className="flex items-center gap-4">
            <button onClick={onCancel} className="px-8 py-3 rounded-full text-slate-400 font-black text-[10px] tracking-widest hover:text-slate-900 transition-all uppercase">Discard</button>
            <button onClick={handleConfirm} className="bg-slate-900 text-white px-12 py-4 rounded-full font-black text-[10px] tracking-widest shadow-xl transition-all hover:scale-105 active:scale-95 uppercase">Finalize Prep</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CropModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, Download, Move, LayoutGrid, RotateCcw } from 'lucide-react';
import { SheetPhoto, A4_WIDTH_CM, A4_HEIGHT_CM, CM_TO_VIEWPORT } from '../types';

interface LayoutStudioProps {
  initialPhotos: { url: string; quantity: number; photoId: string }[];
  onClose: () => void;
  onExport: (dataUrl: string) => void;
}

const LayoutStudio: React.FC<LayoutStudioProps> = ({ initialPhotos, onClose, onExport }) => {
  const [sheetPhotos, setSheetPhotos] = useState<SheetPhoto[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const photos: SheetPhoto[] = [];
    let currentX = 1;
    let currentY = 1;
    const itemWidth = 3.1;
    const itemHeight = 4.2;
    const spacing = 0.5;

    initialPhotos.forEach((group) => {
      for (let i = 0; i < group.quantity; i++) {
        if (currentX + itemWidth > A4_WIDTH_CM - 1) {
          currentX = 1;
          currentY += itemHeight + spacing;
        }
        photos.push({
          id: `${group.photoId}-${i}`,
          photoId: group.photoId,
          url: group.url,
          x: currentX,
          y: currentY,
          width: itemWidth,
          height: itemHeight
        });
        currentX += itemWidth + spacing;
      }
    });
    setSheetPhotos(photos);
  }, [initialPhotos]);

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    const startX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const startY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const photo = sheetPhotos.find(p => p.id === id);
    if (!photo) return;

    const initialX = photo.x;
    const initialY = photo.y;
    setActiveId(id);

    const onMove = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const currentY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;
      const dx = (currentX - startX) / CM_TO_VIEWPORT;
      const dy = (currentY - startY) / CM_TO_VIEWPORT;

      setSheetPhotos(prev => prev.map(p => 
        p.id === id ? { 
          ...p, 
          x: Math.max(0, Math.min(A4_WIDTH_CM - p.width, initialX + dx)),
          y: Math.max(0, Math.min(A4_HEIGHT_CM - p.height, initialY + dy))
        } : p
      ));
    };

    const onEnd = () => {
      setActiveId(null);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onEnd);
    };

    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onEnd);
  };

  const captureSheet = async () => {
    setIsExporting(true);
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const dpiScale = 118.11;
    canvas.width = A4_WIDTH_CM * dpiScale;
    canvas.height = A4_HEIGHT_CM * dpiScale;
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (const p of sheetPhotos) {
      const img = new Image();
      img.src = p.url;
      await new Promise(resolve => img.onload = resolve);
      ctx.drawImage(img, p.x * dpiScale, p.y * dpiScale, p.width * dpiScale, p.height * dpiScale);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 1;
      ctx.strokeRect(p.x * dpiScale, p.y * dpiScale, p.width * dpiScale, p.height * dpiScale);
    }
    onExport(canvas.toDataURL('image/jpeg', 0.95));
    setIsExporting(false);
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col bg-slate-50/95 animate-in fade-in duration-500 overflow-hidden">
      {/* Header */}
      <header className="z-10 px-12 py-8 flex items-center justify-between border-b border-slate-100">
        <div className="flex flex-col">
          <h2 className="text-sm font-black tracking-widest uppercase text-slate-900">Sheet Architect</h2>
          <p className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.4em] mt-1">Manual Placement Matrix</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-all text-slate-400">
          <X size={20} />
        </button>
      </header>

      {/* Workspace */}
      <main className="flex-1 overflow-auto flex justify-center p-20 custom-scrollbar">
        <div 
          className="relative bg-white shadow-2xl border border-slate-200"
          style={{ width: `${A4_WIDTH_CM * CM_TO_VIEWPORT}px`, height: `${A4_HEIGHT_CM * CM_TO_VIEWPORT}px` }}
        >
          <div className="absolute inset-0 pointer-events-none opacity-[0.02]" style={{ 
            backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)',
            backgroundSize: `${CM_TO_VIEWPORT}px ${CM_TO_VIEWPORT}px`
          }}></div>

          {sheetPhotos.map((p) => (
            <div
              key={p.id}
              onMouseDown={(e) => handleDrag(p.id, e)}
              className={`absolute cursor-move transition-shadow duration-200 select-none ${activeId === p.id ? 'z-50 shadow-2xl scale-105' : 'z-10 shadow-sm'}`}
              style={{
                left: `${p.x * CM_TO_VIEWPORT}px`,
                top: `${p.y * CM_TO_VIEWPORT}px`,
                width: `${p.width * CM_TO_VIEWPORT}px`,
                height: `${p.height * CM_TO_VIEWPORT}px`,
              }}
            >
              <img src={p.url} alt="Passport" className="w-full h-full object-cover border border-black/10 pointer-events-none" />
              {activeId === p.id && (
                <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[7px] font-black text-slate-400 uppercase bg-white/80 px-2 py-0.5 rounded shadow-sm">
                  {p.x.toFixed(1)} / {p.y.toFixed(1)} cm
                </div>
              )}
            </div>
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="z-10 px-12 py-10 flex items-center justify-between border-t border-slate-100 bg-white/50 backdrop-blur-md">
        <div className="flex flex-col">
