import { removeBackgroundAndOptimize } from './services/geminiService';
import PhotoCard from './components/PhotoCard';
import CropModal from './components/CropModal';
import LayoutStudio from './components/LayoutStudio';

const App: React.FC = () => {
  const [photos, setPhotos] = useState<ProcessedPhoto[]>([]);
  const [showLayoutStudio, setShowLayoutStudio] = useState(false);
  const [croppingPhotoId, setCroppingPhotoId] = useState<string | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    const newPhotos: ProcessedPhoto[] = files.map(file => ({
      id: Math.random().toString(36).substring(7),
      originalName: file.name,
      originalUrl: URL.createObjectURL(file),
      processedUrl: null,
      status: 'idle',
      quantity: 8 
    }));
    setPhotos(prev => [...prev, ...newPhotos]);
    if (photos.length === 0 && newPhotos.length > 0) setCroppingPhotoId(newPhotos[0].id);
    e.target.value = '';
  };

  const handleCropComplete = async (croppedDataUrl: string, customPrompt?: string) => {
    if (!croppingPhotoId) return;
    const id = croppingPhotoId;
    setCroppingPhotoId(null);
    setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'processing', originalUrl: croppedDataUrl } : p));
    try {
      const processedUrl = await removeBackgroundAndOptimize(croppedDataUrl.split(',')[1], 'image/jpeg', customPrompt);
      setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'ready', processedUrl } : p));
      setPhotos(current => {
        const nextIdle = current.find(p => p.status === 'idle');
        if (nextIdle) setCroppingPhotoId(nextIdle.id);
        return current;
      });
    } catch (err) {
      setPhotos(prev => prev.map(p => p.id === id ? { ...p, status: 'error', error: 'AI Error' } : p));
    }
  };

  const totalToPrint = useMemo(() => photos.reduce((acc, curr) => acc + (curr.status === 'ready' ? curr.quantity : 0), 0), [photos]);
  const readyPhotosData = useMemo(() => photos.filter(p => p.status === 'ready' && p.processedUrl).map(p => ({ url: p.processedUrl!, quantity: p.quantity, photoId: p.id })), [photos]);

  return (
    <div className="flex h-screen overflow-hidden p-6 gap-6">
      {/* Sidebar - Inspired by AURA */}
      <nav className="w-64 glass-dark rounded-[2.5rem] flex flex-col p-8 flex-shrink-0 border border-white/5">
        <div className="flex items-center gap-3 mb-16">
          <div className="w-8 h-8 accent-gradient rounded-lg flex items-center justify-center text-white">
            <Sparkles size={18} fill="currentColor" />
          </div>
          <span className="text-xl font-black tracking-tighter text-white">VIPUL</span>
        </div>

        <div className="space-y-8 flex-1">
          <div className="space-y-4">
            <button className="flex items-center gap-4 text-teal-400 font-bold text-sm w-full"><Home size={18} /> Home</button>
            <button className="flex items-center gap-4 text-slate-400 hover:text-white transition-colors font-bold text-sm w-full"><Library size={18} /> Library</button>
            <button className="flex items-center gap-4 text-slate-400 hover:text-white transition-colors font-bold text-sm w-full"><Users size={18} /> Clients</button>
          </div>
          <div className="pt-8 border-t border-white/5">
            <button onClick={() => setShowLayoutStudio(true)} className="flex items-center gap-4 text-slate-400 hover:text-white transition-colors font-bold text-sm w-full">
              <Printer size={18} /> Layout Studio
            </button>
          </div>
        </div>

        <div className="mt-auto space-y-4">
           <button className="flex items-center gap-4 text-slate-400 hover:text-white transition-colors font-bold text-sm w-full"><Settings size={18} /> Settings</button>
        </div>
      </nav>

      {/* Main Panel */}
      <main className="flex-1 glass-dark rounded-[2.5rem] overflow-hidden flex flex-col border border-white/5">
        <header className="px-12 py-10 flex items-center justify-between border-b border-white/5">
          <div>
            <div className="flex items-center gap-2 mb-2">
              <span className="bg-teal-400/10 text-teal-400 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest border border-teal-400/20">Studio Mode</span>
            </div>
            <h2 className="text-4xl font-black tracking-tighter text-white">Workshop</h2>
          </div>
          <label className="cursor-pointer accent-gradient text-white px-8 py-4 rounded-full font-black text-xs uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-transform flex items-center gap-2">
            <Upload size={16} /> Upload RAW
            <input type="file" multiple accept="image/*" onChange={handleFileUpload} className="hidden" />
          </label>
        </header>

        <div className="flex-1 overflow-y-auto p-12 custom-scrollbar">
          {photos.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-50">
              <Upload size={64} className="mb-6 text-slate-500" />
              <p className="text-xl font-medium text-slate-400">Empty Workspace</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {photos.map(photo => (
                <PhotoCard 
                  key={photo.id}
                  photo={photo}
                  onUpdateQuantity={(id, qty) => setPhotos(prev => prev.map(p => p.id === id ? { ...p, quantity: qty } : p))}
                  onRemove={(id) => setPhotos(prev => prev.filter(p => p.id !== id))}
                  onProcess={() => setCroppingPhotoId(photo.id)}
                />
              ))}
            </div>
          )}
        </div>

        <footer className="px-12 py-6 border-t border-white/5 flex items-center justify-between bg-black/20">
          <div className="flex gap-10">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Queue Status</span>
              <span className="text-sm font-bold text-teal-400">{totalToPrint} Total Copies</span>
            </div>
          </div>
          <div className="text-[10px] font-black text-slate-600 uppercase tracking-[0.5em] italic">VIPUL PRO SYSTEM</div>
        </footer>
      </main>

      {croppingPhotoId && photos.find(p => p.id === croppingPhotoId) && (
        <CropModal 
          imageUrl={photos.find(p => p.id === croppingPhotoId)!.originalUrl}
          onCancel={() => setCroppingPhotoId(null)}
          onConfirm={handleCropComplete}
        />
      )}

      {showLayoutStudio && <LayoutStudio initialPhotos={readyPhotosData} onClose={() => setShowLayoutStudio(false)} onExport={(u) => window.open(u)} />}
