import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Check, Maximize, RotateCcw, Move, Sun, Contrast, Sliders, Wand2, ArrowRight, ArrowLeft } from 'lucide-react';

interface Rect { x: number; y: number; width: number; height: number; }
interface Point { x: number; y: number; }
interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const imgRef = useRef<HTMLImageElement>(null);
  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });
  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [aiPrompt, setAiPrompt] = useState('');

  // Real functional curves state
  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });

  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'curve' | null>(null);
  const [activePointIdx, setActivePointIdx] = useState<number | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });
    setCrop({ x: width * 0.1, y: height * 0.1, width: width * 0.8, height: height * 0.8 });
  };

  // Spline-like linear interpolation for the curve
  const getCurveValue = (points: Point[], x: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    if (x <= sorted[0].x) return sorted[0].y;
    if (x >= sorted[sorted.length - 1].x) return sorted[sorted.length - 1].y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i]; const p2 = sorted[i+1];
      if (x >= p1.x && x <= p2.x) {
        return p1.y + (x - p1.x) * (p2.y - p1.y) / (p2.x - p1.x);
      }
    }
    return x;
  };

  const generateTableValues = (chan: Channel) => {
    const master = curves.rgb;
    const specific = curves[chan];
    const vals = [];
    for (let i = 0; i < 256; i++) {
      const v = getCurveValue(specific, getCurveValue(master, i));
      vals.push((Math.max(0, Math.min(255, v)) / 255).toFixed(3));
    }
    return vals.join(' ');
  };

  const tableR = useMemo(() => generateTableValues('r'), [curves]);
  const tableG = useMemo(() => generateTableValues('g'), [curves]);
  const tableB = useMemo(() => generateTableValues('b'), [curves]);

  const handleMouseDown = (e: React.MouseEvent, type: any, pIdx?: number) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
    if (pIdx !== undefined) setActivePointIdx(pIdx);
  };

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType || !imgRef.current) return;
    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;

    if (dragType === 'curve' && activePointIdx !== null) {
      const rect = document.getElementById('curves-grid')!.getBoundingClientRect();
      const nx = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const ny = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));
      setCurves(prev => {
        const pts = [...prev[activeChannel]];
        if (activePointIdx === 0) pts[0] = { x: 0, y: ny };
        else if (activePointIdx === pts.length - 1) pts[pts.length - 1] = { x: 255, y: ny };
        else pts[activePointIdx] = { x: nx, y: ny };
        return { ...prev, [activeChannel]: pts.sort((a,b) => a.x - b.x) };
      });
      return;
    }

    const { width: w, height: h } = imgDisplaySize;
    let nc = { ...startCrop };
    if (dragType === 'move') {
      nc.x = Math.max(0, Math.min(w - startCrop.width, startCrop.x + dx));
      nc.y = Math.max(0, Math.min(h - startCrop.height, startCrop.y + dy));
    } else if (dragType === 'se') {
      nc.width = Math.max(40, Math.min(w - startCrop.x, startCrop.width + dx));
      nc.height = Math.max(40, Math.min(h - startCrop.y, startCrop.height + dy));
    } else if (dragType === 'nw') {
      const moveX = Math.min(dx, startCrop.width - 40);
      const moveY = Math.min(dy, startCrop.height - 40);
      nc.x = Math.max(0, startCrop.x + moveX);
      nc.y = Math.max(0, startCrop.y + moveY);
      nc.width = startCrop.width - (nc.x - startCrop.x);
      nc.height = startCrop.height - (nc.y - startCrop.y);
    }
    setCrop(nc);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize, activePointIdx, activeChannel]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', () => setIsDragging(false));
    }
    return () => { window.removeEventListener('mousemove', onMouseMove); };
  }, [isDragging, onMouseMove]);

  const addPoint = (e: React.MouseEvent) => {
    if (dragType === 'curve') return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);
    setCurves(prev => ({ ...prev, [activeChannel]: [...prev[activeChannel], {x, y}].sort((a,b) => a.x - b.x) }));
  };

  const handleConfirm = async () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;
    canvas.width = crop.width * scaleX; canvas.height = crop.height * scaleY;
    ctx.filter = `url(#pro-grading-filter)`;
    ctx.drawImage(imgRef.current, crop.x*scaleX, crop.y*scaleY, crop.width*scaleX, crop.height*scaleY, 0, 0, canvas.width, canvas.height);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md p-8 animate-in fade-in duration-300">
      <svg width="0" height="0" className="absolute"><filter id="pro-grading-filter"><feComponentTransfer><feFuncR type="table" tableValues={tableR} /><feFuncG type="table" tableValues={tableG} /><feFuncB type="table" tableValues={tableB} /></feComponentTransfer></filter></svg>

      <div className="bg-[#1c1f23] w-full max-w-7xl h-[85vh] rounded-[3rem] overflow-hidden flex flex-col border border-white/5 shadow-2xl">
        <div className="px-12 py-8 border-b border-white/5 flex items-center justify-between">
          <div><h3 className="text-xl font-black text-white uppercase tracking-tighter">Color Grading</h3><p className="text-[10px] text-teal-400 font-black tracking-widest uppercase mt-1">Professional Suite</p></div>
          <button onClick={onCancel} className="p-3 hover:bg-white/5 rounded-full text-slate-400 transition-colors"><X size={24} /></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          <div className="flex-1 relative bg-black/40 flex items-center justify-center p-12 overflow-hidden select-none">
            <div className="relative inline-block border border-white/5 shadow-2xl">
              <img ref={imgRef} src={imageUrl} onLoad={handleImageLoad} style={{ filter: `url(#pro-grading-filter)` }} className="max-h-[50vh] rounded-sm" draggable={false} />
              <div style={{ left: crop.x, top: crop.y, width: crop.width, height: crop.height }} className="absolute border-2 border-white cursor-move shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]" onMouseDown={e => handleMouseDown(e, 'move')}>
                <div onMouseDown={e => handleMouseDown(e, 'nw')} className="absolute -top-2 -left-2 w-4 h-4 bg-teal-400 border-2 border-white rounded-full cursor-nw-resize"></div>
                <div onMouseDown={e => handleMouseDown(e, 'se')} className="absolute -bottom-2 -right-2 w-4 h-4 bg-teal-400 border-2 border-white rounded-full cursor-se-resize"></div>
              </div>
            </div>
          </div>

          <div className="w-96 border-l border-white/5 flex flex-col p-10 space-y-8 bg-black/10 overflow-y-auto custom-scrollbar">
            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">AI Mastering Prompt</label>
              <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Change clothing to blue..." className="w-full h-24 bg-white/5 border border-white/10 rounded-2xl p-4 text-xs text-white focus:outline-none focus:border-teal-400 transition-all resize-none" />
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Curves / {activeChannel.toUpperCase()}</label>
                <div className="flex gap-1">
                  {CHANNELS.map(ch => (
                    <button key={ch} onClick={() => setActiveChannel(ch)} className={`px-3 py-1 text-[9px] font-black rounded-full transition-all border ${activeChannel === ch ? 'bg-teal-400 text-black border-teal-400' : 'text-slate-500 border-white/10 hover:border-white/20'}`}>{ch.toUpperCase()}</button>
                  ))}
                </div>
              </div>

              <div id="curves-grid" className="relative aspect-square w-full bg-[#1c1f23] rounded-2xl border border-white/10 overflow-hidden cursor-crosshair" onClick={addPoint}>
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-10">
                  {[...Array(16)].map((_, i) => <div key={i} className="border border-white"></div>)}
                </div>
                <div className="absolute bottom-0 left-0 w-full h-2 bg-gradient-to-r from-black to-white opacity-20"></div>
                <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <polyline points={curves[activeChannel].map(p => `${(p.x/255)*100}%, ${(1-p.y/255)*100}%`).join(' ')} fill="none" stroke={activeChannel === 'rgb' ? '#2dd4bf' : activeChannel === 'r' ? '#ef4444' : activeChannel === 'g' ? '#22c55e' : '#3b82f6'} strokeWidth="2" />
                  {curves[activeChannel].map((p, i) => (
                    <circle key={i} cx={`${(p.x/255)*100}%`} cy={`${(1-p.y/255)*100}%`} r="6" fill="#1c1f23" stroke="white" strokeWidth="2" className="cursor-pointer pointer-events-auto hover:scale-125 transition-transform" onMouseDown={e => handleMouseDown(e, 'curve', i)} onDoubleClick={() => i !== 0 && i !== curves[activeChannel].length-1 && setCurves(pr => ({...pr, [activeChannel]: pr[activeChannel].filter((_, idx)=>idx!==i)}))} />
                  ))}
                </svg>
              </div>
              <p className="text-[8px] font-bold text-slate-600 uppercase text-center">Double-click point to delete</p>
            </div>
          </div>
        </div>

        <div className="px-12 py-8 bg-black/20 border-t border-white/5 flex items-center justify-between">
           <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest max-w-xs">Master curves to achieve perfect skin tones and lighting balance.</p>
           <div className="flex gap-4">
             <button onClick={onCancel} className="px-10 py-4 text-slate-400 font-black text-xs uppercase tracking-widest hover:text-white transition-colors">Discard</button>
             <button onClick={handleConfirm} className="accent-gradient text-white px-12 py-4 rounded-full font-black text-xs uppercase tracking-widest shadow-2xl transition-transform hover:scale-105 active:scale-95">Finalize Prep</button>
           </div>
        </div>
      </div>
    </div>
  );
};
