import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Sliders, Spline, Wand2, Sun, Contrast, Droplet, ArrowLeft, ArrowRight } from 'lucide-react';

interface Point { x: number; y: number; }
interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const imgRef = useRef<HTMLImageElement>(null);
  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [aiPrompt, setAiPrompt] = useState('');
  const [adjustments, setAdjustments] = useState({ brightness: 100, contrast: 100, saturation: 100 });

  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });

  const [activePointIdx, setActivePointIdx] = useState<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  const getCurveValue = (points: Point[], x: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    if (x <= sorted[0].x) return sorted[0].y;
    if (x >= sorted[sorted.length - 1].x) return sorted[sorted.length - 1].y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i]; const p2 = sorted[i+1];
      if (x >= p1.x && x <= p2.x) return p1.y + (x - p1.x) * (p2.y - p1.y) / (p2.x - p1.x);
    }
    return x;
  };

  const generateTable = (chan: Channel) => {
    const master = curves.rgb;
    const spec = curves[chan];
    const vals = [];
    for (let i = 0; i < 256; i++) {
      const v = getCurveValue(spec, getCurveValue(master, i));
      vals.push((Math.max(0, Math.min(255, v)) / 255).toFixed(3));
    }
    return vals.join(' ');
  };

  const tableR = useMemo(() => generateTable('r'), [curves]);
  const tableG = useMemo(() => generateTable('g'), [curves]);
  const tableB = useMemo(() => generateTable('b'), [curves]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || activePointIdx === null) return;
    const rect = document.getElementById('curves-area')!.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));

    setCurves(prev => {
      const pts = [...prev[activeChannel]];
      if (activePointIdx === 0) pts[0] = { x: 0, y };
      else if (activePointIdx === pts.length - 1) pts[pts.length - 1] = { x: 255, y };
      else pts[activePointIdx] = { x, y };
      return { ...prev, [activeChannel]: pts.sort((a,b) => a.x - b.x) };
    });
  }, [isDragging, activePointIdx, activeChannel]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', () => { setIsDragging(false); setActivePointIdx(null); });
    }
    return () => window.removeEventListener('mousemove', onMouseMove);
  }, [isDragging, onMouseMove]);

  const addPoint = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);
    setCurves(prev => ({ ...prev, [activeChannel]: [...prev[activeChannel], {x, y}].sort((a,b) => a.x - b.x) }));
  };

  const curveDataPath = useMemo(() => {
    const pts = curves[activeChannel];
    const d = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${(p.x / 255) * 100} ${(1 - p.y / 255) * 100}`).join(' ');
    // Add path for area fill
    const fill = `${d} L 100 100 L 0 100 Z`;
    return { d, fill };
  }, [curves, activeChannel]);

  const filterString = `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#studio-pro-filter)`;

  const handleConfirm = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const naturalW = imgRef.current!.naturalWidth;
    const naturalH = imgRef.current!.naturalHeight;
    canvas.width = naturalW; canvas.height = naturalH;
    ctx.filter = filterString;
    ctx.drawImage(imgRef.current!, 0, 0);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-8 animate-in fade-in zoom-in duration-300">
      <svg width="0" height="0" className="absolute">
        <filter id="studio-pro-filter">
          <feComponentTransfer>
            <feFuncR type="table" tableValues={tableR} />
            <feFuncG type="table" tableValues={tableG} />
            <feFuncB type="table" tableValues={tableB} />
          </feComponentTransfer>
        </filter>
        <linearGradient id="area-gradient" x1="0" x2="0" y1="0" y2="1">
           <stop offset="0%" stopColor="var(--accent)" stopOpacity="0.2" />
           <stop offset="100%" stopColor="var(--accent)" stopOpacity="0" />
        </linearGradient>
      </svg>

      <div className="bg-[var(--bg-main)] w-full max-w-7xl h-[90vh] rounded-[3rem] overflow-hidden flex flex-col border border-[var(--border)] shadow-2xl">
        <div className="px-12 py-8 border-b border-[var(--border)] flex items-center justify-between">
          <div><h3 className="text-xl font-black uppercase tracking-tighter">Visual Grading</h3><p className="text-[10px] text-[#2dd4bf] font-black tracking-widest uppercase mt-1">Professional Master Suite</p></div>
          <button onClick={onCancel} className="p-3 hover:bg-black/5 rounded-full transition-colors"><X size={24} /></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Visual Workspace */}
          <div className="flex-1 relative bg-black/5 flex items-center justify-center p-12 overflow-hidden select-none">
             <img ref={imgRef} src={imageUrl} style={{ filter: filterString }} className="max-h-[60vh] rounded-2xl shadow-2xl transition-all duration-300" draggable={false} />
          </div>

          {/* Immersive Controls Sidebar */}
          <div className="w-[420px] border-l border-[var(--border)] flex flex-col p-10 space-y-10 overflow-y-auto custom-scrollbar">

            <div className="space-y-4">
              <label className="text-[10px] font-black text-[var(--text-secondary)] uppercase tracking-widest flex items-center gap-2"><Wand2 size={12}/> AI Edit Command</label>
              <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Sharp white suit, portrait lighting..." className="w-full h-24 glass border border-[var(--border)] rounded-2xl p-4 text-xs focus:outline-none focus:border-[#2dd4bf] transition-all resize-none font-medium" />
            </div>

            {/* Curves Tool - Redesigned */}
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-[10px] font-black text-[var(--text-secondary)] uppercase tracking-widest flex items-center gap-2"><Spline size={12}/> Channel: <span className="text-[#2dd4bf]">{activeChannel.toUpperCase()}</span></label>
                <div className="flex gap-1">
                   {CHANNELS.map(ch => (
                     <button key={ch} onClick={() => setActiveChannel(ch)} className={`px-3 py-1 text-[9px] font-black rounded-lg border transition-all ${activeChannel === ch ? 'bg-[#2dd4bf] text-white border-[#2dd4bf]' : 'text-[var(--text-secondary)] border-[var(--border)] hover:border-[#2dd4bf55]'}`}>{ch.toUpperCase()}</button>
                   ))}
                </div>
              </div>

              <div id="curves-area" className="relative aspect-square w-full glass rounded-3xl border border-[var(--border)] overflow-hidden" onClick={addPoint}>
                {/* Diagonal Baseline */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-10">
                   <line x1="0" y1="100%" x2="100%" y2="0" stroke="var(--text-primary)" strokeWidth="1" />
                </svg>

                {/* Visual Grid */}
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-[0.03]">
                  {[...Array(16)].map((_, i) => <div key={i} className="border border-white"></div>)}
                </div>

                <svg viewBox="0 0 100 100" className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  {/* Area Effect Fill */}
                  <path d={curveDataPath.fill} fill="url(#area-gradient)" />
                  {/* Curve Path */}
                  <path d={curveDataPath.d} fill="none" stroke="var(--accent)" strokeWidth="2" strokeLinecap="round" className="curve-path shadow-lg" />
                  {/* Interactive Points */}
