                <div key={adj.key} className="space-y-4">
                  <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                    <span className="flex items-center gap-2 text-[var(--text-secondary)]">{adj.icon} {adj.label}</span>
                    <span className="text-[#2dd4bf]">{adjustments[adj.key as keyof typeof adjustments]}%</span>
                  </div>
                  <input type="range" min="50" max="150" value={adjustments[adj.key as keyof typeof adjustments]} onChange={e => setAdjustments(prev => ({...prev, [adj.key]: parseInt(e.target.value)}))} />
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="px-12 py-8 bg-black/5 border-t border-[var(--border)] flex items-center justify-between">
           <div className="flex items-center gap-10">
              <div className="flex items-center gap-3">
                 <div className="w-1 h-1 rounded-full bg-[#2dd4bf]"></div>
                 <span className="text-[10px] font-black tracking-widest uppercase opacity-50">Master Tone Calibration</span>
              </div>
           </div>
           <div className="flex gap-6">
             <button onClick={onCancel} className="px-10 py-4 text-xs font-black uppercase tracking-widest opacity-50 hover:opacity-100 transition-all">Discard</button>
             <button onClick={handleConfirm} className="bg-[#2dd4bf] text-white px-12 py-4 rounded-full font-black text-xs uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-transform">Finalize & Save</button>
           </div>
        </div>
      </div>
    </div>
  );
};
