        </div>

        <button onClick={() => setActiveTab('settings')} className={`p-3 rounded-xl transition-all ${activeTab === 'settings' ? 'bg-[#2dd4bf22] text-[#2dd4bf]' : 'text-slate-400 hover:text-white'}`}><Settings size={24} /></button>
      </nav>

      {/* Main Workspace */}
      <main className="flex-1 glass rounded-[2.5rem] overflow-hidden flex flex-col border border-[var(--border)]">
        {activeTab === 'home' && (
          <>
            <header className="px-12 py-10 flex items-center justify-between border-b border-[var(--border)]">
              <div>
