              )}
            </div>
          </>
        )}

        {activeTab === 'library' && (
          <div className="p-12 flex-1 overflow-y-auto custom-scrollbar">
            <h2 className="text-4xl font-black tracking-tighter text-[var(--text-primary)] mb-10">Studio Library</h2>
            {library.length === 0 ? (
              <p className="opacity-30 text-sm uppercase tracking-widest text-[var(--text-primary)]">Library Empty</p>
