              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6">
                {library.map((p, i) => (
                  <div key={i} className="group relative aspect-[3/4] rounded-2xl overflow-hidden bg-black/20 border border-[var(--border)]">
