                      <button onClick={() => {setPhotos([p, ...photos]); setActiveTab('home');}} className="p-4 bg-white text-black rounded-full shadow-xl hover:scale-110 transition-transform" title="Re-Edit"><RotateCcw size={20} /></button>
                      <button onClick={() => setLibrary(prev => prev.filter((_, idx) => idx !== i))} className="p-4 bg-red-500 text-white rounded-full shadow-xl hover:scale-110 transition-transform"><Trash2 size={20} /></button>
                    </div>
                  </div>
                ))}
