        )}

        {activeTab === 'settings' && (
          <div className="p-12 max-w-2xl mx-auto w-full">
            <h2 className="text-4xl font-black tracking-tighter mb-10 text-[var(--text-primary)]">System Config</h2>
            <div className="p-8 glass rounded-[2.5rem] border border-[var(--border)] flex items-center justify-between">
              <div>
                <h4 className="font-bold text-xl text-[var(--text-primary)]">Environment Theme</h4>
                <p className="text-sm text-[var(--text-secondary)] mt-1">Adjust workspace lighting.</p>
              </div>
              <div className="flex bg-black/10 rounded-full p-1 border border-[var(--border)]">
                <button onClick={() => setTheme('light')} className={`px-6 py-3 rounded-full flex items-center gap-2 text-[10px] font-black uppercase transition-all ${theme === 'light' ? 'bg-white text-black shadow-lg' : 'text-slate-500'}`}><Sun size={14}/> Light</button>
                <button onClick={() => setTheme('dark')} className={`px-6 py-3 rounded-full flex items-center gap-2 text-[10px] font-black uppercase transition-all ${theme === 'dark' ? 'bg-[#2dd4bf] text-white shadow-lg' : 'text-slate-500'}`}><Moon size={14}/> Dark</button>
              </div>
