import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Sliders, Spline, Wand2, Sun, Contrast, Droplet } from 'lucide-react';

interface Point { x: number; y: number; }
interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const imgRef = useRef<HTMLImageElement>(null);
  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [aiPrompt, setAiPrompt] = useState('');
  const [adjustments, setAdjustments] = useState({ brightness: 100, contrast: 100, saturation: 100 });

  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });

  const [activePointIdx, setActivePointIdx] = useState<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  const getCurveValue = (points: Point[], x: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    if (x <= sorted[0].x) return sorted[0].y;
    if (x >= sorted[sorted.length - 1].x) return sorted[sorted.length - 1].y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i]; const p2 = sorted[i+1];
      if (x >= p1.x && x <= p2.x) return p1.y + (x - p1.x) * (p2.y - p1.y) / (p2.x - p1.x);
    }
    return x;
  };

  const generateTable = (chan: Channel) => {
    const master = curves.rgb;
    const spec = curves[chan];
    const vals = [];
    for (let i = 0; i < 256; i++) {
      const v = getCurveValue(spec, getCurveValue(master, i));
      vals.push((Math.max(0, Math.min(255, v)) / 255).toFixed(3));
    }
    return vals.join(' ');
  };

  const tableR = useMemo(() => generateTable('r'), [curves]);
  const tableG = useMemo(() => generateTable('g'), [curves]);
  const tableB = useMemo(() => generateTable('b'), [curves]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || activePointIdx === null) return;
    const rect = document.getElementById('curves-area')!.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));

    setCurves(prev => {
      const pts = [...prev[activeChannel]];
      if (activePointIdx === 0) pts[0] = { x: 0, y };
      else if (activePointIdx === pts.length - 1) pts[pts.length - 1] = { x: 255, y };
      else pts[activePointIdx] = { x, y };
      return { ...prev, [activeChannel]: pts.sort((a,b) => a.x - b.x) };
    });
  }, [isDragging, activePointIdx, activeChannel]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', () => { setIsDragging(false); setActivePointIdx(null); });
    }
    return () => window.removeEventListener('mousemove', onMouseMove);
  }, [isDragging, onMouseMove]);

  const addPoint = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);
    setCurves(prev => {
      // Don't add if already dragging a point or too close to existing
      const pts = [...prev[activeChannel]];
      const exists = pts.some(p => Math.abs(p.x - x) < 10);
      if (exists) return prev;
      return { ...prev, [activeChannel]: [...pts, {x, y}].sort((a,b) => a.x - b.x) };
    });
  };

  const curveDataPath = useMemo(() => {
    const pts = curves[activeChannel];
    const path = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${(p.x / 255) * 100} ${(1 - p.y / 255) * 100}`).join(' ');
    const fill = `${path} L 100 100 L 0 100 Z`;
    return { path, fill };
  }, [curves, activeChannel]);

  const filterString = `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#pro-grading-filter)`;

  const handleConfirm = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = imgRef.current!.naturalWidth;
    canvas.height = imgRef.current!.naturalHeight;
    ctx.filter = filterString;
    ctx.drawImage(imgRef.current!, 0, 0);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-8 bg-black/90 backdrop-blur-3xl animate-in fade-in duration-500">
      <svg width="0" height="0" className="absolute">
        <filter id="pro-grading-filter">
          <feComponentTransfer>
            <feFuncR type="table" tableValues={tableR} />
            <feFuncG type="table" tableValues={tableG} />
            <feFuncB type="table" tableValues={tableB} />
          </feComponentTransfer>
        </filter>
        <linearGradient id="curve-fill-grad" x1="0" x2="0" y1="0" y2="1">
           <stop offset="0%" stopColor="#2dd4bf" stopOpacity="0.3" />
           <stop offset="100%" stopColor="#2dd4bf" stopOpacity="0" />
        </linearGradient>
      </svg>

      <div className="bg-[var(--bg-main)] w-full max-w-7xl h-[92vh] rounded-[3.5rem] overflow-hidden flex flex-col border border-[var(--border)] shadow-[0_40px_100px_rgba(0,0,0,0.6)]">
        <div className="px-12 py-10 border-b border-[var(--border)] flex items-center justify-between">
          <div><h3 className="text-2xl font-black text-[var(--text-primary)] uppercase tracking-tighter">Grading Suite</h3><p className="text-[10px] text-[#2dd4bf] font-black tracking-widest uppercase mt-2">Professional Mastering Engine</p></div>
          <button onClick={onCancel} className="p-4 hover:bg-white/5 rounded-full transition-all text-[var(--text-secondary)] hover:text-white"><X size={28} /></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          <div className="flex-1 relative bg-black/10 flex items-center justify-center p-16 select-none overflow-hidden">
             <div className="relative group">
               <img ref={imgRef} src={imageUrl} style={{ filter: filterString }} className="max-h-[60vh] rounded-3xl shadow-2xl ring-1 ring-white/10 transition-all duration-700 group-hover:scale-105" draggable={false} />
             </div>
          </div>

          <div className="w-[450px] border-l border-[var(--border)] flex flex-col p-12 space-y-12 bg-black/5 overflow-y-auto custom-scrollbar">

            <div className="space-y-4">
              <label className="text-[11px] font-black text-[var(--text-secondary)] uppercase tracking-widest flex items-center gap-2"><Wand2 size={14}/> Studio Command</label>
              <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="Describe mastering details..." className="w-full h-24 bg-black/20 border border-[var(--border)] rounded-2xl p-5 text-sm text-[var(--text-primary)] focus:outline-none focus:border-[#2dd4bf] transition-all resize-none placeholder:opacity-30" />
            </div>

            <div className="space-y-8">
              <div className="flex items-center justify-between">
                <label className="text-[11px] font-black text-[var(--text-secondary)] uppercase tracking-widest">Curves / <span className="text-[#2dd4bf]">{activeChannel.toUpperCase()}</span></label>
                <div className="flex gap-1.5 p-1 bg-black/20 rounded-xl border border-[var(--border)]">
                   {CHANNELS.map(ch => (
                     <button key={ch} onClick={() => setActiveChannel(ch)} className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${activeChannel === ch ? 'bg-[#2dd4bf] text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}>{ch.toUpperCase()}</button>
                   ))}
                </div>
              </div>

              <div id="curves-area" className="relative aspect-square w-full bg-[#0a0c10] rounded-[2rem] border border-[var(--border)] overflow-hidden shadow-inner cursor-crosshair" onClick={addPoint}>
                {/* Baseline Diagonal */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-20">
                   <line x1="0" y1="100%" x2="100%" y2="0" stroke="white" strokeWidth="2" strokeDasharray="4 4" />
                </svg>
                {/* Grid Lines */}
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-[0.05]">
                  {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-white"></div>)}
                </div>

                <svg viewBox="0 0 100 100" className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <path d={curveDataPath.fill} fill="url(#curve-fill-grad)" />
                  <path d={curveDataPath.path} fill="none" stroke="#2dd4bf" strokeWidth="3" strokeLinecap="round" />
                  {curves[activeChannel].map((p, i) => (
                    <circle key={i} cx={`${(p.x/255)*100}`} cy={`${(1-p.y/255)*100}`} r="2" fill="#0a0c10" stroke="white" strokeWidth="1" className="cursor-pointer pointer-events-auto hover:scale-150 transition-transform" onMouseDown={e => { e.stopPropagation(); setIsDragging(true); setActivePointIdx(i); }} onDoubleClick={() => i !== 0 && i !== curves[activeChannel].length-1 && setCurves(pr => ({...pr, [activeChannel]: pr[activeChannel].filter((_, idx)=>idx!==i)}))} />
                  ))}
                </svg>
              </div>
            </div>

            <div className="space-y-10">
              {[
                { label: 'Brightness', key: 'brightness', icon: <Sun size={16}/> },
                { label: 'Contrast', key: 'contrast', icon: <Contrast size={16}/> },
                { label: 'Saturation', key: 'saturation', icon: <Droplet size={16}/> },
              ].map(adj => (
                <div key={adj.key} className="space-y-4">
                  <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.2em] text-[var(--text-secondary)]">
                    <span className="flex items-center gap-2">{adj.icon} {adj.label}</span>
                    <span className="text-[#2dd4bf] text-xs">{adjustments[adj.key as keyof typeof adjustments]}%</span>
                  </div>
                  <input type="range" min="50" max="150" value={adjustments[adj.key as keyof typeof adjustments]} onChange={e => setAdjustments(prev => ({...prev, [adj.key]: parseInt(e.target.value)}))} />
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="px-12 py-10 border-t border-[var(--border)] flex items-center justify-between bg-black/5">
           <p className="text-[11px] text-[var(--text-secondary)] font-bold uppercase tracking-widest max-w-xs leading-relaxed">Ensure lighting and framing adhere to international passport standards.</p>
           <div className="flex gap-6">
             <button onClick={onCancel} className="px-10 py-5 text-xs font-black uppercase tracking-widest text-[var(--text-secondary)] hover:text-white transition-all">Discard</button>
             <button onClick={handleConfirm} className="bg-[#2dd4bf] text-white px-14 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all">Apply Studio Tuning</button>
           </div>
        </div>
      </div>
    </div>
  );
};
export default CropModal;

import React, { useState, useEffect } from 'react';
import { X, Download, Move, RotateCcw } from 'lucide-react';
import { SheetPhoto, A4_WIDTH_CM, A4_HEIGHT_CM, CM_TO_VIEWPORT, PASSPORT_SETTINGS } from '../types';

interface LayoutStudioProps {
  initialPhotos: { url: string; quantity: number; photoId: string }[];
  onClose: () => void;
  onExport: (dataUrl: string) => void;
}

const LayoutStudio: React.FC<LayoutStudioProps> = ({ initialPhotos, onClose, onExport }) => {
  const [sheetPhotos, setSheetPhotos] = useState<SheetPhoto[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const photos: SheetPhoto[] = [];
    let currentX = 1.0;
    let currentY = 1.0;
    const itemWidth = PASSPORT_SETTINGS.photoWidthCm;
    const itemHeight = PASSPORT_SETTINGS.photoHeightCm;
    const spacing = PASSPORT_SETTINGS.spacingMm / 10;
    const maxHorizontal = PASSPORT_SETTINGS.maxHorizontal; // Strictly 6

    let countInRow = 0;
    initialPhotos.forEach((group) => {
      for (let i = 0; i < group.quantity; i++) {
        if (countInRow >= maxHorizontal) {
          countInRow = 0;
          currentX = 1.0;
          currentY += itemHeight + spacing;
        }
        photos.push({
          id: `${group.photoId}-${i}`,
          photoId: group.photoId,
          url: group.url,
          x: currentX,
          y: currentY,
          width: itemWidth,
          height: itemHeight
        });
        currentX += itemWidth + spacing;
        countInRow++;
      }
    });
    setSheetPhotos(photos);
  }, [initialPhotos]);

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    const startX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const startY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const photo = sheetPhotos.find(p => p.id === id);
    if (!photo) return;
    const initialX = photo.x;
    const initialY = photo.y;
    setActiveId(id);
    const onMove = (mv: MouseEvent | TouchEvent) => {
      const cx = 'touches' in mv ? mv.touches[0].clientX : (mv as MouseEvent).clientX;
      const cy = 'touches' in mv ? mv.touches[0].clientY : (mv as MouseEvent).clientY;
      const dx = (cx - startX) / CM_TO_VIEWPORT;
      const dy = (cy - startY) / CM_TO_VIEWPORT;
      setSheetPhotos(prev => prev.map(p => p.id === id ? { 
        ...p, x: Math.max(0, Math.min(A4_WIDTH_CM - p.width, initialX + dx)),
        y: Math.max(0, Math.min(A4_HEIGHT_CM - p.height, initialY + dy))
      } : p));
    };
    const onEnd = () => { setActiveId(null); window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onEnd); };
    window.addEventListener('mousemove', onMove); window.addEventListener('mouseup', onEnd);
  };

  const captureSheet = async () => {
    setIsExporting(true);
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const dpi = 300;
    const cmToPx = dpi / 2.54;
    canvas.width = A4_WIDTH_CM * cmToPx; canvas.height = A4_HEIGHT_CM * cmToPx;
    ctx.fillStyle = '#FFFFFF'; ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (const p of sheetPhotos) {
      const img = new Image(); img.src = p.url;
      await new Promise(res => img.onload = res);
      ctx.drawImage(img, p.x * cmToPx, p.y * cmToPx, p.width * cmToPx, p.height * cmToPx);
      ctx.strokeStyle = '#000000'; ctx.lineWidth = 1;
      ctx.strokeRect(p.x * cmToPx, p.y * cmToPx, p.width * cmToPx, p.height * cmToPx);
    }
    onExport(canvas.toDataURL('image/jpeg', 0.98));
    setIsExporting(false);
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col bg-black/90 backdrop-blur-3xl animate-in fade-in duration-500 overflow-hidden">
      <header className="px-12 py-10 flex items-center justify-between border-b border-white/5 bg-black/20">
        <div><h2 className="text-2xl font-black text-white uppercase tracking-tighter">Architectural View</h2><p className="text-[10px] text-[#2dd4bf] font-black tracking-widest uppercase mt-2">A4 Precision Matrix</p></div>
        <button onClick={onClose} className="p-4 hover:bg-white/5 rounded-full text-white/50 transition-all"><X size={28} /></button>
      </header>
      <main className="flex-1 overflow-auto flex justify-center p-24 custom-scrollbar bg-black/50">
        <div className="relative bg-white shadow-[0_40px_100px_rgba(0,0,0,0.8)] border border-white/10" style={{ width: `${A4_WIDTH_CM * CM_TO_VIEWPORT}px`, height: `${A4_HEIGHT_CM * CM_TO_VIEWPORT}px` }}>
          <div className="absolute inset-0 pointer-events-none opacity-[0.03]" style={{ backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: `${CM_TO_VIEWPORT}px ${CM_TO_VIEWPORT}px` }}></div>
          {sheetPhotos.map((p) => (
            <div key={p.id} onMouseDown={(e) => handleDrag(p.id, e)} className={`absolute cursor-move transition-transform duration-200 select-none ${activeId === p.id ? 'z-50 scale-105 shadow-2xl ring-2 ring-[#2dd4bf]' : 'z-10 shadow-sm border border-black/5'}`} style={{ left: `${p.x * CM_TO_VIEWPORT}px`, top: `${p.y * CM_TO_VIEWPORT}px`, width: `${p.width * CM_TO_VIEWPORT}px`, height: `${p.height * CM_TO_VIEWPORT}px` }}>
              <img src={p.url} className="w-full h-full object-cover pointer-events-none" />
              {activeId === p.id && <div className="absolute -top-10 left-1/2 -translate-x-1/2 text-[9px] font-black text-[#2dd4bf] uppercase bg-black/80 px-4 py-1.5 rounded-full border border-[#2dd4bf55] backdrop-blur-md">{p.x.toFixed(1)} / {p.y.toFixed(1)} CM</div>}
            </div>
          ))}
        </div>
      </main>
      <footer className="px-12 py-10 flex items-center justify-between border-t border-white/5 bg-black/30 backdrop-blur-xl">
        <div className="flex gap-16">
          <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Grid Config</span><span className="text-sm font-bold text-white uppercase tracking-widest">Fixed 6 Horizontal Max</span></div>
          <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Total Assets</span><span className="text-sm font-bold text-white uppercase tracking-widest">{sheetPhotos.length} Items</span></div>
        </div>
        <div className="flex gap-6">
          <button onClick={onClose} className="px-10 py-5 text-xs font-black uppercase tracking-widest text-slate-400 hover:text-white transition-all">Discard</button>
          <button onClick={captureSheet} disabled={isExporting} className="bg-[#2dd4bf] text-white px-14 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
            {isExporting ? <RotateCcw className="animate-spin" size={18}/> : <Download size={18} />}
            {isExporting ? 'Processing' : 'Generate Production Sheet'}
          </button>
        </div>
      </footer>
    </div>
  );
};
export default LayoutStudio;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Sliders, Spline, Wand2, Sun, Contrast, Droplet, Maximize } from 'lucide-react';

interface Rect { x: number; y: number; width: number; height: number; }
interface Point { x: number; y: number; }
interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const imgRef = useRef<HTMLImageElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Crop State
  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });

  // Adjustment States
  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [aiPrompt, setAiPrompt] = useState('');
  const [adjustments, setAdjustments] = useState({ brightness: 100, contrast: 100, saturation: 100 });
  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });

  // Dragging States
  const [activePointIdx, setActivePointIdx] = useState<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'curve' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });
    // Default crop: centered 80%
    setCrop({ x: width * 0.1, y: height * 0.1, width: width * 0.8, height: height * 0.8 });
  };

  const getCurveValue = (points: Point[], x: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    if (x <= sorted[0].x) return sorted[0].y;
    if (x >= sorted[sorted.length - 1].x) return sorted[sorted.length - 1].y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i]; const p2 = sorted[i+1];
      if (x >= p1.x && x <= p2.x) return p1.y + (x - p1.x) * (p2.y - p1.y) / (p2.x - p1.x);
    }
    return x;
  };

  const generateTable = (chan: Channel) => {
    const master = curves.rgb;
    const spec = curves[chan];
    const vals = [];
    for (let i = 0; i < 256; i++) {
      const v = getCurveValue(spec, getCurveValue(master, i));
      vals.push((Math.max(0, Math.min(255, v)) / 255).toFixed(3));
    }
    return vals.join(' ');
  };

  const tableR = useMemo(() => generateTable('r'), [curves]);
  const tableG = useMemo(() => generateTable('g'), [curves]);
  const tableB = useMemo(() => generateTable('b'), [curves]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType) return;
    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;

    if (dragType === 'curve' && activePointIdx !== null) {
      const rect = document.getElementById('curves-area')!.getBoundingClientRect();
      const nx = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const ny = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));
      setCurves(prev => {
        const pts = [...prev[activeChannel]];
        if (activePointIdx === 0) pts[0] = { x: 0, y: ny };
        else if (activePointIdx === pts.length - 1) pts[pts.length - 1] = { x: 255, y: ny };
        else pts[activePointIdx] = { x: nx, y: ny };
        return { ...prev, [activeChannel]: pts.sort((a,b) => a.x - b.x) };
      });
      return;
    }

    const { width: imgW, height: imgH } = imgDisplaySize;
    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'se':
        newCrop.width = Math.max(40, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(40, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'nw':
        const moveX = Math.min(dx, startCrop.width - 40);
        const moveY = Math.min(dy, startCrop.height - 40);
        newCrop.x = Math.max(0, startCrop.x + moveX);
        newCrop.y = Math.max(0, startCrop.y + moveY);
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'ne':
        const moveY_ne = Math.min(dy, startCrop.height - 40);
        newCrop.y = Math.max(0, startCrop.y + moveY_ne);
        newCrop.width = Math.max(40, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        const moveX_sw = Math.min(dx, startCrop.width - 40);
        newCrop.x = Math.max(0, startCrop.x + moveX_sw);
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(40, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
    }
    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize, activePointIdx, activeChannel]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', () => { setIsDragging(false); setDragType(null); setActivePointIdx(null); });
    }
    return () => window.removeEventListener('mousemove', onMouseMove);
  }, [isDragging, onMouseMove]);

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType, pIdx?: number) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
    if (pIdx !== undefined) setActivePointIdx(pIdx);
  };

  const addCurvePoint = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);
    setCurves(prev => {
      const pts = [...prev[activeChannel]];
      const exists = pts.some(p => Math.abs(p.x - x) < 10);
      if (exists) return prev;
      return { ...prev, [activeChannel]: [...pts, {x, y}].sort((a,b) => a.x - b.x) };
    });
  };

  const curveDataPath = useMemo(() => {
    const pts = curves[activeChannel];
    const path = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${(p.x / 255) * 100} ${(1 - p.y / 255) * 100}`).join(' ');
    const fill = `${path} L 100 100 L 0 100 Z`;
    return { path, fill };
  }, [curves, activeChannel]);

  const filterString = `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#pro-grading-filter)`;

  const handleConfirm = async () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;

    canvas.width = crop.width * scaleX;
    canvas.height = crop.height * scaleY;

    ctx.filter = filterString;
    ctx.drawImage(
      imgRef.current, 
      crop.x * scaleX, 
      crop.y * scaleY, 
      crop.width * scaleX, 
      crop.height * scaleY, 
      0, 0, 
      canvas.width, 
      canvas.height
    );

    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-8 bg-black/95 backdrop-blur-3xl animate-in fade-in duration-500">
      <svg width="0" height="0" className="absolute">
        <filter id="pro-grading-filter">
          <feComponentTransfer>
            <feFuncR type="table" tableValues={tableR} />
            <feFuncG type="table" tableValues={tableG} />
            <feFuncB type="table" tableValues={tableB} />
          </feComponentTransfer>
        </filter>
        <linearGradient id="curve-fill-grad" x1="0" x2="0" y1="0" y2="1">
           <stop offset="0%" stopColor="#2dd4bf" stopOpacity="0.3" />
           <stop offset="100%" stopColor="#2dd4bf" stopOpacity="0" />
        </linearGradient>
      </svg>

      <div className="bg-[var(--bg-main)] w-full max-w-7xl h-[92vh] rounded-[3.5rem] overflow-hidden flex flex-col border border-[var(--border)] shadow-[0_40px_100px_rgba(0,0,0,0.8)]">
        <div className="px-12 py-8 border-b border-[var(--border)] flex items-center justify-between bg-black/10">
          <div>
            <h3 className="text-2xl font-black text-[var(--text-primary)] uppercase tracking-tighter">Asset Mastering</h3>
            <p className="text-[10px] text-[#2dd4bf] font-black tracking-widest uppercase mt-2">Crop & Grade Workspace</p>
          </div>
          <button onClick={onCancel} className="p-4 hover:bg-white/5 rounded-full transition-all text-[var(--text-secondary)] hover:text-white"><X size={28} /></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Main Workspace (Image & Crop Selection) */}
          <div className="flex-1 relative bg-black/20 flex items-center justify-center p-16 select-none overflow-hidden" ref={containerRef}>
             <div className="relative inline-block border border-white/5 shadow-2xl">
               <img 
                 ref={imgRef} 
                 src={imageUrl} 
                 onLoad={handleImageLoad}
                 style={{ filter: filterString }} 
                 className="max-h-[60vh] rounded-xl ring-1 ring-white/10" 
                 draggable={false} 
               />

               {/* Crop Overlay */}
               <div 
                 style={{ left: crop.x, top: crop.y, width: crop.width, height: crop.height }} 
                 className="absolute border-2 border-[#2dd4bf] cursor-move shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]" 
                 onMouseDown={e => handleMouseDown(e, 'move')}
               >
                 {/* Selection Handles */}
                 <div onMouseDown={e => handleMouseDown(e, 'nw')} className="absolute -top-2.5 -left-2.5 w-5 h-5 bg-[#2dd4bf] border-2 border-white rounded-full cursor-nw-resize shadow-lg"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'ne')} className="absolute -top-2.5 -right-2.5 w-5 h-5 bg-[#2dd4bf] border-2 border-white rounded-full cursor-ne-resize shadow-lg"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'sw')} className="absolute -bottom-2.5 -left-2.5 w-5 h-5 bg-[#2dd4bf] border-2 border-white rounded-full cursor-sw-resize shadow-lg"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'se')} className="absolute -bottom-2.5 -right-2.5 w-5 h-5 bg-[#2dd4bf] border-2 border-white rounded-full cursor-se-resize shadow-lg"></div>

                 {/* Guide Lines */}
                 <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-20">
                    {[...Array(9)].map((_, i) => <div key={i} className="border-[0.5px] border-white/50"></div>)}
                 </div>
               </div>
             </div>
          </div>

          {/* Right Sidebar (Grading Controls) */}
          <div className="w-[480px] border-l border-[var(--border)] flex flex-col p-12 space-y-12 bg-black/10 overflow-y-auto custom-scrollbar">

            <div className="space-y-4">
              <label className="text-[11px] font-black text-[var(--text-secondary)] uppercase tracking-widest flex items-center gap-2"><Wand2 size={14}/> Studio Instruction</label>
              <textarea 
                value={aiPrompt} 
                onChange={e => setAiPrompt(e.target.value)} 
                placeholder="e.g. Formal attire, adjust lighting for professional look..." 
                className="w-full h-24 bg-black/30 border border-[var(--border)] rounded-2xl p-5 text-sm text-[var(--text-primary)] focus:outline-none focus:border-[#2dd4bf] transition-all resize-none placeholder:opacity-20 font-medium" 
              />
            </div>

            <div className="space-y-8">
              <div className="flex items-center justify-between">
                <label className="text-[11px] font-black text-[var(--text-secondary)] uppercase tracking-widest">Grading Curves / <span className="text-[#2dd4bf]">{activeChannel.toUpperCase()}</span></label>
                <div className="flex gap-1.5 p-1 bg-black/30 rounded-xl border border-[var(--border)]">
                   {CHANNELS.map(ch => (
                     <button key={ch} onClick={() => setActiveChannel(ch)} className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${activeChannel === ch ? 'bg-[#2dd4bf] text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}>{ch.toUpperCase()}</button>
                   ))}
                </div>
              </div>

              <div id="curves-area" className="relative aspect-square w-full bg-[#0a0c10] rounded-[2.5rem] border border-[var(--border)] overflow-hidden shadow-2xl cursor-crosshair" onClick={addCurvePoint}>
                {/* Diagonal Baseline */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-20">
                   <line x1="0" y1="100%" x2="100%" y2="0" stroke="white" strokeWidth="2" strokeDasharray="5 5" />
                </svg>
                {/* Grid Lines */}
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-[0.05]">
                  {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-white"></div>)}
                </div>

                <svg viewBox="0 0 100 100" className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <path d={curveDataPath.fill} fill="url(#curve-fill-grad)" />
                  <path d={curveDataPath.path} fill="none" stroke="#2dd4bf" strokeWidth="3" strokeLinecap="round" />
                  {curves[activeChannel].map((p, i) => (
                    <circle 
                      key={i} 
                      cx={`${(p.x/255)*100}`} 
                      cy={`${(1-p.y/255)*100}`} 
                      r="2.5" 
                      fill="#0a0c10" 
                      stroke="white" 
                      strokeWidth="1.5" 
                      className="cursor-pointer pointer-events-auto hover:scale-150 transition-transform" 
                      onMouseDown={e => { e.stopPropagation(); handleMouseDown(e, 'curve', i); }} 
                      onDoubleClick={() => i !== 0 && i !== curves[activeChannel].length-1 && setCurves(pr => ({...pr, [activeChannel]: pr[activeChannel].filter((_, idx)=>idx!==i)}))} 
                    />
                  ))}
                </svg>
              </div>
            </div>

            <div className="space-y-10">
              {[
                { label: 'Brightness', key: 'brightness', icon: <Sun size={18}/> },
                { label: 'Contrast', key: 'contrast', icon: <Contrast size={18}/> },
                { label: 'Saturation', key: 'saturation', icon: <Droplet size={18}/> },
              ].map(adj => (
                <div key={adj.key} className="space-y-4">
                  <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.2em] text-[var(--text-secondary)]">
                    <span className="flex items-center gap-2">{adj.icon} {adj.label}</span>
                    <span className="text-[#2dd4bf] text-sm">{adjustments[adj.key as keyof typeof adjustments]}%</span>
                  </div>
                  <input 
                    type="range" 
                    min="50" max="150" 
                    value={adjustments[adj.key as keyof typeof adjustments]} 
                    onChange={e => setAdjustments(prev => ({...prev, [adj.key]: parseInt(e.target.value)}))} 
                  />
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="px-12 py-10 border-t border-[var(--border)] flex items-center justify-between bg-black/20 backdrop-blur-md">
           <p className="text-xs text-[var(--text-secondary)] font-medium uppercase tracking-widest max-w-xs leading-relaxed">Ensure framing and tones adhere to high-end studio standards before finalize.</p>
           <div className="flex gap-8">
             <button onClick={onCancel} className="px-10 py-5 text-xs font-black uppercase tracking-widest text-[var(--text-secondary)] hover:text-white transition-all">Discard</button>
             <button onClick={handleConfirm} className="bg-[#2dd4bf] text-white px-16 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-[0_15px_30px_rgba(45,212,191,0.4)] hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
               <Maximize size={18} /> Finish Prep
             </button>
           </div>
        </div>
      </div>
    </div>
  );
};
export default CropModal;

