                        <button onClick={() => setLibrary(prev => prev.filter((_, idx) => idx !== i))} className="p-4 bg-red-500 text-white rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all"><Trash2 size={22} /></button>
                      </div>
