import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Wand2, Sun, Contrast, Droplet, Maximize } from 'lucide-react';

interface Rect { x: number; y: number; width: number; height: number; }
interface Point { x: number; y: number; }
interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const imgRef = useRef<HTMLImageElement>(null);

  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });

  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [aiPrompt, setAiPrompt] = useState('');
  const [adjustments, setAdjustments] = useState({ brightness: 100, contrast: 100, saturation: 100 });
  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });

  const [activePointIdx, setActivePointIdx] = useState<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'curve' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });
    setCrop({ x: width * 0.1, y: height * 0.1, width: width * 0.8, height: height * 0.8 });
  };

  const getCurveValue = (points: Point[], x: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    if (x <= sorted[0].x) return sorted[0].y;
    if (x >= sorted[sorted.length - 1].x) return sorted[sorted.length - 1].y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i]; const p2 = sorted[i+1];
      if (x >= p1.x && x <= p2.x) return p1.y + (x - p1.x) * (p2.y - p1.y) / (p2.x - p1.x);
    }
    return x;
  };

  const generateTable = (chan: Channel) => {
    const master = curves.rgb;
    const spec = curves[chan];
    const vals = [];
    for (let i = 0; i < 256; i++) {
      const v = getCurveValue(spec, getCurveValue(master, i));
      vals.push((Math.max(0, Math.min(255, v)) / 255).toFixed(3));
    }
    return vals.join(' ');
  };

  const tableR = useMemo(() => generateTable('r'), [curves]);
  const tableG = useMemo(() => generateTable('g'), [curves]);
  const tableB = useMemo(() => generateTable('b'), [curves]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType) return;
    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;

    if (dragType === 'curve' && activePointIdx !== null) {
      const rect = document.getElementById('curves-area')!.getBoundingClientRect();
      const nx = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const ny = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));
      setCurves(prev => {
        const pts = [...prev[activeChannel]];
        if (activePointIdx === 0) pts[0] = { x: 0, y: ny };
        else if (activePointIdx === pts.length - 1) pts[pts.length - 1] = { x: 255, y: ny };
        else pts[activePointIdx] = { x: nx, y: ny };
        return { ...prev, [activeChannel]: pts.sort((a,b) => a.x - b.x) };
      });
      return;
    }

    const { width: imgW, height: imgH } = imgDisplaySize;
    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'se':
        newCrop.width = Math.max(40, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(40, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'nw':
        const moveX = Math.min(dx, startCrop.width - 40);
        const moveY = Math.min(dy, startCrop.height - 40);
        newCrop.x = Math.max(0, startCrop.x + moveX);
        newCrop.y = Math.max(0, startCrop.y + moveY);
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'ne':
        const moveY_ne = Math.min(dy, startCrop.height - 40);
        newCrop.y = Math.max(0, startCrop.y + moveY_ne);
        newCrop.width = Math.max(40, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        const moveX_sw = Math.min(dx, startCrop.width - 40);
        newCrop.x = Math.max(0, startCrop.x + moveX_sw);
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(40, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
    }
    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize, activePointIdx, activeChannel]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', () => { setIsDragging(false); setDragType(null); setActivePointIdx(null); });
    }
    return () => window.removeEventListener('mousemove', onMouseMove);
  }, [isDragging, onMouseMove]);

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType, pIdx?: number) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
    if (pIdx !== undefined) setActivePointIdx(pIdx);
  };

  const addCurvePoint = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);
    setCurves(prev => {
      const pts = [...prev[activeChannel]];
      const exists = pts.some(p => Math.abs(p.x - x) < 10);
      if (exists) return prev;
      return { ...prev, [activeChannel]: [...pts, {x, y}].sort((a,b) => a.x - b.x) };
    });
  };

  const curveDataPath = useMemo(() => {
    const pts = curves[activeChannel];
    const path = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${(p.x / 255) * 100} ${(1 - p.y / 255) * 100}`).join(' ');
    const fill = `${path} L 100 100 L 0 100 Z`;
    return { path, fill };
  }, [curves, activeChannel]);

  const filterString = `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#pro-grading-filter)`;

  const handleConfirm = async () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;
    canvas.width = crop.width * scaleX;
    canvas.height = crop.height * scaleY;
    ctx.filter = filterString;
    ctx.drawImage(imgRef.current, crop.x * scaleX, crop.y * scaleY, crop.width * scaleX, crop.height * scaleY, 0, 0, canvas.width, canvas.height);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-12 bg-black/95 backdrop-blur-3xl animate-in fade-in zoom-in-95 duration-500">
      <svg width="0" height="0" className="absolute">
        <filter id="pro-grading-filter">
          <feComponentTransfer>
            <feFuncR type="table" tableValues={tableR} />
            <feFuncG type="table" tableValues={tableG} />
            <feFuncB type="table" tableValues={tableB} />
          </feComponentTransfer>
        </filter>
        <linearGradient id="curve-fill-grad" x1="0" x2="0" y1="0" y2="1">
           <stop offset="0%" stopColor="#2dd4bf" stopOpacity="0.4" />
           <stop offset="100%" stopColor="#2dd4bf" stopOpacity="0" />
        </linearGradient>
      </svg>

      <div className="bg-[var(--bg-main)] w-full max-w-7xl h-full rounded-[4rem] overflow-hidden flex flex-col border border-white/5 shadow-[0_40px_120px_rgba(0,0,0,0.8)]">
        <div className="px-14 py-10 border-b border-white/5 flex items-center justify-between bg-black/10">
          <div>
            <h3 className="text-3xl font-black text-[var(--text-primary)] uppercase tracking-tighter">Asset Mastering</h3>
            <p className="text-[10px] text-[#2dd4bf] font-black tracking-[0.4em] uppercase mt-2">Professional Grading Environment</p>
          </div>
          <button onClick={onCancel} className="p-4 hover:bg-white/5 rounded-full transition-all text-slate-500 hover:text-white"><X size={32} /></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Main Visual Workspace */}
          <div className="flex-1 relative bg-black/20 flex items-center justify-center p-20 select-none overflow-hidden">
             <div className="relative inline-block border border-white/5 shadow-2xl">
               <img ref={imgRef} src={imageUrl} onLoad={handleImageLoad} style={{ filter: filterString }} className="max-h-[55vh] rounded-2xl ring-1 ring-white/10" draggable={false} />

               {/* Symmetrical Crop Overlay */}
               <div style={{ left: crop.x, top: crop.y, width: crop.width, height: crop.height }} className="absolute border-2 border-[#2dd4bf] cursor-move shadow-[0_0_0_9999px_rgba(0,0,0,0.7)]" onMouseDown={e => handleMouseDown(e, 'move')}>
                 <div onMouseDown={e => handleMouseDown(e, 'nw')} className="absolute -top-3 -left-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-nw-resize shadow-2xl transition-transform hover:scale-125"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'ne')} className="absolute -top-3 -right-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-ne-resize shadow-2xl transition-transform hover:scale-125"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'sw')} className="absolute -bottom-3 -left-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-sw-resize shadow-2xl transition-transform hover:scale-125"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'se')} className="absolute -bottom-3 -right-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-se-resize shadow-2xl transition-transform hover:scale-125"></div>
                 <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-30">
                    {[...Array(9)].map((_, i) => <div key={i} className="border-[0.5px] border-white/60"></div>)}
                 </div>
               </div>
             </div>
          </div>

          {/* Immersive Control Panel */}
          <div className="w-[450px] border-l border-white/5 flex flex-col p-14 space-y-12 bg-black/10 overflow-y-auto custom-scrollbar">
            <div className="space-y-4">
              <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Wand2 size={14}/> Studio Instructions</label>
              <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="Describe mastering details..." className="w-full h-24 bg-black/40 border border-white/10 rounded-3xl p-6 text-sm text-[var(--text-primary)] focus:outline-none focus:border-[#2dd4bf] transition-all resize-none font-medium placeholder:opacity-20" />
            </div>

            <div className="space-y-8">
              <div className="flex items-center justify-between">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Master Curves / <span className="text-[#2dd4bf]">{activeChannel.toUpperCase()}</span></label>
                <div className="flex gap-1.5 p-1 bg-black/40 rounded-2xl border border-white/5">
                   {CHANNELS.map(ch => (
                     <button key={ch} onClick={() => setActiveChannel(ch)} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${activeChannel === ch ? 'bg-[#2dd4bf] text-white shadow-xl shadow-[#2dd4bf44]' : 'text-slate-500 hover:text-white'}`}>{ch.toUpperCase()}</button>
                   ))}
                </div>
              </div>

              <div id="curves-area" className="relative aspect-square w-full bg-[#08090b] rounded-[3rem] border border-white/10 overflow-hidden shadow-inner cursor-crosshair" onClick={addCurvePoint}>
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-20">
                   <line x1="0" y1="100%" x2="100%" y2="0" stroke="white" strokeWidth="2" strokeDasharray="6 6" />
                </svg>
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-[0.05]">
                  {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-white"></div>)}
                </div>
                <svg viewBox="0 0 100 100" className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <path d={curveDataPath.fill} fill="url(#curve-fill-grad)" className="transition-all duration-300" />
                  <path d={curveDataPath.path} fill="none" stroke="#2dd4bf" strokeWidth="3" strokeLinecap="round" className="curve-path" />
                  {curves[activeChannel].map((p, i) => (
                    <circle key={i} cx={`${(p.x/255)*100}`} cy={`${(1-p.y/255)*100}`} r="2.5" fill="#08090b" stroke="white" strokeWidth="1.5" className="cursor-pointer pointer-events-auto hover:scale-150 transition-transform" onMouseDown={e => { e.stopPropagation(); handleMouseDown(e, 'curve', i); }} onDoubleClick={() => i !== 0 && i !== curves[activeChannel].length-1 && setCurves(pr => ({...pr, [activeChannel]: pr[activeChannel].filter((_, idx)=>idx!==i)}))} />
                  ))}
                </svg>
              </div>
            </div>

            <div className="space-y-12 pb-10">
              {[
                { label: 'Brightness', key: 'brightness', icon: <Sun size={18}/> },
                { label: 'Contrast', key: 'contrast', icon: <Contrast size={18}/> },
                { label: 'Saturation', key: 'saturation', icon: <Droplet size={18}/> },
              ].map(adj => (
                <div key={adj.key} className="space-y-4">
                  <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">
                    <span className="flex items-center gap-3">{adj.icon} {adj.label}</span>
                    <span className="text-[#2dd4bf] text-xs">{adjustments[adj.key as keyof typeof adjustments]}%</span>
                  </div>
                  <input type="range" min="50" max="150" value={adjustments[adj.key as keyof typeof adjustments]} onChange={e => setAdjustments(prev => ({...prev, [adj.key]: parseInt(e.target.value)}))} />
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Ultra-Thin Immersive Footer */}
        <div className="px-14 py-8 border-t border-white/5 flex items-center justify-between bg-black/20 backdrop-blur-2xl">
           <div className="flex gap-8">
             <button onClick={onCancel} className="px-10 py-5 text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all duration-300">Discard Changes</button>
           </div>
           <button onClick={handleConfirm} className="bg-[#2dd4bf] text-white px-20 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-[0_15px_40px_rgba(45,212,191,0.5)] hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
             <Maximize size={18} /> Finish Prep
           </button>
        </div>
      </div>
    </div>
  );
};
export default CropModal;

import React, { useState, useEffect } from 'react';
import { X, Download, RotateCcw } from 'lucide-react';
import { SheetPhoto, A4_WIDTH_CM, A4_HEIGHT_CM, CM_TO_VIEWPORT, PASSPORT_SETTINGS } from '../types';

interface LayoutStudioProps {
  initialPhotos: { url: string; quantity: number; photoId: string }[];
  onClose: () => void;
  onExport: (dataUrl: string) => void;
}

const LayoutStudio: React.FC<LayoutStudioProps> = ({ initialPhotos, onClose, onExport }) => {
  const [sheetPhotos, setSheetPhotos] = useState<SheetPhoto[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const photos: SheetPhoto[] = [];
    const itemWidth = PASSPORT_SETTINGS.photoWidthCm;
    const itemHeight = PASSPORT_SETTINGS.photoHeightCm;
    const spacing = PASSPORT_SETTINGS.spacingMm / 10;
    const maxHorizontal = PASSPORT_SETTINGS.maxHorizontal; // Strictly 6

    // Calculate grid width to center horizontally
    const totalGridWidth = (maxHorizontal * itemWidth) + ((maxHorizontal - 1) * spacing);
    const startX = (A4_WIDTH_CM - totalGridWidth) / 2;
    const startY = 1.5; // Top margin

    let currentX = startX;
    let currentY = startY;
    let countInRow = 0;

    initialPhotos.forEach((group) => {
      for (let i = 0; i < group.quantity; i++) {
        if (countInRow >= maxHorizontal) {
          countInRow = 0;
          currentX = startX;
          currentY += itemHeight + spacing;
        }

        // Prevent adding if it goes beyond A4 height
        if (currentY + itemHeight < A4_HEIGHT_CM - 1) {
          photos.push({
            id: `${group.photoId}-${i}`,
            photoId: group.photoId,
            url: group.url,
            x: currentX,
            y: currentY,
            width: itemWidth,
            height: itemHeight
          });
        }

        currentX += itemWidth + spacing;
        countInRow++;
      }
    });
    setSheetPhotos(photos);
  }, [initialPhotos]);

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    const startX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const startY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const photo = sheetPhotos.find(p => p.id === id);
    if (!photo) return;
    const initialX = photo.x;
    const initialY = photo.y;
    setActiveId(id);
    const onMove = (mv: MouseEvent | TouchEvent) => {
      const cx = 'touches' in mv ? mv.touches[0].clientX : (mv as MouseEvent).clientX;
      const cy = 'touches' in mv ? mv.touches[0].clientY : (mv as MouseEvent).clientY;
      const dx = (cx - startX) / CM_TO_VIEWPORT;
      const dy = (cy - startY) / CM_TO_VIEWPORT;
      setSheetPhotos(prev => prev.map(p => p.id === id ? { 
        ...p, x: Math.max(0, Math.min(A4_WIDTH_CM - p.width, initialX + dx)),
        y: Math.max(0, Math.min(A4_HEIGHT_CM - p.height, initialY + dy))
      } : p));
    };
    const onEnd = () => { setActiveId(null); window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onEnd); };
    window.addEventListener('mousemove', onMove); window.addEventListener('mouseup', onEnd);
  };

  const captureSheet = async () => {
    setIsExporting(true);
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const dpi = 300;
    const cmToPx = dpi / 2.54;
    canvas.width = A4_WIDTH_CM * cmToPx;
    canvas.height = A4_HEIGHT_CM * cmToPx;
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (const p of sheetPhotos) {
      const img = new Image(); img.src = p.url;
      await new Promise(res => img.onload = res);
      ctx.drawImage(img, p.x * cmToPx, p.y * cmToPx, p.width * cmToPx, p.height * cmToPx);
      ctx.strokeStyle = '#000000'; ctx.lineWidth = 1;
      ctx.strokeRect(p.x * cmToPx, p.y * cmToPx, p.width * cmToPx, p.height * cmToPx);
    }
    onExport(canvas.toDataURL('image/jpeg', 0.98));
    setIsExporting(false);
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col bg-black/95 backdrop-blur-3xl animate-in fade-in duration-700 overflow-hidden">
      <header className="px-14 py-10 flex items-center justify-between border-b border-white/5 bg-black/20">
        <div>
          <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Production Matrix</h2>
          <p className="text-[10px] text-[#2dd4bf] font-black tracking-[0.5em] uppercase mt-3">High Precision A4 Symmetric Sheet</p>
        </div>
        <button onClick={onClose} className="p-4 hover:bg-white/5 rounded-full text-white/40 transition-all"><X size={32} /></button>
      </header>

      <main className="flex-1 overflow-auto flex justify-center p-24 custom-scrollbar bg-black/40">
        <div className="relative bg-white shadow-[0_60px_150px_rgba(0,0,0,1)] border border-white/5" style={{ width: `${A4_WIDTH_CM * CM_TO_VIEWPORT}px`, height: `${A4_HEIGHT_CM * CM_TO_VIEWPORT}px` }}>
          <div className="absolute inset-0 pointer-events-none opacity-[0.02]" style={{ backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: `${CM_TO_VIEWPORT/2}px ${CM_TO_VIEWPORT/2}px` }}></div>
          {sheetPhotos.map((p) => (
            <div key={p.id} onMouseDown={(e) => handleDrag(p.id, e)} className={`absolute cursor-move transition-transform duration-300 select-none ${activeId === p.id ? 'z-50 scale-110 shadow-[0_20px_50px_rgba(0,0,0,0.5)] ring-2 ring-[#2dd4bf]' : 'z-10 border border-black/5'}`} style={{ left: `${p.x * CM_TO_VIEWPORT}px`, top: `${p.y * CM_TO_VIEWPORT}px`, width: `${p.width * CM_TO_VIEWPORT}px`, height: `${p.height * CM_TO_VIEWPORT}px` }}>
              <img src={p.url} className="w-full h-full object-cover pointer-events-none" />
              {activeId === p.id && <div className="absolute -top-12 left-1/2 -translate-x-1/2 text-[9px] font-black text-[#2dd4bf] uppercase bg-black/90 px-5 py-2 rounded-full border border-[#2dd4bf44] backdrop-blur-xl shadow-2xl animate-in fade-in slide-in-from-bottom-2">{p.x.toFixed(2)} / {p.y.toFixed(2)} cm</div>}
            </div>
          ))}
        </div>
      </main>

      <footer className="px-14 py-12 flex items-center justify-between border-t border-white/5 bg-black/30 backdrop-blur-3xl">
        <div className="flex gap-20">
          <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">A4 Calibration</span><span className="text-sm font-bold text-white uppercase tracking-[0.2em]">Centered Grid (Max 6x)</span></div>
          <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Asset Count</span><span className="text-sm font-bold text-white uppercase tracking-[0.2em]">{sheetPhotos.length} Production Units</span></div>
        </div>
        <div className="flex gap-8">
          <button onClick={onClose} className="px-12 py-5 text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all">Cancel Sheet</button>
          <button onClick={captureSheet} disabled={isExporting} className="bg-[#2dd4bf] text-white px-16 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-[0_15px_40px_rgba(45,212,191,0.5)] hover:scale-105 active:scale-95 transition-all flex items-center gap-4">
            {isExporting ? <RotateCcw className="animate-spin" size={20}/> : <Download size={20} />}
            {isExporting ? 'Generating...' : 'Export High-Res Sheet'}
          </button>
        </div>
      </footer>
    </div>
  );
};
export default LayoutStudio;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { X, Wand2, Sun, Contrast, Droplet, Maximize } from 'lucide-react';

interface Rect { x: number; y: number; width: number; height: number; }
interface Point { x: number; y: number; }
interface CropModalProps {
  imageUrl: string;
  onConfirm: (croppedUrl: string, customPrompt?: string) => void;
  onCancel: () => void;
}

const CHANNELS = ['rgb', 'r', 'g', 'b'] as const;
type Channel = typeof CHANNELS[number];

const CropModal: React.FC<CropModalProps> = ({ imageUrl, onConfirm, onCancel }) => {
  const imgRef = useRef<HTMLImageElement>(null);

  const [crop, setCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });
  const [imgDisplaySize, setImgDisplaySize] = useState({ width: 0, height: 0 });

  const [activeChannel, setActiveChannel] = useState<Channel>('rgb');
  const [aiPrompt, setAiPrompt] = useState('');
  const [adjustments, setAdjustments] = useState({ brightness: 100, contrast: 100, saturation: 100 });
  const [curves, setCurves] = useState<Record<Channel, Point[]>>({
    rgb: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    r: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    g: [{ x: 0, y: 0 }, { x: 255, y: 255 }],
    b: [{ x: 0, y: 0 }, { x: 255, y: 255 }]
  });

  const [activePointIdx, setActivePointIdx] = useState<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragType, setDragType] = useState<'move' | 'nw' | 'ne' | 'sw' | 'se' | 'curve' | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [startCrop, setStartCrop] = useState<Rect>({ x: 0, y: 0, width: 0, height: 0 });

  const handleImageLoad = () => {
    if (!imgRef.current) return;
    const { width, height } = imgRef.current;
    setImgDisplaySize({ width, height });
    setCrop({ x: width * 0.1, y: height * 0.1, width: width * 0.8, height: height * 0.8 });
  };

  const getCurveValue = (points: Point[], x: number) => {
    const sorted = [...points].sort((a, b) => a.x - b.x);
    if (x <= sorted[0].x) return sorted[0].y;
    if (x >= sorted[sorted.length - 1].x) return sorted[sorted.length - 1].y;
    for (let i = 0; i < sorted.length - 1; i++) {
      const p1 = sorted[i]; const p2 = sorted[i+1];
      if (x >= p1.x && x <= p2.x) return p1.y + (x - p1.x) * (p2.y - p1.y) / (p2.x - p1.x);
    }
    return x;
  };

  const generateTable = (chan: Channel) => {
    const master = curves.rgb;
    const spec = curves[chan];
    const vals = [];
    for (let i = 0; i < 256; i++) {
      const v = getCurveValue(spec, getCurveValue(master, i));
      vals.push((Math.max(0, Math.min(255, v)) / 255).toFixed(3));
    }
    return vals.join(' ');
  };

  const tableR = useMemo(() => generateTable('r'), [curves]);
  const tableG = useMemo(() => generateTable('g'), [curves]);
  const tableB = useMemo(() => generateTable('b'), [curves]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging || !dragType) return;
    const dx = e.clientX - startPos.x;
    const dy = e.clientY - startPos.y;

    if (dragType === 'curve' && activePointIdx !== null) {
      const rect = document.getElementById('curves-area')!.getBoundingClientRect();
      const nx = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
      const ny = Math.max(0, Math.min(255, Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255)));
      setCurves(prev => {
        const pts = [...prev[activeChannel]];
        if (activePointIdx === 0) pts[0] = { x: 0, y: ny };
        else if (activePointIdx === pts.length - 1) pts[pts.length - 1] = { x: 255, y: ny };
        else pts[activePointIdx] = { x: nx, y: ny };
        return { ...prev, [activeChannel]: pts.sort((a,b) => a.x - b.x) };
      });
      return;
    }

    const { width: imgW, height: imgH } = imgDisplaySize;
    let newCrop = { ...startCrop };

    switch (dragType) {
      case 'move':
        newCrop.x = Math.max(0, Math.min(imgW - startCrop.width, startCrop.x + dx));
        newCrop.y = Math.max(0, Math.min(imgH - startCrop.height, startCrop.y + dy));
        break;
      case 'se':
        newCrop.width = Math.max(40, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = Math.max(40, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
      case 'nw':
        const moveX = Math.min(dx, startCrop.width - 40);
        const moveY = Math.min(dy, startCrop.height - 40);
        newCrop.x = Math.max(0, startCrop.x + moveX);
        newCrop.y = Math.max(0, startCrop.y + moveY);
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'ne':
        const moveY_ne = Math.min(dy, startCrop.height - 40);
        newCrop.y = Math.max(0, startCrop.y + moveY_ne);
        newCrop.width = Math.max(40, Math.min(imgW - startCrop.x, startCrop.width + dx));
        newCrop.height = startCrop.height - (newCrop.y - startCrop.y);
        break;
      case 'sw':
        const moveX_sw = Math.min(dx, startCrop.width - 40);
        newCrop.x = Math.max(0, startCrop.x + moveX_sw);
        newCrop.width = startCrop.width - (newCrop.x - startCrop.x);
        newCrop.height = Math.max(40, Math.min(imgH - startCrop.y, startCrop.height + dy));
        break;
    }
    setCrop(newCrop);
  }, [isDragging, dragType, startPos, startCrop, imgDisplaySize, activePointIdx, activeChannel]);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', () => { setIsDragging(false); setDragType(null); setActivePointIdx(null); });
    }
    return () => window.removeEventListener('mousemove', onMouseMove);
  }, [isDragging, onMouseMove]);

  const handleMouseDown = (e: React.MouseEvent, type: typeof dragType, pIdx?: number) => {
    e.stopPropagation();
    setIsDragging(true);
    setDragType(type);
    setStartPos({ x: e.clientX, y: e.clientY });
    setStartCrop({ ...crop });
    if (pIdx !== undefined) setActivePointIdx(pIdx);
  };

  const addCurvePoint = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = Math.round(((e.clientX - rect.left) / rect.width) * 255);
    const y = Math.round(255 - ((e.clientY - rect.top) / rect.height) * 255);
    setCurves(prev => {
      const pts = [...prev[activeChannel]];
      const exists = pts.some(p => Math.abs(p.x - x) < 10);
      if (exists) return prev;
      return { ...prev, [activeChannel]: [...pts, {x, y}].sort((a,b) => a.x - b.x) };
    });
  };

  const curveDataPath = useMemo(() => {
    const pts = curves[activeChannel];
    const path = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${(p.x / 255) * 100} ${(1 - p.y / 255) * 100}`).join(' ');
    const fill = `${path} L 100 100 L 0 100 Z`;
    return { path, fill };
  }, [curves, activeChannel]);

  const filterString = `brightness(${adjustments.brightness}%) contrast(${adjustments.contrast}%) saturate(${adjustments.saturation}%) url(#pro-grading-filter)`;

  const handleConfirm = async () => {
    if (!imgRef.current) return;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const scaleX = imgRef.current.naturalWidth / imgRef.current.width;
    const scaleY = imgRef.current.naturalHeight / imgRef.current.height;
    canvas.width = crop.width * scaleX;
    canvas.height = crop.height * scaleY;
    ctx.filter = filterString;
    ctx.drawImage(imgRef.current, crop.x * scaleX, crop.y * scaleY, crop.width * scaleX, crop.height * scaleY, 0, 0, canvas.width, canvas.height);
    onConfirm(canvas.toDataURL('image/jpeg', 0.95), aiPrompt);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-10 bg-black/95 backdrop-blur-3xl animate-in fade-in zoom-in-95 duration-500">
      <svg width="0" height="0" className="absolute">
        <filter id="pro-grading-filter">
          <feComponentTransfer>
            <feFuncR type="table" tableValues={tableR} />
            <feFuncG type="table" tableValues={tableG} />
            <feFuncB type="table" tableValues={tableB} />
          </feComponentTransfer>
        </filter>
        <linearGradient id="curve-fill-grad" x1="0" x2="0" y1="0" y2="1">
           <stop offset="0%" stopColor="#2dd4bf" stopOpacity="0.5" />
           <stop offset="100%" stopColor="#2dd4bf" stopOpacity="0" />
        </linearGradient>
      </svg>

      <div className="bg-[var(--bg-main)] w-full max-w-7xl h-full rounded-[3.5rem] overflow-hidden flex flex-col border border-white/5 shadow-[0_40px_150px_rgba(0,0,0,1)]">
        <div className="px-12 py-8 border-b border-white/5 flex items-center justify-between bg-black/10">
          <div>
            <h3 className="text-2xl font-black text-[var(--text-primary)] uppercase tracking-tighter">Asset Mastering</h3>
            <p className="text-[10px] text-[#2dd4bf] font-black tracking-[0.5em] uppercase mt-1">Calibration Engine</p>
          </div>
          <button onClick={onCancel} className="p-3 hover:bg-white/5 rounded-full transition-all text-slate-500 hover:text-white"><X size={28} /></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          <div className="flex-1 relative bg-black/20 flex items-center justify-center p-16 select-none overflow-hidden">
             <div className="relative inline-block border border-white/5 shadow-2xl">
               <img ref={imgRef} src={imageUrl} onLoad={handleImageLoad} style={{ filter: filterString }} className="max-h-[50vh] rounded-2xl ring-1 ring-white/10" draggable={false} />

               <div style={{ left: crop.x, top: crop.y, width: crop.width, height: crop.height }} className="absolute border-2 border-[#2dd4bf] cursor-move shadow-[0_0_0_9999px_rgba(0,0,0,0.75)]" onMouseDown={e => handleMouseDown(e, 'move')}>
                 <div onMouseDown={e => handleMouseDown(e, 'nw')} className="absolute -top-3 -left-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-nw-resize shadow-2xl hover:scale-125 transition-transform"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'ne')} className="absolute -top-3 -right-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-ne-resize shadow-2xl hover:scale-125 transition-transform"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'sw')} className="absolute -bottom-3 -left-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-sw-resize shadow-2xl hover:scale-125 transition-transform"></div>
                 <div onMouseDown={e => handleMouseDown(e, 'se')} className="absolute -bottom-3 -right-3 w-6 h-6 bg-[#2dd4bf] border-2 border-white rounded-full cursor-se-resize shadow-2xl hover:scale-125 transition-transform"></div>
                 <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-40">
                    {[...Array(9)].map((_, i) => <div key={i} className="border-[0.5px] border-white/40"></div>)}
                 </div>
               </div>
             </div>
          </div>

          <div className="w-[420px] border-l border-white/5 flex flex-col p-12 space-y-10 bg-black/10 overflow-y-auto custom-scrollbar">
            <div className="space-y-4">
              <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Wand2 size={14}/> Studio Command</label>
              <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="Asset mastering prompt..." className="w-full h-24 bg-black/40 border border-white/10 rounded-3xl p-6 text-sm text-[var(--text-primary)] focus:outline-none focus:border-[#2dd4bf] transition-all resize-none font-medium placeholder:opacity-20" />
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Master Curves / <span className="text-[#2dd4bf]">{activeChannel.toUpperCase()}</span></label>
                <div className="flex gap-1 p-1 bg-black/40 rounded-xl border border-white/5">
                   {CHANNELS.map(ch => (
                     <button key={ch} onClick={() => setActiveChannel(ch)} className={`px-3 py-1.5 text-[10px] font-black rounded-lg transition-all ${activeChannel === ch ? 'bg-[#2dd4bf] text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}>{ch.toUpperCase()}</button>
                   ))}
                </div>
              </div>

              <div id="curves-area" className="relative aspect-square w-full bg-[#07080a] rounded-[2.5rem] border border-white/10 overflow-hidden shadow-inner cursor-crosshair" onClick={addCurvePoint}>
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-20">
                   <line x1="0" y1="100%" x2="100%" y2="0" stroke="white" strokeWidth="2" strokeDasharray="6 6" />
                </svg>
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-[0.05]">
                  {[...Array(16)].map((_, i) => <div key={i} className="border-[0.5px] border-white"></div>)}
                </div>
                <svg viewBox="0 0 100 100" className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                  <path d={curveDataPath.fill} fill="url(#curve-fill-grad)" className="transition-all duration-300" />
                  <path d={curveDataPath.path} fill="none" stroke="#2dd4bf" strokeWidth="2.5" strokeLinecap="round" className="curve-path" />
                  {curves[activeChannel].map((p, i) => (
                    <circle key={i} cx={`${(p.x/255)*100}`} cy={`${(1-p.y/255)*100}`} r="2" fill="#07080a" stroke="white" strokeWidth="1" className="cursor-pointer pointer-events-auto hover:scale-150 transition-transform" onMouseDown={e => { e.stopPropagation(); handleMouseDown(e, 'curve', i); }} onDoubleClick={() => i !== 0 && i !== curves[activeChannel].length-1 && setCurves(pr => ({...pr, [activeChannel]: pr[activeChannel].filter((_, idx)=>idx!==i)}))} />
                  ))}
                </svg>
              </div>
            </div>

            <div className="space-y-10">
              {[
                { label: 'Brightness', key: 'brightness', icon: <Sun size={18}/> },
                { label: 'Contrast', key: 'contrast', icon: <Contrast size={18}/> },
                { label: 'Saturation', key: 'saturation', icon: <Droplet size={18}/> },
              ].map(adj => (
                <div key={adj.key} className="space-y-3">
                  <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">
                    <span className="flex items-center gap-3">{adj.icon} {adj.label}</span>
                    <span className="text-[#2dd4bf] text-xs font-black">{adjustments[adj.key as keyof typeof adjustments]}%</span>
                  </div>
                  <input type="range" min="50" max="150" value={adjustments[adj.key as keyof typeof adjustments]} onChange={e => setAdjustments(prev => ({...prev, [adj.key]: parseInt(e.target.value)}))} />
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Thinner Symmetrical Footer */}
        <div className="px-12 py-6 border-t border-white/5 flex items-center justify-between bg-black/20 backdrop-blur-2xl">
           <button onClick={onCancel} className="px-8 py-4 text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all">Discard</button>
           <button onClick={handleConfirm} className="bg-[#2dd4bf] text-white px-20 py-4 rounded-full font-black text-xs uppercase tracking-widest shadow-[0_10px_30px_rgba(45,212,191,0.4)] hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
             <Maximize size={16} /> Finish Prep
           </button>
        </div>
      </div>
    </div>
  );
};
export default CropModal;

import React, { useState, useEffect } from 'react';
import { X, Download, RotateCcw } from 'lucide-react';
import { SheetPhoto, A4_WIDTH_CM, A4_HEIGHT_CM, CM_TO_VIEWPORT, PASSPORT_SETTINGS } from '../types';

interface LayoutStudioProps {
  initialPhotos: { url: string; quantity: number; photoId: string }[];
  onClose: () => void;
  onExport: (dataUrl: string) => void;
}

const LayoutStudio: React.FC<LayoutStudioProps> = ({ initialPhotos, onClose, onExport }) => {
  const [sheetPhotos, setSheetPhotos] = useState<SheetPhoto[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const photos: SheetPhoto[] = [];
    const itemWidth = PASSPORT_SETTINGS.photoWidthCm;
    const itemHeight = PASSPORT_SETTINGS.photoHeightCm;
    const spacing = PASSPORT_SETTINGS.spacingMm / 10;
    const maxHorizontal = PASSPORT_SETTINGS.maxHorizontal; 

    // Calculate grid width to center horizontally
    const totalGridWidth = (maxHorizontal * itemWidth) + ((maxHorizontal - 1) * spacing);
    const startX = (A4_WIDTH_CM - totalGridWidth) / 2;
    const startY = 2.0; 

    let currentX = startX;
    let currentY = startY;
    let countInRow = 0;

    initialPhotos.forEach((group) => {
      for (let i = 0; i < group.quantity; i++) {
        if (countInRow >= maxHorizontal) {
          countInRow = 0;
          currentX = startX;
          currentY += itemHeight + spacing;
        }

        if (currentY + itemHeight < A4_HEIGHT_CM - 1) {
          photos.push({
            id: `${group.photoId}-${i}`,
            photoId: group.photoId,
            url: group.url,
            x: currentX,
            y: currentY,
            width: itemWidth,
            height: itemHeight
          });
        }

        currentX += itemWidth + spacing;
        countInRow++;
      }
    });
    setSheetPhotos(photos);
  }, [initialPhotos]);

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    const startX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const startY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const photo = sheetPhotos.find(p => p.id === id);
    if (!photo) return;
    const initialX = photo.x;
    const initialY = photo.y;
    setActiveId(id);
    const onMove = (mv: MouseEvent | TouchEvent) => {
      const cx = 'touches' in mv ? mv.touches[0].clientX : (mv as MouseEvent).clientX;
      const cy = 'touches' in mv ? mv.touches[0].clientY : (mv as MouseEvent).clientY;
      const dx = (cx - startX) / CM_TO_VIEWPORT;
      const dy = (cy - startY) / CM_TO_VIEWPORT;
      setSheetPhotos(prev => prev.map(p => p.id === id ? { 
        ...p, x: Math.max(0, Math.min(A4_WIDTH_CM - p.width, initialX + dx)),
        y: Math.max(0, Math.min(A4_HEIGHT_CM - p.height, initialY + dy))
      } : p));
    };
    const onEnd = () => { setActiveId(null); window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onEnd); };
    window.addEventListener('mousemove', onMove); window.addEventListener('mouseup', onEnd);
  };

  const captureSheet = async () => {
    setIsExporting(true);
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    const dpi = 300;
    const cmToPx = dpi / 2.54;
    canvas.width = A4_WIDTH_CM * cmToPx;
    canvas.height = A4_HEIGHT_CM * cmToPx;
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (const p of sheetPhotos) {
      const img = new Image(); img.src = p.url;
      await new Promise(res => img.onload = res);
      ctx.drawImage(img, p.x * cmToPx, p.y * cmToPx, p.width * cmToPx, p.height * cmToPx);

      // Explicit Black Borders for printing standards
      ctx.strokeStyle = '#000000'; 
      ctx.lineWidth = 2.0; // Slightly thicker for easier cutting
      ctx.strokeRect(p.x * cmToPx, p.y * cmToPx, p.width * cmToPx, p.height * cmToPx);
    }
    onExport(canvas.toDataURL('image/jpeg', 0.98));
    setIsExporting(false);
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col bg-black/95 backdrop-blur-3xl animate-in fade-in duration-700 overflow-hidden">
      <header className="px-12 py-8 flex items-center justify-between border-b border-white/5 bg-black/20">
        <div>
          <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Production Sheet</h2>
          <p className="text-[10px] text-[#2dd4bf] font-black tracking-[0.5em] uppercase mt-1">Symmetrical A4 Matrix Calibration</p>
        </div>
        <button onClick={onClose} className="p-4 hover:bg-white/5 rounded-full text-white/30 transition-all"><X size={32} /></button>
      </header>

      <main className="flex-1 overflow-auto flex justify-center p-20 custom-scrollbar bg-black/40">
        <div className="relative bg-white shadow-[0_50px_100px_rgba(0,0,0,1)] border border-white/5" style={{ width: `${A4_WIDTH_CM * CM_TO_VIEWPORT}px`, height: `${A4_HEIGHT_CM * CM_TO_VIEWPORT}px` }}>
          <div className="absolute inset-0 pointer-events-none opacity-[0.01]" style={{ backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: `${CM_TO_VIEWPORT/2}px ${CM_TO_VIEWPORT/2}px` }}></div>
          {sheetPhotos.map((p) => (
            <div key={p.id} onMouseDown={(e) => handleDrag(p.id, e)} className={`absolute cursor-move transition-transform duration-300 select-none border border-black ${activeId === p.id ? 'z-50 scale-105 shadow-2xl ring-2 ring-[#2dd4bf]' : 'z-10 shadow-sm'}`} style={{ left: `${p.x * CM_TO_VIEWPORT}px`, top: `${p.y * CM_TO_VIEWPORT}px`, width: `${p.width * CM_TO_VIEWPORT}px`, height: `${p.height * CM_TO_VIEWPORT}px` }}>
              <img src={p.url} className="w-full h-full object-cover pointer-events-none" />
              {activeId === p.id && <div className="absolute -top-12 left-1/2 -translate-x-1/2 text-[9px] font-black text-[#2dd4bf] uppercase bg-black/95 px-5 py-2 rounded-full border border-[#2dd4bf44] backdrop-blur-2xl shadow-2xl animate-in fade-in slide-in-from-bottom-2">{p.x.toFixed(2)} / {p.y.toFixed(2)} cm</div>}
            </div>
          ))}
        </div>
      </main>

      <footer className="px-12 py-10 flex items-center justify-between border-t border-white/5 bg-black/30 backdrop-blur-3xl">
        <div className="flex gap-16">
          <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">A4 GRID</span><span className="text-sm font-black text-white uppercase tracking-[0.2em]">Symmetrical 6-Horizontal</span></div>
          <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">BATCH SIZE</span><span className="text-sm font-black text-white uppercase tracking-[0.2em]">{sheetPhotos.length} Units</span></div>
        </div>
        <div className="flex gap-6">
          <button onClick={onClose} className="px-10 py-5 text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all">Cancel</button>
          <button onClick={captureSheet} disabled={isExporting} className="bg-[#2dd4bf] text-white px-16 py-5 rounded-full font-black text-xs uppercase tracking-widest shadow-[0_15px_40px_rgba(45,212,191,0.5)] hover:scale-105 active:scale-95 transition-all flex items-center gap-4">
            {isExporting ? <RotateCcw className="animate-spin" size={20}/> : <Download size={20} />}
            {isExporting ? 'Generating...' : 'Download Production Ready Sheet'}
          </button>
        </div>
      </footer>
    </div>
  );
};
export default LayoutStudio;
